-- Poems batch 24
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a3e4aa0f-aba7-4024-a349-3c9fb23be270','漢州月夕遊房太尉西湖','李德裕','唐','唐诗','tang','','["\u897f\u6e56"]','丞相鳴琴地，何年閉玉徽。',48,'全唐诗/poet.tang.25000.json','["丞相鳴琴地，何年閉玉徽。", "偶因明月夕，重敞故樓扉。", "桃柳谿空在，芙蓉客暫依。", "誰憐濟川楫，長與夜舟歸。"]'),
('b63a96f9-e226-4ef7-a0fb-6970d0f8465e','重題','李德裕','唐','唐诗','tang','','[]','晚日臨寒渚，微風發櫂謳。',48,'全唐诗/poet.tang.25000.json','["晚日臨寒渚，微風發櫂謳。", "鳳池波自闊，魚水運難留。", "亭古思宏棟，川長憶夜舟。", "想公高世志，祗似冶城遊。"]'),
('82225630-b128-444f-a56e-021b35ba050b','房公舊竹亭聞琴緬慕風流神期如在因重題此作','李德裕','唐','唐诗','tang','','[]','流水音長在，青霞意不傳。',24,'全唐诗/poet.tang.25000.json','["流水音長在，青霞意不傳。", "獨悲形解後，誰聽廣陵絃。"]'),
('4cd93e8a-ad8d-43d9-8d71-72e69c5ba79f','憶金門舊遊奉寄江西沈大夫','李德裕','唐','唐诗','tang','','[]','東望滄溟路幾重，無因白首更相逢。',64,'全唐诗/poet.tang.25000.json','["東望滄溟路幾重，無因白首更相逢。", "已悲泉下雙琪樹，又惜天邊一臥龍。", "人事升沉纔十載，宦遊漂泊過千峰。", "思君遠寄西山藥，歲暮相期向赤松。"]'),
('5fd1eeef-5e4d-4e80-ba8b-06786ca97c70','早入中書行公主冊禮事畢登集賢閣成詠','李德裕','唐','唐诗','tang','','[]','明星入東陌，燦燦光層宙。',96,'全唐诗/poet.tang.25000.json','["明星入東陌，燦燦光層宙。", "皎月映高梧，輕風發涼候。", "金門列葆吹，鐘室傳清漏。", "簡冊自中來，貂黃忝宣授。", "更登天祿閣，極眺終南岫。", "遙羨商山翁，閑歌紫芝秀。", "晨興念始辱，夕惕思致寇。", "傾奪非我心，悽然感田竇。"]'),
('013c9243-bd61-42c8-afd4-9261db7c74e2','題羅浮石','李德裕','唐','唐诗','tang','','[]','清景持芳菊，涼天倚茂松。',24,'全唐诗/poet.tang.25000.json','["清景持芳菊，涼天倚茂松。", "名山何必去，此地有羣峰。"]'),
('affd9d6b-278c-485c-9181-02c1e7501a3f','重過列子廟追感頃年自淮服與居守王僕射同題名於廟壁僕射已爲御史余尚布衣自後俱列紫垣繼遊內署兩爲夏官之代復聯左揆之榮荷寵多同感涕何極因書四韻奉寄','李德裕','唐','唐诗','tang','','[]','白首過遺廟，朱輪入故城。',48,'全唐诗/poet.tang.25000.json','["白首過遺廟，朱輪入故城。", "已慚聯左揆，猶喜抗前旌。", "曳履忘年舊，彈冠久要情。", "重看題壁處，豈羨棄繻生。"]'),
('7fd2e15e-24c5-47bd-83a4-4e3fe7384ddd','遙傷茅山縣孫尊師三首 一','李德裕','唐','唐诗','tang','','[]','蟬蛻遺虛白，蜺飛入上清。',48,'全唐诗/poet.tang.25000.json','["蟬蛻遺虛白，蜺飛入上清。", "同人悲劒解，舊友覺衣輕。", "黃鵠遙將舉，斑麟儼未行。", "惟應鮑靚室，中夜識琴聲。"]'),
('c63261ea-2130-4663-b206-8c52c3915222','遙傷茅山縣孫尊師三首 二','李德裕','唐','唐诗','tang','','[]','金格期初至，飆輪去不停。',48,'全唐诗/poet.tang.25000.json','["金格期初至，飆輪去不停。", "山摧武擔石，天隕少微星。", "弟子悲徐甲，門人泣蔡經。", "空聞留玉舃，猶在阜鄉亭。"]'),
('11f38d5e-78f2-42cb-aaff-a5146e980d4d','遙傷茅山縣孫尊師三首 三','李德裕','唐','唐诗','tang','','[]','空宇留丹竈，層霞被羽衣。',48,'全唐诗/poet.tang.25000.json','["空宇留丹竈，層霞被羽衣。", "舊山聞鹿化，遺舃尚鳧飛。", "數日奇香在，何年白鶴歸。", "想君旋下淚，方欵里閭扉。"]'),
('e283ac05-0ee6-4342-b972-af263c1e2405','尊師是桃源黃先生傳法弟子常見尊師稱先師靈迹今重賦此詩兼寄題黃先生舊館','李德裕','唐','唐诗','tang','','[]','後學方成市，吾師又上賓。',48,'全唐诗/poet.tang.25000.json','["後學方成市，吾師又上賓。", "洞天應不夜，源樹秪如春。", "棋客留童子，山精避直神。", "無因握石髓，及與養生人。"]'),
('f8b2a053-dbd5-4e21-9e46-91ab7f11d0e8','僕射相公偶話於故集賢張學士廳寫得德裕與僕射舊唱和詩其時和者五人惟僕射與德裕皆列高位淒然懷舊輒獻此詩','李德裕','唐','唐诗','tang','','[]','賦感鄰人篴，詩留夫子牆。',24,'全唐诗/poet.tang.25000.json','["賦感鄰人篴，詩留夫子牆。", "延年如有作，應不用山王。"]'),
('5bd4807e-f20d-46e4-ab5b-530de8760a99','惠泉','李德裕','唐','唐诗','tang','','[]','茲泉由太潔，終不畜纖鱗。',48,'全唐诗/poet.tang.25000.json','["茲泉由太潔，終不畜纖鱗。", "到底清何益，含虛勢自貧。", "明璣難秘彩，美玉詎潛珍。", "未及黃陂量，滔滔豈有津。"]'),
('18a77994-ce2d-485a-a66d-03e8ff1a1465','無題','李德裕','唐','唐诗','tang','','[]','松倚蒼崖老，蘭臨碧洞衰。',24,'全唐诗/poet.tang.25000.json','["松倚蒼崖老，蘭臨碧洞衰。", "不勞鄰舍篴，吹起舊時悲。"]'),
('08640c71-cf9b-4dc3-a65a-12b770c40af6','題冠蓋里','李德裕','唐','唐诗','tang','','[]','偶來冠蓋里，媿是舊三公。',24,'全唐诗/poet.tang.25000.json','["偶來冠蓋里，媿是舊三公。", "自喜無兵術，輕裘上閟宮。"]'),
('bf043f37-cf30-4c39-969c-69b84fcca334','離平泉馬上作','李德裕','唐','唐诗','tang','','[]','十年紫殿掌洪鈞，出入三朝一品身。',66,'全唐诗/poet.tang.25000.json','["十年紫殿掌洪鈞，出入三朝一品身。", "文帝寵深陪雉尾，武皇恩厚宴龍津。", "黑山永破和親虜，烏嶺全阬跋扈臣。", "自是功高臨盡處，禍來[名]滅不由人。"]'),
('190158b4-8500-4485-97c7-52d6a3cc7cc8','謫嶺南道中作','李德裕','唐','唐诗','tang','','["\u6292\u60c5", "\u8d2c\u8c2a", "\u5199\u666f"]','嶺水爭分路轉迷，桄榔椰葉暗蠻溪。',64,'全唐诗/poet.tang.25000.json','["嶺水爭分路轉迷，桄榔椰葉暗蠻溪。", "愁衝毒霧逢虵草，畏落沙蟲避燕泥。", "五月畬田收火米，三更津吏報潮雞。", "不堪腸斷思鄉處，紅槿花中越鳥啼。"]'),
('ec61eac1-97b1-4c60-b17b-62334b8ac6d2','到惡溪夜泊蘆島','李德裕','唐','唐诗','tang','','[]','甘露花香不再持，遠公應怪負前期。',64,'全唐诗/poet.tang.25000.json','["甘露花香不再持，遠公應怪負前期。", "青蠅豈獨悲虞氏，黃犬應聞笑李斯。", "風雨瘴昏蠻日月，煙波魂斷惡溪時。", "嶺頭無限相思淚，泣向寒梅近北枝。"]'),
('e5e574a4-9739-4ace-9433-89631cba5a25','登崖州城作','李德裕','唐','唐诗','tang','','[]','獨上高樓望帝京，鳥飛猶是半年程。',32,'全唐诗/poet.tang.25000.json','["獨上高樓望帝京，鳥飛猶是半年程。", "青山似欲留人住，百匝千遭遶郡城。"]'),
('388be58f-85a2-452f-8b15-30d3a04ad2e9','鴛鴦篇','李德裕','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','君不見昔時同心人，化作鴛鴦鳥。',313,'全唐诗/poet.tang.25000.json','["君不見昔時同心人，化作鴛鴦鳥。", "和鳴一夕不暫離，交頸千年尚爲少。", "二月草菲菲，山櫻花未稀。", "金塘風日好，何處不相依？", "既逢解佩游女，更值凌波宓妃。", "精光搖翠蓋，麗色映珠璣。", "雙影相伴，雙心莫違。", "淹留碧沙上，蕩漾洗紅衣。", "春光兮宛轉，嬉遊兮未反。", "宿莫近天泉池，飛莫近長洲苑。", "爾願歡愛不相忘，須去人間羅網遠。", "南有瀟湘洲，且爲千里遊。", "洞庭無苦寒，沅江多碧流。", "昔爲薄命妾，無日不含愁。", "今爲水中鳥，頡頏自相求。", "洛陽女兒在青閣，二月羅衣輕更薄。", "金泥文彩未足珍，畫作鴛鴦始堪著。", "亦有少婦破瓜年，春閨無伴獨嬋娟。", "夜夜學織連枝錦，織作鴛鴦人共憐。", "悠悠湘水濱，清淺漾初蘋。", "菖花發豔無人識，江柳逶迤空自春。", "唯憐獨鶴依琴曲，更念孤鸞隱鏡塵。", "願作鴛鴦被，長覆有情人。"]'),
('6c8bb35d-2170-44e1-9fb7-2a1170a96775','南梁行','李德裕','唐','唐诗','tang','','[]','江南鬱鬱春草長，悠悠漢水浮清光。',288,'全唐诗/poet.tang.25000.json','["江南鬱鬱春草長，悠悠漢水浮清光。", "雜英飛盡空和景，綠楊陰重官舍靜。", "此時醉客縱橫書，公言可薦承明廬。", "青天詔下寵光至，頒籍金閨徵石渠。", "重歸山路煙嵐隔，巫山未深晚花折。", "澗底紅光奪目燃，搖風有毒愁行客。", "杜鵑啼咽花亦殷，聲悲絕豔連空山。", "斜陽瞥映淺深樹，雲雨翻迷崖谷間。", "山雞錦質矜毛羽，透竹穿蘿命儔侶。", "喬木幽谷上下同，雄雌不異飛棲處。", "望秦峰迥過商顏，浪疊雲堆萬簇山。", "行盡杳冥青嶂外，九重鐘漏紫雲間。", "元和列侍明光殿，諫草初焚市朝變。", "北闕趨臣半隟塵，南梁笑客皆飛霰。", "追思感歎却昏迷，霜鬢愁吟到曉雞。", "故園歲深開斷簡，秋堂月曉掩遺袿。", "嗚嗚曉角霞輝粲，撫劒當楹一長歎。", "芻狗無由學聖賢，空持感激終昏旦。"]'),
('4cb83db3-099a-401f-88d8-93019abd77b1','近於伊川卜山居將命者畫圖而至欣然有感聊賦此詩兼寄上浙東元相公大夫使求青田胎化鶴','李德裕','唐','唐诗','tang','','[]','弱歲弄詞翰，遂叨明主恩。',144,'全唐诗/poet.tang.25000.json','["弱歲弄詞翰，遂叨明主恩。", "懷章過越邸，建斾守吳門。", "西圮陰難駐，東臯意尚存。", "慙逾六百石，愧負五千言。", "寄世知嬰繳，辭榮類觸藩。", "欲追綿上隱，況近子平村。", "邑有桐鄉愛，山餘黍谷暄。", "既非逃相地，乃是故侯園。", "野竹多微逕，巖泉豈一源。", "映池方樹密，傍澗古藤繁。", "邛杖堪扶老，黃牛已服轅。", "只應將唳鶴，幽谷共翩翻。"]'),
('870e7110-a9f4-4845-aa89-2dbd3ba7cdb3','憶平泉山居贈沈吏部一首','李德裕','唐','唐诗','tang','','[]','昔聞羊叔子，茅屋在東渠。',144,'全唐诗/poet.tang.25000.json','["昔聞羊叔子，茅屋在東渠。", "豈不念歸路，徘徊畏簡書。", "乃知軒冕客，自與田園疎。", "歿世有遺恨，精誠何所如。", "嗟予寡時用，夙志在林閭。", "雖抱山水癖，敢希仁智居。", "清泉繞舍下，修竹蔭庭除。", "幽徑松蓋密，小池蓮葉初。", "從來有好鳥，近復躍鯈魚。", "少室映川陸，鳴臯對蓬廬。", "張何舊寮寀，相勉在懸輿。", "常恐似伯玉，瞻前慙魏舒。"]'),
('4a7172aa-a31c-402d-a451-e22bbb517df3','夏晚有懷平泉林居','李德裕','唐','唐诗','tang','','[]','孟夏守畏途，捨舟在徂暑。',144,'全唐诗/poet.tang.25000.json','["孟夏守畏途，捨舟在徂暑。", "愀然何所念，念我龍門塢。", "密竹無蹊徑，高松有四五。", "飛泉鳴樹間，颯颯如度雨。", "菌桂秀層嶺，芳蓀媚幽渚。", "稚子候我歸，衡門獨延佇。", "誰言聖與哲，曾是不懷土。", "公旦既思周，宣尼亦念魯。", "矧余竄炎裔，日夕誰晤語。", "眷闕悲子牟，班荆感椒舉。", "悽悽視環玦，惻惻步庭廡。", "豈待莊舃吟，方知倦羈旅。"]'),
('1398a0a7-dfec-4645-8bdf-69b6edec5672','早秋龍興寺江亭閑眺憶龍門山居寄崔張舊從事','李德裕','唐','唐诗','tang','','[]','江亭感秋至，蘭徑悲露泫。',120,'全唐诗/poet.tang.25000.json','["江亭感秋至，蘭徑悲露泫。", "秔稻秀晚川，杉松鬱晴巘。", "嗟予有林壑，茲夕念原衍。", "綠篠連嶺多，青莎近溪淺。", "淵明菊猶在，仲蔚蒿莫翦。", "喬木粲凌苕，陰崖積幽蘚。", "遙思伊川水，北渡龍門峴。", "蒼翠雙闕間，逶迤清灘轉。", "故人在鄉國，歲晏路悠緬。", "惆悵此生涯，無由共登踐。"]'),
('e747423f-c1f7-418b-9b94-0596086c53f9','比聞龍門敬善寺有紅桂樹獨秀伊川嘗於江南諸山訪之莫致陳侍御知予所好因訪剡溪樵客偶得數株移植郊園衆芳色沮乃知敬善所有是蜀道菵草徒得嘉名因賦是詩兼贈陳侍御','李德裕','唐','唐诗','tang','','[]','昔聞紅桂枝，獨秀龍門側。',120,'全唐诗/poet.tang.25000.json','["昔聞紅桂枝，獨秀龍門側。", "越叟遺數株，周人未嘗識。", "平生愛此樹，攀翫無由得。", "君子知我心，因之爲羽翼。", "豈煩嘉客譽，且就清陰息。", "來自天姥岑，長疑翠嵐色。", "芬芳世所絕，偃蹇枝漸直。", "瓊葉潤不凋，珠英粲如織。", "猶疑翡翠宿，想待鵷雛食。", "寧止暫淹留，終當更封植。"]'),
('a98b425a-5ba1-4fed-9161-362584634bfd','懷山居邀松陽子同作','李德裕','唐','唐诗','tang','','[]','我有愛山心，如飢復如渴。',192,'全唐诗/poet.tang.25000.json','["我有愛山心，如飢復如渴。", "出谷一年餘，常疑十年別。", "春思巖花爛，夏憶寒泉冽。", "秋憶泛蘭巵，冬思玩松雪。", "晨思小山桂，暝憶深潭月。", "醉憶剖紅梨，飯思食紫蕨。", "坐思藤蘿密，步憶莓苔滑。", "晝夜百刻中，愁腸幾回絕。", "每念羊叔子，言之豈常輟。", "人生不如意，十乃居七八。", "我未及懸輿，今猶佩朝紱。", "焉能逐麋鹿，便得遊林樾。", "范恣滄波舟，張懷赤松列。", "惟應詎身恤，豈敢忘臣節。", "器滿自當欹，物盈終有缺。", "從茲返樵徑，庶可希前哲。"]'),
('a7824e5f-40ca-4492-8899-8f42452a2372','思歸赤松村呈松陽子','李德裕','唐','唐诗','tang','','[]','昔人思避世，惟恐不深幽。',48,'全唐诗/poet.tang.25000.json','["昔人思避世，惟恐不深幽。", "禽慶潛名岳，鴟夷漾釣舟。", "顧余知止足，所樂在歸休。", "不似尋山者，忘家恣遠遊。"]'),
('30c9734d-d165-47d8-8528-e80dccfba3d9','近臘對雪有懷林居','李德裕','唐','唐诗','tang','','[]','蓬門常晝掩，竹徑寂無人。',48,'全唐诗/poet.tang.25000.json','["蓬門常晝掩，竹徑寂無人。", "鳥起飄松霰，麕行動谷榛。", "應知禽魚侶，合與薜蘿親。", "遙憶平臯望，溪煙已發春。"]'),
('30c05ba0-1740-48fc-9e3f-11936702d76d','思山居一十首 清明後憶山中','李德裕','唐','唐诗','tang','','[]','遙思寒食後，野老林下醉。',48,'全唐诗/poet.tang.25000.json','["遙思寒食後，野老林下醉。", "月照一山明，風吹百花氣。", "飛泉與萬籟，髣髴疑簫吹。", "不待曙華分，已應喧鳥至。"]'),
('24253550-2f45-45be-815e-997e872d38a8','思山居一十首 題寄商山石','李德裕','唐','唐诗','tang','','[]','綺皓巖中石，嘗經伴隱淪。',48,'全唐诗/poet.tang.25000.json','["綺皓巖中石，嘗經伴隱淪。", "紫芝呈幾曲，紅蘚閟千春。", "聊用支琴尾，寧惟倚病身。", "自知來處所，何暇問嚴遵。"]'),
('2d8f2552-eed0-4ece-9701-dd3126dd89c2','思山居一十首 憶鐘苽時','李德裕','唐','唐诗','tang','','[]','尚平方畢娶，疎廣念歸期。',48,'全唐诗/poet.tang.25000.json','["尚平方畢娶，疎廣念歸期。", "澗底松成蓋，簷前桂長枝。", "徑閑芳草合，山靜落花遲。", "雖有苽園在，無因及種時。"]'),
('920a0be7-5088-4a6a-b724-bc765c5684fa','思山居一十首 春日獨坐思歸','李德裕','唐','唐诗','tang','','[]','壯齡心已盡，孤賞意猶存。',48,'全唐诗/poet.tang.25000.json','["壯齡心已盡，孤賞意猶存。", "豈望圖麟閣，惟思臥鹿門。", "無謀堪適野，何力可拘原。", "只有容身去，幽山自灌園。"]'),
('7d37048b-90e3-4fdf-bd9e-f2f6e272c9f3','思山居一十首 思登家山林嶺','李德裕','唐','唐诗','tang','','[]','自知無世用，只是愛山遊。',48,'全唐诗/poet.tang.25000.json','["自知無世用，只是愛山遊。", "舊有嵇康嬾，今慙趙武偷。", "登巒未覺疾，泛水便忘憂。", "最惜殘筋力，捫蘿遍一丘。"]'),
('58a32612-fac8-4a8b-b311-52a396fe23e5','思山居一十首 思鄉園老人','李德裕','唐','唐诗','tang','','[]','常羨蓽門翁，所思惟歲稔。',48,'全唐诗/poet.tang.25000.json','["常羨蓽門翁，所思惟歲稔。", "遙知松月曙，尚在山窗寢。", "蘭氣入幽簾，禽言傍孤枕。", "晨興步巖徑，更酌寒泉飲。"]'),
('09154b8e-daf6-4da6-a951-2596efb2a3af','思山居一十首 寄龍門僧','李德裕','唐','唐诗','tang','','[]','龍門有開士，愛我春潭碧。',48,'全唐诗/poet.tang.25000.json','["龍門有開士，愛我春潭碧。", "清景出東山，閑來玩松石。", "應憐林壑主，遠作滄溟客。", "爲我謝此僧，終當理歸策。"]'),
('ffbd7136-ae59-4a8f-81c2-b4e71b5d81f1','思山居一十首 憶藥苗','李德裕','唐','唐诗','tang','','[]','溪上藥苗齊，丰茸正堪掇。',48,'全唐诗/poet.tang.25000.json','["溪上藥苗齊，丰茸正堪掇。", "皆能扶我壽，豈止堅肌骨。", "味掩商山芝，英逾首陽蕨。", "豈如甘谷士，只得香泉啜。"]'),
('e2fd112f-3850-4bdd-987a-9b1c444c3dc0','思山居一十首 憶村中老人春酒','李德裕','唐','唐诗','tang','','[]','二叟茅茨下，清晨飲濁醪。',48,'全唐诗/poet.tang.25000.json','["二叟茅茨下，清晨飲濁醪。", "雨殘紅芍藥，風落紫櫻桃。", "巢燕銜泥疾，簷蟲挂網高。", "閑思春谷事，轉覺宦途勞。"]'),
('c08c0804-5f75-499d-b89d-2e7fc922876e','思山居一十首 憶葛勝木禪床','李德裕','唐','唐诗','tang','','[]','憶我齋中榻，寒宵幾獨眠。',48,'全唐诗/poet.tang.25000.json','["憶我齋中榻，寒宵幾獨眠。", "管寧穿亦坐，徐孺去常懸。", "蟲網垂應遍，苔痕染更鮮。", "何人及身在，歸對老僧禪。"]'),
('6d38f001-75cd-44c4-91a4-ece9b6030134','初夏有懷山居','李德裕','唐','唐诗','tang','','[]','山中有所憶，夏景始清幽。',48,'全唐诗/poet.tang.25000.json','["山中有所憶，夏景始清幽。", "野竹陰無日，巖泉冷似秋。", "翠岑當累榭，皓月入輕舟。", "只有思歸夕，空簾且夢遊。"]'),
('9c0eff5a-f089-4ffc-875f-49d7a41ec8a4','張公超谷中石','李德裕','唐','唐诗','tang','','[]','鼓篋依綠槐，橫經起秋霧。',48,'全唐诗/poet.tang.25000.json','["鼓篋依綠槐，橫經起秋霧。", "有時連岳客，尚辦絃歌處。", "自予去幽谷，誰人襲芳杜。", "空留古苔石，對我巖中樹。"]'),
('38853f70-8e7a-4af2-a182-f2eae2619119','初歸平泉過龍門南嶺遙望山居即事','李德裕','唐','唐诗','tang','','[]','初歸故鄉陌，極望且徐輪。',48,'全唐诗/poet.tang.25000.json','["初歸故鄉陌，極望且徐輪。", "近野樵蒸至，平泉煙火新。", "農夫饋雞黍，漁子薦霜鱗。", "惆悵懷楊僕，慚爲關外人。"]'),
('383eda54-11ce-47da-be4a-c79a1dce423a','伊川晚眺','李德裕','唐','唐诗','tang','','[]','桑葉初黃梨葉紅，伊川落日盡無風。',32,'全唐诗/poet.tang.25000.json','["桑葉初黃梨葉紅，伊川落日盡無風。", "漢儲何假終南客，甪里先生在谷中。"]'),
('67aa90b3-9634-49b3-b0c4-14b9f17c5432','潭上喜見新月','李德裕','唐','唐诗','tang','','[]','簪組十年夢，園廬今夕情。',48,'全唐诗/poet.tang.25000.json','["簪組十年夢，園廬今夕情。", "誰憐故鄉月，復映碧潭生。", "皓彩松上見，寒光波際輕。", "還將孤賞意，暫寄玉琴聲。"]'),
('dd9e9cd2-522f-4809-a26f-648afdbd2afa','郊外即事寄侍郎大尹','李德裕','唐','唐诗','tang','','[]','高秋慙非隱，閑林喜退居。',48,'全唐诗/poet.tang.25000.json','["高秋慙非隱，閑林喜退居。", "老農爭席坐，稚子帶經鋤。", "竹徑難迴騎，仙舟但跂予。", "豈知陶靖節，秪自愛吾廬。"]'),
('297fbc2e-c789-41df-b4a3-5aebe3b55cb9','山居遇雪喜道者相訪','李德裕','唐','唐诗','tang','','[]','幽居近谷西，喬木與山齊。',48,'全唐诗/poet.tang.25000.json','["幽居近谷西，喬木與山齊。", "野竹連池合，巖松映雪低。", "喜君來白社，值我在青谿。", "應笑於陵子，遺榮自灌畦。"]'),
('275423ed-cfdb-4b5b-830e-cc40137333ee','雪霽晨起','李德裕','唐','唐诗','tang','','[]','雪覆寒溪竹，風卷野田蓬。',24,'全唐诗/poet.tang.25000.json','["雪覆寒溪竹，風卷野田蓬。", "四望無竹跡，誰憐孤老翁。"]'),
('3282311c-bea6-4f03-83ba-e4e0dd5457ca','洛中士君子多以平泉見呼愧獲方外之名因以此詩爲報奉寄劉賓客','李德裕','唐','唐诗','tang','','[]','非高柳下逸，自愛竹林閑。',48,'全唐诗/poet.tang.25000.json','["非高柳下逸，自愛竹林閑。", "才異居東里，愚因在北山。", "徑荒寒未掃，門設晝長關。", "不及鴟夷子，悠悠煙水間。"]'),
('e747758a-5fe6-4ee8-b2d2-e462ca32f42c','早春至言禪公法堂憶平泉別業','李德裕','唐','唐诗','tang','','[]','昔我伊原上，孤遊竹樹間。',48,'全唐诗/poet.tang.25000.json','["昔我伊原上，孤遊竹樹間。", "人依紅桂靜，鳥傍碧潭閑。", "松蓋低春雪，藤輪倚暮山。", "永懷桑梓邑，衰老若爲還。"]'),
('22179021-1fac-45c0-9764-8f1f76da456d','峽山亭月夜獨宿對櫻桃花有懷伊川別墅','李德裕','唐','唐诗','tang','','[]','皎月照芳樹，鮮葩含素輝。',48,'全唐诗/poet.tang.25000.json','["皎月照芳樹，鮮葩含素輝。", "愁人惜春夜，達曙想巖扉。", "風靜陰滿砌，露濃香入衣。", "恨無金谷妓，爲我奏思歸。"]'),
('7ca78c96-d703-4bc1-839c-3bc02f55bdf9','春暮思平泉雜詠二十首 望伊川','李德裕','唐','唐诗','tang','','[]','遠村寒食後，細雨度川來。',48,'全唐诗/poet.tang.25000.json','["遠村寒食後，細雨度川來。", "芳草連谿合，梨花映墅開。", "槿籬懸落照，松徑長新苔。", "向夕亭臯望，遊禽幾處回。"]'),
('cfdce32c-1438-4ccc-8e1d-e951a06c059e','春暮思平泉雜詠二十首 潭上紫藤','李德裕','唐','唐诗','tang','','[]','故鄉春欲盡，一歲芳難再。',48,'全唐诗/poet.tang.25000.json','["故鄉春欲盡，一歲芳難再。", "巖樹已青葱，吾廬日堪愛。", "幽溪人未去，芳草行應礙。", "遙憶紫藤垂，繁英照潭黛。"]'),
('97a8d41f-bcd2-4fc4-809b-bd6f8df79441','春暮思平泉雜詠二十首 書樓晴望','李德裕','唐','唐诗','tang','','[]','幽居人世外，久厭市朝喧。',48,'全唐诗/poet.tang.25000.json','["幽居人世外，久厭市朝喧。", "蒼翠連雙闕，微茫認九原。", "殘紅映鞏樹，斜日照轘轅。", "薄暮柴扉掩，誰知仲蔚園。"]'),
('c3006dfc-e98b-4e18-9c70-9dfaf1cb215a','春暮思平泉雜詠二十首 西嶺望鳴臯山','李德裕','唐','唐诗','tang','','[]','高秋對涼野，四望何蕭瑟。',48,'全唐诗/poet.tang.25000.json','["高秋對涼野，四望何蕭瑟。", "遠見鳴臯山，青峰原上出。", "晨興採薇蕨，向暮歸蓬蓽。", "詎假數揮金，餐和養餘日。"]'),
('d9ef031d-f029-4b5b-8708-837db6c42462','春暮思平泉雜詠二十首 瀑泉亭','李德裕','唐','唐诗','tang','','[]','向老多悲恨，悽然念一丘。',48,'全唐诗/poet.tang.25000.json','["向老多悲恨，悽然念一丘。", "巖泉終古在，風月幾年遊。", "菌閣饒佳樹，菱潭有釣舟。", "不如羊叔子，名與峴山留。"]'),
('ab72ba3a-5a6b-4923-bdff-ca04b8dc658a','春暮思平泉雜詠二十首 紅桂樹','李德裕','唐','唐诗','tang','','[]','欲求塵外物，此樹是瑤林。',48,'全唐诗/poet.tang.25000.json','["欲求塵外物，此樹是瑤林。", "後素合餘絢，如丹見本心。", "妍姿無點辱，芳意託幽深。", "願以鮮葩色，凌霜照碧潯。"]'),
('c5fc7e08-e26d-4d96-a0a8-d6fa3aabbcba','春暮思平泉雜詠二十首 金松','李德裕','唐','唐诗','tang','','[]','台嶺生奇樹，佳名世未知。',48,'全唐诗/poet.tang.25000.json','["台嶺生奇樹，佳名世未知。", "纖纖疑大菊，落落是松枝。", "照日含金晰，籠煙淡翠滋。", "勿言人去晚，猶有歲寒期。"]'),
('805f3344-6463-490d-9751-736ceb7b0d35','春暮思平泉雜詠二十首 月桂','李德裕','唐','唐诗','tang','','[]','何年霜夜月，桂子落寒山。',48,'全唐诗/poet.tang.25000.json','["何年霜夜月，桂子落寒山。", "翠幹生巖下，金英在世間。", "幽崖空自老，清漢未知還。", "惟有涼秋夜，嫦娥來暫攀。"]'),
('29163583-e6fa-467c-9708-f659ee45f355','春暮思平泉雜詠二十首 山桂','李德裕','唐','唐诗','tang','','[]','吾愛山中樹，繁英滿目鮮。',48,'全唐诗/poet.tang.25000.json','["吾愛山中樹，繁英滿目鮮。", "臨風飄碎錦，映日亂非煙。", "影入春潭底，香凝月榭前。", "豈知幽獨客，賴此當朱絃。"]'),
('8db06ced-43bb-40c0-8f6c-cd85147c43d1','春暮思平泉雜詠二十首 栢','李德裕','唐','唐诗','tang','','[]','聞有三株樹，惟應秘閬風。',48,'全唐诗/poet.tang.25000.json','["聞有三株樹，惟應秘閬風。", "珊瑚不生葉，朱草又無叢。", "未若凌雲栢，常能終歲紅。", "晨霞與落日，相照在巖中。"]'),
('82207ddc-db30-477d-8563-91bec1321707','春暮思平泉雜詠二十首 芳蓀','李德裕','唐','唐诗','tang','','[]','楚客重蘭蓀，遺芳今未歇。',48,'全唐诗/poet.tang.25000.json','["楚客重蘭蓀，遺芳今未歇。", "葉抽清淺水，花照暄妍節。", "紫豔映渠鮮，輕香含露潔。", "離居若有贈，暫與幽人折。"]'),
('0c07e2f8-507b-43e2-866e-f5197d14e262','春暮思平泉雜詠二十首 流盃亭','李德裕','唐','唐诗','tang','','[]','激水自山椒，析波分淺瀨。',48,'全唐诗/poet.tang.25000.json','["激水自山椒，析波分淺瀨。", "回環疑古篆，詰曲如縈帶。", "寧愬羽觴遲，惟歡親友會。", "欲知中聖處，皓月臨松蓋。"]'),
('79ae1555-e2eb-4b93-a799-cc90fe9944f9','春暮思平泉雜詠二十首 東谿','李德裕','唐','唐诗','tang','','[]','近蓄東谿水，悠悠起淥波。',48,'全唐诗/poet.tang.25000.json','["近蓄東谿水，悠悠起淥波。", "綵鴛留不去，芳草日應多。", "夾岸生奇篠，緣巖覆女蘿。", "蘭橈思無限，爲感濯纓歌。"]'),
('1b420e8b-6da9-492e-947d-f34c439e9806','春暮思平泉雜詠二十首 鸂鶒','李德裕','唐','唐诗','tang','','[]','清沚雙鸂鶒，前年海上雛。',48,'全唐诗/poet.tang.25000.json','["清沚雙鸂鶒，前年海上雛。", "今年戀洲嶼，思若在江湖。", "欲起搖荷蓋，閑飛濺水珠。", "不能常泛泛，惟作逐波鳧。"]'),
('26fd6c50-4a0d-4358-ba54-5ff59e9d4d27','春暮思平泉雜詠二十首 西園','李德裕','唐','唐诗','tang','','[]','西園最多趣，永日自忘歸。',48,'全唐诗/poet.tang.25000.json','["西園最多趣，永日自忘歸。", "石瀨流清淺，風岑澹翠微。", "曉翻紅藥豔，晴裊碧潭輝。", "獨望娟娟月，宵分半掩扉。"]'),
('9629804a-398d-4262-90b8-4e245123e7a6','春暮思平泉雜詠二十首 海石楠','李德裕','唐','唐诗','tang','','[]','昔見歷陽山，雞籠已孤秀。',48,'全唐诗/poet.tang.25000.json','["昔見歷陽山，雞籠已孤秀。", "今看海嶠樹，翠蓋何幽茂。", "霰雪詎能侵，煙嵐自相揉。", "攀條獨臨憩，況值清陰晝。"]'),
('ff533005-4c8c-4a7f-81ef-9e60ec961ba4','春暮思平泉雜詠二十首 雙碧潭','李德裕','唐','唐诗','tang','','[]','清剡與嚴湍，潺湲皆可憶。',48,'全唐诗/poet.tang.25000.json','["清剡與嚴湍，潺湲皆可憶。", "適來玩山水，無此秋潭色。", "莫辨幽蘭叢，難分翠禽翼。", "遲遲洲渚步，臨眺忘餐食。"]'),
('29a9d34b-cc0d-4926-a979-7f6eee920ee6','春暮思平泉雜詠二十首 竹徑','李德裕','唐','唐诗','tang','','[]','野竹自成徑，繞溪三里餘。',48,'全唐诗/poet.tang.25000.json','["野竹自成徑，繞溪三里餘。", "檀欒被層阜，蕭瑟蔭清渠。", "日落見林靜，風行知谷虛。", "田家故人少，誰肯共焚魚。"]'),
('5310b4ae-6d3e-46c5-974b-c0613f854e9c','春暮思平泉雜詠二十首 花藥欄','李德裕','唐','唐诗','tang','','[]','蕙草春已碧，蘭花秋更紅。',48,'全唐诗/poet.tang.25000.json','["蕙草春已碧，蘭花秋更紅。", "四時發英豔，三徑滿芳叢。", "秀色濯清露，鮮輝搖惠風。", "王孫未知返，幽賞竟誰同。"]'),
('994c6256-3246-4a44-8bb7-f01950782e72','春暮思平泉雜詠二十首 自敘','李德裕','唐','唐诗','tang','','[]','五嶽徑雖深，遍遊心已蕩。',48,'全唐诗/poet.tang.25000.json','["五嶽徑雖深，遍遊心已蕩。", "苟能知止足，所遇皆清曠。", "七十難可期，一丘乃微尚。", "遙懷少室山，常恐非吾望。"]'),
('b852ff25-d358-4939-bf05-03b9ec76c667','首夏清景想望山居','李德裕','唐','唐诗','tang','','[]','嘉樹陰初合，山中賞更新。',72,'全唐诗/poet.tang.25000.json','["嘉樹陰初合，山中賞更新。", "禽言未知夏，蘭徑尚餘春。", "散滿蘿垂帶，扶疎桂長輪。", "丹青寫不盡，宵夢歎非真。", "累榭空留月，虛舟若待人。", "何時倚蘭棹，相與掇汀蘋。"]'),
('5385ff2d-f7c3-47b2-8333-8f0ba58081e4','思平泉樹石雜詠一十首 釣臺','李德裕','唐','唐诗','tang','','[]','我有嚴湍思，懷人訪故臺。',48,'全唐诗/poet.tang.25000.json','["我有嚴湍思，懷人訪故臺。", "客星依釣隱，仙石逐槎回。", "倒影含清沚，凝陰長碧苔。", "飛泉信可挹，幽客未歸來。"]'),
('13dc5e49-a70c-4cc0-bb86-c8b70f62f22b','思平泉樹石雜詠一十首 似鹿石','李德裕','唐','唐诗','tang','','[]','林中有奇石，髣髴獸潛行。',48,'全唐诗/poet.tang.25000.json','["林中有奇石，髣髴獸潛行。", "乍似依巖桂，還疑食野苹。", "茸長綠蘚映，斑細紫苔生。", "不是見羇者，何勞如頓纓。"]'),
('0a49c386-19d4-4855-ab4d-d357ae71cd38','思平泉樹石雜詠一十首 海上石笋','李德裕','唐','唐诗','tang','','[]','常愛仙都山，奇峰千仞懸。',48,'全唐诗/poet.tang.25000.json','["常愛仙都山，奇峰千仞懸。", "迢迢一何迥，不與衆山連。", "忽逢海嶠石，稍慰平生憶。", "何以慰我心，亭亭孤且直。"]'),
('f6809ea4-b1f5-40f0-9387-7da3a2d02451','思平泉樹石雜詠一十首 疊石','李德裕','唐','唐诗','tang','','[]','潺湲桂水湍，漱石多奇狀。',48,'全唐诗/poet.tang.25000.json','["潺湲桂水湍，漱石多奇狀。", "鱗次冠煙霞，蟬聯疊波浪。", "今來碧梧下，迥出秋潭上。", "歲晚苔蘚滋，懷賢益惆悵。"]'),
('ccf1ca36-a813-4a01-958b-9bce9ce5ae83','思平泉樹石雜詠一十首 重臺芙蓉','李德裕','唐','唐诗','tang','','[]','芙蓉含露時，秀色波中溢。',48,'全唐诗/poet.tang.25000.json','["芙蓉含露時，秀色波中溢。", "玉女襲朱裳，重重映皓質。", "晨霞耀丹景，片片明秋日。", "蘭澤多衆芳，妍姿不相匹。"]'),
('fef0203b-eed3-4cf6-aeeb-62707ac855e8','思平泉樹石雜詠一十首 白鷺鶿','李德裕','唐','唐诗','tang','','[]','余心憐白鷺，潭上日相依。',48,'全唐诗/poet.tang.25000.json','["余心憐白鷺，潭上日相依。", "拂石疑星落，凌風似雪飛。", "碧沙常獨立，清景自忘歸。", "所樂惟煙水，徘徊戀釣磯。"]'),
('b2afed80-f205-46c2-9c85-70ed40845509','思平泉樹石雜詠一十首 海魚骨','李德裕','唐','唐诗','tang','','[]','昔日任公子，期年釣此魚。',48,'全唐诗/poet.tang.25000.json','["昔日任公子，期年釣此魚。", "無由見成岳，聊喜識專車。", "皎皎連霜月，高高映碧渠。", "陶潛雖好事，觀海只披圖。"]'),
('727bbbc2-f83b-4c44-a0a3-ba34176b9ab2','思平泉樹石雜詠一十首 泛池舟','李德裕','唐','唐诗','tang','','[]','桂舟蘭作枻，芬芳皆絕世。',48,'全唐诗/poet.tang.25000.json','["桂舟蘭作枻，芬芳皆絕世。", "只可弄潺湲，焉能濟大川。", "樹懸涼夜月，風散碧潭煙。", "未得同魚子，菱歌共扣舷。"]'),
('18862695-afad-4b39-9e30-13595c947f99','思平泉樹石雜詠一十首 舴艋舟','李德裕','唐','唐诗','tang','','[]','無輕舴艋舟，始自鴟夷子。',48,'全唐诗/poet.tang.25000.json','["無輕舴艋舟，始自鴟夷子。", "雙闕挂朝衣，五湖極煙水。", "時遊杏壇下，乍入湘川裏。", "永日歌濯纓，超然謝塵滓。"]'),
('edcec266-bb0e-463e-a84c-849192e218a9','思平泉樹石雜詠一十首 二猿','李德裕','唐','唐诗','tang','','[]','釣瀨水漣漪，富春山合沓。',48,'全唐诗/poet.tang.25000.json','["釣瀨水漣漪，富春山合沓。", "松上夜猿鳴，谷中清響合。", "衝網忽見羈，故山從此辭。", "無由碧潭飲，爭接綠蘿枝。"]'),
('9201b478-aece-4771-af96-3e860d0c4ad5','思在山居日偶成此詠邀松陽子同作','李德裕','唐','唐诗','tang','','[]','閑思昔歲事，忽忽念伊川。',72,'全唐诗/poet.tang.25000.json','["閑思昔歲事，忽忽念伊川。", "乘月步秋坂，滿山聞石泉。", "回塘碧潭映，高樹綠蘿懸。", "露下呌田鶴，風來嘶晚蟬。", "懷茲長在夢，歸去且無緣。", "幽谷人未至，蘭苕應更鮮。"]'),
('12496f02-3efa-4bf7-8368-9b23850fa5a3','重憶山居六首 平泉源','李德裕','唐','唐诗','tang','','[]','出谷纔浮芥，中園已濫觴。',48,'全唐诗/poet.tang.25000.json','["出谷纔浮芥，中園已濫觴。", "逶迤過竹塢，浩淼走蘭塘。", "夜靜聞魚躍，風微見鴈翔。", "從茲東向海，可泛濟川航。"]'),
('faaf019b-5e60-4094-a7a6-754762ed30df','重憶山居六首 泰山石','李德裕','唐','唐诗','tang','','["\u6cf0\u5c71"]','雞鳴日觀望，遠與扶桑對。',48,'全唐诗/poet.tang.25000.json','["雞鳴日觀望，遠與扶桑對。", "滄海似鎔金，衆山如點黛。", "遙知碧峰首，獨立煙嵐內。", "此石依五松，蒼蒼幾千載。"]'),
('be29ee26-6ba1-471d-b9d3-948cc2fa4055','重憶山居六首 巫山石','李德裕','唐','唐诗','tang','','[]','十二峰前月，三聲猿夜愁。',48,'全唐诗/poet.tang.25000.json','["十二峰前月，三聲猿夜愁。", "此中多怪石，日夕漱寒流。", "必是歸星渚，先求歷斗牛。", "還疑煙雨霽，髣髴是嵩丘。"]'),
('b6ccc575-b4f1-4027-b442-811fc39a451d','重憶山居六首 羅浮山','李德裕','唐','唐诗','tang','','[]','龍伯釣鼇時，蓬萊一峰坼。',48,'全唐诗/poet.tang.25000.json','["龍伯釣鼇時，蓬萊一峰坼。", "飛來碧海畔，遂與三山隔。", "其下多長溪，潺湲淙亂石。", "知君分如此，贈逾荆山璧。"]'),
('805feea3-9669-4ea8-a097-d50534875e13','重憶山居六首 漏潭石','李德裕','唐','唐诗','tang','','[]','常疑六合外，未信漆園書。',48,'全唐诗/poet.tang.25000.json','["常疑六合外，未信漆園書。", "及此聞溪漏，方欣驗尾閭。", "大哉天地氣，呼吸有盈虛。", "美石勞相贈，瓊瑰自不如。"]'),
('261752fa-18b4-40f4-8014-c470041ba395','重憶山居六首 釣石','李德裕','唐','唐诗','tang','','[]','嚴光隱富春，山色谿又碧。',48,'全唐诗/poet.tang.25000.json','["嚴光隱富春，山色谿又碧。", "所釣不在魚，揮綸以自適。", "余懷慕君子，且欲坐潭石。", "持此返伊川，悠然慰衰疾。"]'),
('0a084f7d-f42e-4381-a3ba-208cd7b0e0cc','懷伊川郊居','李德裕','唐','唐诗','tang','','[]','衰疾常懷土，郊園欲掩扉。',48,'全唐诗/poet.tang.25000.json','["衰疾常懷土，郊園欲掩扉。", "雖知明目地，不及有身歸。", "鞏樹秋陰遍，伊原霽色微。", "此生看白首，良願已應違。"]'),
('19a66e68-70db-4b33-b62e-b2828037323e','晨起見雪憶山居','李德裕','唐','唐诗','tang','','[]','忽憶巖中雪，誰人拂薜蘿。',48,'全唐诗/poet.tang.25000.json','["忽憶巖中雪，誰人拂薜蘿。", "竹梢低未舉，松蓋偃應多。", "山溜隨冰落，林麕帶霰過。", "不勞聞鶴語，方奏苦寒歌。"]'),
('691e9ad8-895a-4613-95f9-a006846938e6','憶平泉雜詠 憶初暖','李德裕','唐','唐诗','tang','','[]','今日初春暖，山中事若何。',48,'全唐诗/poet.tang.25000.json','["今日初春暖，山中事若何。", "雪開喧鳥至，澌散躍魚多。", "幽翠生松栝，輕煙起薜蘿。", "柴扉常晝掩，惟有野人過。"]'),
('16051d12-58a3-4822-9206-4f6697994051','憶平泉雜詠 憶辛夷','李德裕','唐','唐诗','tang','','[]','昔年將出谷，幾日對辛夷。',48,'全唐诗/poet.tang.25000.json','["昔年將出谷，幾日對辛夷。", "倚樹憐芳意，攀條惜歲滋。", "清陰須暫憩，秀色正堪思。", "只待揮金日，慇懃泛羽巵。"]'),
('12029f03-2eaa-44eb-9944-e95e1f178cd8','憶平泉雜詠 憶寒梅','李德裕','唐','唐诗','tang','','[]','寒塘數樹梅，常近臘前開。',48,'全唐诗/poet.tang.25000.json','["寒塘數樹梅，常近臘前開。", "雪映緣巖竹，香侵泛水苔。", "遙思清景暮，還有野禽來。", "誰是攀枝客，茲辰醉始迴。"]'),
('2fb8af5d-a5b4-442e-a9c1-e3f42a2d154f','憶平泉雜詠 憶藥欄','李德裕','唐','唐诗','tang','','[]','野人清旦起，掃雪見蘭芽。',48,'全唐诗/poet.tang.25000.json','["野人清旦起，掃雪見蘭芽。", "始畎春泉入，惟愁暮景斜。", "未抽萱草葉，纔發欵冬花。", "誰念江潭老，中宵旅夢賒。"]'),
('3b70daa4-ed82-4ba5-8dc0-6345d6542862','憶平泉雜詠 憶茗芽','李德裕','唐','唐诗','tang','','[]','谷中春日暖，漸憶掇茶英。',48,'全唐诗/poet.tang.25000.json','["谷中春日暖，漸憶掇茶英。", "欲及清明火，能銷醉客酲。", "松花飄鼎泛，蘭氣入甌輕。", "飲罷閑無事，捫蘿溪上行。"]'),
('50586423-6e02-4ebe-a4a9-1897f6ebdb80','憶平泉雜詠 憶野花','李德裕','唐','唐诗','tang','','[]','雖遊洛陽道，未識故園花。',48,'全唐诗/poet.tang.25000.json','["雖遊洛陽道，未識故園花。", "曉憶東谿雪，晴思冠嶺霞。", "谷深蘭色秀，村迥柳陰斜。", "悵望龍門晚，誰知小隱家。"]'),
('5db47599-0db5-4a4f-90f4-9f76b8d1036e','憶平泉雜詠 憶春雨','李德裕','唐','唐诗','tang','','[]','春鳩鳴野樹，細雨入池塘。',48,'全唐诗/poet.tang.25000.json','["春鳩鳴野樹，細雨入池塘。", "潭上花微落，溪邊草更長。", "梳風白鷺起，拂水綵鴛翔。", "最羨歸飛燕，年年在故鄉。"]'),
('dd98fea1-e19b-4351-9146-f8dbbe56484c','憶平泉雜詠 憶晚眺','李德裕','唐','唐诗','tang','','[]','伊川新雨霽，原上見春山。',48,'全唐诗/poet.tang.25000.json','["伊川新雨霽，原上見春山。", "緱嶺晴虹斷，龍門宿鳥還。", "牛羊平野外，桑柘夕煙間。", "不及鄉園叟，悠悠盡日閑。"]'),
('59deff5a-0aef-479c-831b-b08119cc2119','憶平泉雜詠 憶新藤','李德裕','唐','唐诗','tang','','[]','遙聞碧潭上，春晚紫藤開。',48,'全唐诗/poet.tang.25000.json','["遙聞碧潭上，春晚紫藤開。", "水似晨霞照，林疑綵鳳來。", "清香凝島嶼，繁豔映莓苔。", "金谷如相並，應將錦帳回。"]'),
('0c58fe99-845d-485b-aac7-c69b1c22aed4','憶平泉雜詠 憶春耕','李德裕','唐','唐诗','tang','','[]','郊外杏花坼，林間布穀鳴。',48,'全唐诗/poet.tang.25000.json','["郊外杏花坼，林間布穀鳴。", "原田春雨後，谿水夕流平。", "野老荷蓑至，和風吹草輕。", "無因共沮溺，相與事巖耕。"]'),
('6ac62507-ef98-47a5-a05a-17a6a9dc16a3','余所居平泉村舍近蒙韋常侍大尹特改嘉名因寄詩以謝','李德裕','唐','唐诗','tang','','[]','未謝留侯疾，常懷仲蔚園。',48,'全唐诗/poet.tang.25000.json','["未謝留侯疾，常懷仲蔚園。", "閑謠紫芝曲，歸夢赤松村。", "忽改蓬蒿色，俄吹黍谷暄。", "多慙孔北海，傳教及衡門。"]'),
('5aa27f6a-e4f2-4cc6-ad53-a41d7d552b57','山信至說平泉別墅草木滋長地轉幽深悵然思歸復此作','李德裕','唐','唐诗','tang','','[]','忽聞樵客語，暫慰野人心。',48,'全唐诗/poet.tang.25000.json','["忽聞樵客語，暫慰野人心。", "幽徑芳蘭密，閑庭秀木深。", "麕䴥來澗底，鳧鵠遍川潯。", "誰念滄溟上，歸歟起歎音。"]'),
('c376716e-14a2-4ef3-99eb-f6ab69daff67','臨海太守惠予赤城石報以是詩','李德裕','唐','唐诗','tang','','[]','聞君採奇石，剪斷赤城霞。',48,'全唐诗/poet.tang.25000.json','["聞君採奇石，剪斷赤城霞。", "潭上倒虹影，波中搖日華。", "仙巖接絳氣，谿路雜桃花。", "若值客星去，便應隨海槎。"]'),
('3d23c60b-3b57-42b4-89b8-09d75abcf2d7','上巳憶江南禊事','李德裕','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河西繞郡城流，上巳應無祓禊遊。',32,'全唐诗/poet.tang.25000.json','["黃河西繞郡城流，上巳應無祓禊遊。", "爲憶淥江春水色，更無宵夢向吳州。"]'),
('158a48fd-893a-4adb-a193-4d769711bf6b','北固懷古','李德裕','唐','唐诗','tang','','[]','自有此山川，於今幾太守。',48,'全唐诗/poet.tang.25000.json','["自有此山川，於今幾太守。", "近世二千石，畢公宣化厚。", "丞相量納川，平陽氣衝斗。", "三賢若時雨，所至躋仁壽。"]'),
('57c0cd57-397e-4054-86d7-24b6a6842efa','汨羅','李德裕','唐','唐诗','tang','','[]','遠謫南荒一病身，停舟暫弔汨羅人。',64,'全唐诗/poet.tang.25000.json','["遠謫南荒一病身，停舟暫弔汨羅人。", "都緣靳尚圖專國，豈是懷王厭直臣。", "萬里碧潭秋景靜，四時愁色野花新。", "不勞漁父重相問，自有招魂拭淚巾。"]'),
('a98dc8fa-b3c5-4d0b-94c7-ad13ade4ccb8','嶺外守歲','李德裕','唐','唐诗','tang','','[]','冬逐更籌盡，春隨斗柄回。',24,'全唐诗/poet.tang.25000.json','["冬逐更籌盡，春隨斗柄回。", "寒暄一夜隔，客鬢兩年催。"]'),
('7e87a58e-fce7-4ef4-9d68-26b7cb3985ec','記韋楚老不遇','李德裕','唐','唐诗','tang','','[]','昔日徵黃綺，余慚在鳳池。',24,'全唐诗/poet.tang.25000.json','["昔日徵黃綺，余慚在鳳池。", "今來招隱士，恨不見瓊枝。"]'),
('137687e4-9cf2-4f1b-a168-214b6a568f8a','題柳郎中故居','李德裕','唐','唐诗','tang','','[]','下馬荒堦日欲曛，潺潺石溜靜中聞。',32,'全唐诗/poet.tang.25000.json','["下馬荒堦日欲曛，潺潺石溜靜中聞。", "鳥啼花發人聲絕，寂寞山窗掩白雲。"]'),
('41c4e91e-fdc9-4eae-b04c-f0a8a9b40c26','盤陀嶺驛樓','李德裕','唐','唐诗','tang','','[]','嵩少心期杳莫攀，好山聊復一開顏。',32,'全唐诗/poet.tang.25000.json','["嵩少心期杳莫攀，好山聊復一開顏。", "明朝便是南荒路，更上層樓望故關。"]'),
('10d7069b-c2af-4350-ad52-41bc0b927b49','句','李德裕','唐','唐诗','tang','','[]','檢經求綠字，憑酒借紅顏。',236,'全唐诗/poet.tang.25000.json','["檢經求綠字，憑酒借紅顏。", "君不見秋山寂歷風飆歇，半夜青崖吐明月。", "寒光乍出松篠間，萬籟蕭蕭從此發。", "忽聞歌管吟朔風，精魂想在幽巖中。", "銀花懸院榜，神撼引鈴縧。", "葳蕤輕風裏，若銜若垂何可擬。", "自從一夢高唐後，可是無人勝楚王。", "牛羊具特俎，心悟覺身勞。", "雲中棄寶刀，久閑生䏶肉。", "多壽長眉毫，書空蹺足睡。", "路險側身行，誰家幼女敲筯歌。", "何處丁妻點燈織，魚蝦集橘市。", "休咎占人甲，挨持見天丁。", "洛下推年少，山東許地高。", "世上文章士，誰爲第一人。", "老生誇隱拙，時輩毀尖新。", "𭲟濴寒深百尺，奇觚率爾操。", "諷諫欣然納。"]'),
('5a854bf0-ae31-49a9-9dbc-caf2a34eb461','至日荷李常侍過郊居','熊孺登','唐','唐诗','tang','','[]','賤子守柴荆，誰人記姓名。',72,'全唐诗/poet.tang.25000.json','["賤子守柴荆，誰人記姓名。", "風雲千騎降，草木一陽生。", "禮異江河動，歡殊里巷驚。", "稱觴容侍坐，看竹許同行。", "遇覺滄溟淺，恩疑太嶽輕。", "盡搜天地物，無諭此時情。"]'),
('f5e2ca2f-9094-4b19-a87a-23b411269a9f','日暮天無雲','熊孺登','唐','唐诗','tang','','[]','杳杳復蒼然，無雲日暮天。',72,'全唐诗/poet.tang.25000.json','["杳杳復蒼然，無雲日暮天。", "象分青氣外，景盡赤霄前。", "漸吐星河色，遙生水木煙。", "從容難附麗，顧步欲澄鮮。", "但見收三素，何能測上玄。", "應非暫呈瑞，不許出山川。"]'),
('46ace8a4-b7d0-482d-99c2-3d06a2309379','新成小亭月夜','熊孺登','唐','唐诗','tang','','[]','已被月知處，斬新風到來。',24,'全唐诗/poet.tang.25000.json','["已被月知處，斬新風到來。", "無人伴幽境，多取木蘭栽。"]'),
('7e6cbbb7-bb2b-44fc-9872-de4caa63bf40','和竇中丞歲酒喜見小男兩歲','熊孺登','唐','唐诗','tang','','[]','更添十歲應爲相，歲酒從今把未休。',32,'全唐诗/poet.tang.25000.json','["更添十歲應爲相，歲酒從今把未休。", "聞得一毛添五色，眼看相逐鳳池頭。"]'),
('d3eb132b-a28e-4818-8365-8108de95eb53','寒食','熊孺登','唐','唐诗','tang','','[]','東風潑火雨新休，舁盡春泥掃雪溝。',32,'全唐诗/poet.tang.25000.json','["東風潑火雨新休，舁盡春泥掃雪溝。", "走馬犢車當御路，漢陽公主謝雞毬。"]'),
('3ac4bc63-1f26-43ca-ae56-a1e19183ae21','送僧遊山','熊孺登','唐','唐诗','tang','','[]','雲身自在山山去，何處靈山不是歸？日暮寒林投古寺，雪花飛滿水田衣。',32,'全唐诗/poet.tang.25000.json','["雲身自在山山去，何處靈山不是歸？日暮寒林投古寺，雪花飛滿水田衣。"]'),
('af75cd78-0728-47b7-bada-4d86c17246ba','雪中荅僧書','熊孺登','唐','唐诗','tang','','[]','八行銀字非常草，六出天花盡是梅。',32,'全唐诗/poet.tang.25000.json','["八行銀字非常草，六出天花盡是梅。", "無所與陳童子別，雪中辛苦遠山來。"]'),
('425c8711-eba2-4dc9-b5c3-63551e442509','題逍遙樓傷故韋大夫','熊孺登','唐','唐诗','tang','','[]','利及生人無更爲，落花流水舊城池。',32,'全唐诗/poet.tang.25000.json','["利及生人無更爲，落花流水舊城池。", "逍遙樓上雕龍字，便是羊公墮淚碑。"]'),
('0d1cab24-322f-4541-83cd-3989e646218e','戲贈費冠卿','熊孺登','唐','唐诗','tang','','[]','但恐紅塵虛白首，寧論蹇逸分先後。',32,'全唐诗/poet.tang.25000.json','["但恐紅塵虛白首，寧論蹇逸分先後。", "莫占鶯花笑寂寥，長安春色年年有。"]'),
('d3a9e265-1ee6-41cb-93ea-97c926a08426','與左興宗湓城別','熊孺登','唐','唐诗','tang','','[]','江逢九派人將別，猨到三聲月爲秋。',32,'全唐诗/poet.tang.25000.json','["江逢九派人將別，猨到三聲月爲秋。", "不知相見更何日，此夜少年堪白頭。"]'),
('3be54319-2e12-4990-90b4-18fe94de3517','八月十五夜臥疾','熊孺登','唐','唐诗','tang','','[]','一年秪有今宵月，盡上江樓獨病眠。',32,'全唐诗/poet.tang.25000.json','["一年秪有今宵月，盡上江樓獨病眠。", "寂寞竹窗閑不閉，夜深斜影到牀前。"]'),
('6eeef00c-d99d-4f78-8d1b-e68dda63d885','正月十五日','熊孺登','唐','唐诗','tang','','[]','漢家遺事今宵見，楚郭明燈幾處張。',32,'全唐诗/poet.tang.25000.json','["漢家遺事今宵見，楚郭明燈幾處張。", "深夜行歌聲絕後，紫姑神下月蒼蒼。"]'),
('ea08d350-3d1f-46a0-934f-3dffd9c5df36','曲池陪宴即事上竇中丞','熊孺登','唐','唐诗','tang','','[]','水自山阿繞坐來，珊瑚臺上木綿開。',32,'全唐诗/poet.tang.25000.json','["水自山阿繞坐來，珊瑚臺上木綿開。", "欲知舉目無情罰，一片花流酒一杯。"]'),
('fc4163c1-1ab3-4d39-a2ac-1edc318d82f9','董監廟','熊孺登','唐','唐诗','tang','','[]','仁傑淫祠廢欲無，枯楓老櫟兩三株。',32,'全唐诗/poet.tang.25000.json','["仁傑淫祠廢欲無，枯楓老櫟兩三株。", "神烏慣得商人食，飛趂征帆過蠡湖。"]'),
('940eed81-f316-4ce4-91ec-6133b3dc0053','贈侯山人','熊孺登','唐','唐诗','tang','','[]','一見清容愜素聞，有人傳是紫陽君。',32,'全唐诗/poet.tang.25000.json','["一見清容愜素聞，有人傳是紫陽君。", "來時玉女裁春服，翦破湘山幾片雲。"]'),
('0ae0d493-0303-4bad-8e1e-47618616b9a0','送馬判官赴安南','熊孺登','唐','唐诗','tang','','[]','故人交趾去從軍，應笑狂生揮陣雲。',32,'全唐诗/poet.tang.25000.json','["故人交趾去從軍，應笑狂生揮陣雲。", "省得蔡州今日事，舊曾都護帳前聞。"]'),
('6e1a37f4-5102-43bd-a77c-564a8c009ca4','送準上人歸石經院','熊孺登','唐','唐诗','tang','','[]','旃檀刻像今猶少，白石鐫經古未曾。',32,'全唐诗/poet.tang.25000.json','["旃檀刻像今猶少，白石鐫經古未曾。", "歸去更尋翻譯寺，前山應遇鴈門僧。"]'),
('86979e4a-c861-428f-b333-b4f4a82f4f6d','寒食野望','熊孺登','唐','唐诗','tang','','[]','拜掃無過骨肉親，一年唯此兩三辰。',32,'全唐诗/poet.tang.25000.json','["拜掃無過骨肉親，一年唯此兩三辰。", "冢頭莫種有花樹，春色不關泉下人。"]'),
('7e371811-fcc1-4621-b150-a16b614468b9','祗役遇風謝湘中春色','熊孺登','唐','唐诗','tang','','[]','水生風熟布帆新，只見公程不見春。',32,'全唐诗/poet.tang.25000.json','["水生風熟布帆新，只見公程不見春。", "應被百花撩亂笑，比來天地一閑人。"]'),
('0dce9802-f272-4056-8b28-2726e55f5ade','湘江夜泛','熊孺登','唐','唐诗','tang','','[]','江流如箭月如弓，行盡三湘數夜中。',32,'全唐诗/poet.tang.25000.json','["江流如箭月如弓，行盡三湘數夜中。", "無那子規知向蜀，一聲聲似怨春風。"]'),
('44c219c5-cf2c-46c5-b680-4b2d201ce577','蜀江水','熊孺登','唐','唐诗','tang','','[]','日夜朝宗來萬里，共憐江水引蕃心。',32,'全唐诗/poet.tang.25000.json','["日夜朝宗來萬里，共憐江水引蕃心。", "若論巴峽愁人處，猨比灘聲是好音。"]'),
('017629b3-5b29-49b9-9f83-86feb3a7ff00','寄安南馬中丞','熊孺登','唐','唐诗','tang','','[]','龍韜能致虎符分，萬里霜臺壓瘴雲。',32,'全唐诗/poet.tang.25000.json','["龍韜能致虎符分，萬里霜臺壓瘴雲。", "蕃客不須愁海路，波神今伏馬將軍。"]'),
('ec75a12e-606e-460c-8d3d-859e2a583bda','甘子堂陪宴上韋大夫','熊孺登','唐','唐诗','tang','','[]','武陵樓上春長早，甘子堂前花落遲。',32,'全唐诗/poet.tang.25000.json','["武陵樓上春長早，甘子堂前花落遲。", "楚樂怪來聲競起，新歌盡是大夫詞。"]'),
('c64f0074-8f80-4839-82aa-54895e242fdb','青溪村居二首 一','熊孺登','唐','唐诗','tang','','[]','家占溪南千箇竹，地臨湖上一羣山。',32,'全唐诗/poet.tang.25000.json','["家占溪南千箇竹，地臨湖上一羣山。", "漁船多在馬長放，出處自由閑不閑。"]'),
('83e95aa1-77e2-4d4c-8f5d-9a1c3ac65d67','青溪村居二首 二','熊孺登','唐','唐诗','tang','','[]','深樹黃[鸝]曉一聲，林西江上月猶明。',34,'全唐诗/poet.tang.25000.json','["深樹黃[鸝]曉一聲，林西江上月猶明。", "野人早起無他事，貪繞沙泉看笋生。"]'),
('843a96bd-6aa8-43bc-b0ca-c6d2f25693ec','奉和興元鄭相公早春送楊侍郎','熊孺登','唐','唐诗','tang','','[]','征鞍欲上醉還留，南浦春生百草頭。',32,'全唐诗/poet.tang.25000.json','["征鞍欲上醉還留，南浦春生百草頭。", "丞相新裁別離曲，聲聲飛出舊梁州。"]'),
('9522d29d-f489-4b7f-ba58-d741b60a2f12','送舍弟孺復往廬山','熊孺登','唐','唐诗','tang','','["\u5e90\u5c71"]','能騎竹馬辨西東，未省煙花暫不同。',32,'全唐诗/poet.tang.25000.json','["能騎竹馬辨西東，未省煙花暫不同。", "第一早歸春欲盡，廬山好看過湖風。"]'),
('cb4b2fc0-ce53-4570-8f10-6c6b71ee6cac','野別留少微上人','熊孺登','唐','唐诗','tang','','[]','若爲相見還分散，翻覺浮雲亦不閑。',32,'全唐诗/poet.tang.25000.json','["若爲相見還分散，翻覺浮雲亦不閑。", "何處留師暫且住，家貧唯有坐中山。"]'),
('f680d452-eee6-47f9-91e5-58d07bff29de','經古墓','熊孺登','唐','唐诗','tang','','[]','碑折松枯山火燒，夜臺從閉不曾朝。',32,'全唐诗/poet.tang.25000.json','["碑折松枯山火燒，夜臺從閉不曾朝。", "那將逝者比流水，流水東流逢上潮。"]'),
('bf4f2dfe-b4cb-41f7-993c-ac415ea11f4b','贈靈徹上人','熊孺登','唐','唐诗','tang','','[]','詩句能生世界春，僧家更有姓湯人。',32,'全唐诗/poet.tang.25000.json','["詩句能生世界春，僧家更有姓湯人。", "況聞暗憶前朝事，知是修行第幾身。"]'),
('8995d335-d4de-40ac-9e2a-e37db1d5cd91','春郊醉中贈章八元','熊孺登','唐','唐诗','tang','','[]','三月踏青能幾日，百回添酒莫辭頻。',32,'全唐诗/poet.tang.25000.json','["三月踏青能幾日，百回添酒莫辭頻。", "看君到臥楊花裏，始覺春光爲醉人。"]'),
('0dd55a4b-9489-4fb8-a948-3e5550372f6f','懷古','李涉','唐','唐诗','tang','','[]','尼父未適魯，屢屢倦迷津。',48,'全唐诗/poet.tang.25000.json','["尼父未適魯，屢屢倦迷津。", "徒懷教化心，紆鬱不能伸。", "一遇知己言，萬方始喧喧。", "至今百王則，孰不挹其源。"]'),
('b098ed67-25f5-43e3-ab71-d3ebec7caa1a','詠古','李涉','唐','唐诗','tang','','[]','大智思濟物，道行心始休。',96,'全唐诗/poet.tang.25000.json','["大智思濟物，道行心始休。", "垂綸自消息，歲月任春秋。", "紂虐武既賢，風雲固可求。", "順天行殺機，所向協良謀。", "況以丈人師，將濟安川流。", "何勞問枯骨，再取陰陽籌。", "霸國不務仁，兵戈恣相酬。", "空令渭水迹，千古獨悠悠。"]'),
('1f4f0ec0-15a2-405b-a0c0-b29328a660a1','題清溪鬼谷先生舊居','李涉','唐','唐诗','tang','','[]','翠壁開天池，青崖列雲樹。',120,'全唐诗/poet.tang.25000.json','["翠壁開天池，青崖列雲樹。", "冰容不可狀，杳若清河霧。", "常聞先生教，指示秦儀路。", "二子才不同，逞詞過尺度。", "偶因從吏役，遠到冥棲處。", "松月想舊山，煙霞了如故。", "未遑鍊金鼎，日覺容光暮。", "萬慮隨境生，何由返真素。", "寂寞天籟息，清逈鳥聲曙。", "迴首望重重，無期挹風馭。"]'),
('343c239c-b223-409d-a7c8-39adbeda60ce','感興','李涉','唐','唐诗','tang','','[]','隋氏造宮闕，峨峨倚雲煙。',72,'全唐诗/poet.tang.25000.json','["隋氏造宮闕，峨峨倚雲煙。", "搜奇竭四海，立制謀千年。", "秦兵半夜來，烈火焚高臺。", "萬人聚筋血，一旦爲塵埃。", "君看汴河路，尚說隋家柳。", "但問哭陵人，秋草沒來久。"]'),
('c71c6d07-b995-45d0-8a4c-6e52d666025b','鷓鴣詞二首 一','李涉','唐','唐诗','tang','','[]','湘江煙水深，沙岸隔楓林。',48,'全唐诗/poet.tang.25000.json','["湘江煙水深，沙岸隔楓林。", "何處鷓鴣飛，日斜斑竹陰。", "二女空垂淚，三閭枉自沉。", "惟有鷓鴣啼，獨傷行客心。"]'),
('ad840d0b-010c-4354-8102-23ff0d3a9a57','鷓鴣詞二首 二','李涉','唐','唐诗','tang','','[]','越岡連越井，越鳥更南飛。',48,'全唐诗/poet.tang.25000.json','["越岡連越井，越鳥更南飛。", "何處鷓鴣啼，夕煙東嶺歸。", "嶺外行人少，天涯北客稀。", "鷓鴣啼別處，相對淚沾衣。"]'),
('7b5ccf33-1111-4a85-83e3-2f8c2dfee85c','山中','李涉','唐','唐诗','tang','','[]','無奈牧童何，放牛喫我竹。',36,'全唐诗/poet.tang.25000.json','["無奈牧童何，放牛喫我竹。", "隔林呼不譍，呌笑如生鹿。", "欲報田舍翁，更深不歸屋。"]'),
('b11b4329-af6c-4005-9a6b-889ead1d6a62','寄荆娘寫真','李涉','唐','唐诗','tang','','[]','章華臺南莎草齊，長河柳色連金堤。',368,'全唐诗/poet.tang.25000.json','["章華臺南莎草齊，長河柳色連金堤。", "青樓曈曨曙光蚤，梨花滿巷鶯新啼。", "章臺玉顏年十六，小來能唱西梁曲。", "教坊大使久知名，郢上詞人歌不足。", "少年才子心相許，夜夜高堂夢雲雨。", "五銖香帔結同心，三寸紅牋替傳語。", "緣池並戲雙鴛鴦，田田翠葉紅蓮香。", "百年恩愛兩相許，一夕不見生愁腸。", "上清仙女徵遊伴，欲從湘靈住河漢。", "只愁陵谷變人寰，空歎桑田歸海岸。", "願分精魄定形影，永似銀壺挂金井。", "召得丹青絕世工，寫真與身真相同。", "忽然相對兩不語，疑是妝成來鏡中。", "豈期人願天不違，雲軿却駐從山歸。", "畫圖封裹寄箱篋，洞房豔豔生光輝。", "良人翻作東飛翼，却遣江頭問消息。", "經年不得一封書，翠幕雲屏遶空壁。", "結客有少年，名總身姓江。", "征帆三千里，前月發豫章。", "知我別時言，識我馬上郎。", "恨無羽翼飛，使我徒怨滄波長。", "開篋取畫圖，寄我形影與客將。", "如今憔悴不相似，恐君重見生悲傷。", "蒼梧九疑在何處，斑斑竹淚連瀟湘。"]'),
('88882037-a112-4b54-b424-93fe286f92bf','與弟渤新羅劒歌','李涉','唐','唐诗','tang','','[]','我有神劒異人與，暗中往往精靈語。',128,'全唐诗/poet.tang.25000.json','["我有神劒異人與，暗中往往精靈語。", "識者知從東海來，來時一夜因風雨。", "長河臨曉北斗殘，秋水露背青螭寒。", "昨夜大梁城下宿，不借𨁂跌光顏看。", "刃邊颯颯塵沙缺，瘢痕半是蛟龍血。", "雷煥張華久已無，沉冤知向何人說。", "我有愛弟都九江，一條直氣今無雙。", "青光好去莫惆悵，必斬長鯨須少壯。"]'),
('145c6cc3-53ec-43b1-8162-290f3fe73e95','六歎 一','李涉','唐','唐诗','tang','','[]','綺羅香風翡翠車，清明獨傍芙蓉渠。',80,'全唐诗/poet.tang.25000.json','["綺羅香風翡翠車，清明獨傍芙蓉渠。", "上有雲鬟洞仙女，垂羅掩縠煙中語。", "風月頻驚桃李時，滄波久別鴛鴻侶。", "欲傳一札孤飛翼，山長水遠無消息。", "却鎖重門一院深，半夜空庭明月色。"]'),
('3724d7b6-b2a4-4325-9adb-ab513afbed22','六歎 二','李涉','唐','唐诗','tang','','[]','深院梧桐夾金井，上有轆轤青絲索。',64,'全唐诗/poet.tang.25000.json','["深院梧桐夾金井，上有轆轤青絲索。", "美人清晝汲寒泉，寒泉欲上銀缾落。", "迢迢碧甃千餘尺，竟日倚闌空歎息。", "惆悵不來照明鏡，却掩洞房抱寂寂。"]'),
('09e35871-4478-4c35-ac32-81e401b05360','六歎 三','李涉','唐','唐诗','tang','','[]','漢臣一沒丁零塞，牧羊西過陰沙外。',96,'全唐诗/poet.tang.25000.json','["漢臣一沒丁零塞，牧羊西過陰沙外。", "朝憑南鴈信難回，夜望北辰心獨在。", "漢家茅土橫九州，高門長戟封王侯。", "但將鐘鼓悅私愛，肯以犬羊爲國羞。", "夜宿寒雲臥冰雪，嚴風觸刃垂旌節。", "丁年奉使白頭歸，泣盡李陵衣上血。"]'),
('2492153c-d2ed-4dae-a398-248f53e1c711','春山三朅來 一','李涉','唐','唐诗','tang','','[]','釣魚朅來春日暖，沿溪不厭舟行緩。',112,'全唐诗/poet.tang.25000.json','["釣魚朅來春日暖，沿溪不厭舟行緩。", "野竹初栽碧玉長，澄潭欲下青絲短。", "昔人避世兼避讐，暮棲雲外朝悠悠。", "我今無事亦如此，赤鯉忽到長竿頭。", "汎汎隨波凡幾里，碧莎如煙沙似砥。", "瘦壁橫空怪石危，山花鬬日禽爭水。", "有時帶月歸扣舷，身閑自是漁家仙。"]'),
('1c09f945-fce3-481d-abfb-8e29b13e70b6','春山三朅來 二','李涉','唐','唐诗','tang','','[]','山上朅來採新茗，新花亂發前山頂。',64,'全唐诗/poet.tang.25000.json','["山上朅來採新茗，新花亂發前山頂。", "瓊英動搖鍾乳碧，業業高下隨崖嶺。", "未必蓬萊有仙藥，能向鼎中雲漠漠。", "越甌遙見裂鼻香，欲覺身輕騎白鶴。"]'),
('b68143da-8bbd-4bb7-8989-fde18ff51aa9','春山三朅來 三','李涉','唐','唐诗','tang','','[]','採藥朅來藥苗盛，藥生只傍行人徑。',96,'全唐诗/poet.tang.25000.json','["採藥朅來藥苗盛，藥生只傍行人徑。", "世人重耳不重目，指似藥苗心不足。", "野客住山三十載，妻兒共寄浮雲外。", "小男學語便分別，已辯君臣知匹配。", "都市廣長開大鋪，疾來求者多相悞。", "見說韓康舊姓名，識之不識先相怒。"]'),
('6ff463a1-0105-4abb-a798-d6583a427af0','牧童詞','李涉','唐','唐诗','tang','','["\u513f\u7ae5", "\u8bbd\u523a"]','朝牧牛，牧牛下江曲。',52,'全唐诗/poet.tang.25000.json','["朝牧牛，牧牛下江曲。", "夜牧牛，牧牛度村谷。", "荷蓑出林春雨細，蘆管臥吹莎草綠。", "亂插蓬蒿箭滿腰，不怕猛虎欺黃犢。"]'),
('eb2b7ed7-2003-4c2d-a0f1-ca154b7db0ce','醉中贈崔膺','李涉','唐','唐诗','tang','','[]','與君兄弟匡嶺故，與君相逢揚子渡。',192,'全唐诗/poet.tang.25000.json','["與君兄弟匡嶺故，與君相逢揚子渡。", "白浪南分吳塞雲，綠楊深入隋宮路。", "隋家文物今雖改，舞館歌臺基尚在。", "煬帝陵邊草木深，汴河流水空歸海。", "古今悠悠人自別，此地繁華終未歇。", "大道青樓夾翠煙，瓊墀繡帳開明月。", "與君一言兩相許，外捨形骸中爾女。", "揚州歌酒不可追，洛神映箔湘妃語。", "白馬黃金爲身置，誰能獨羨他人醉。", "暫到香爐一夕間，能展愁眉百世事。", "君看白日光如箭，一度別來顏色變。", "早謀侯印佩腰間，莫遣看花鬢如霰。"]'),
('fead2d67-502b-4d65-9654-91184c8bb0e6','岳陽別張[祜]','李涉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','十年蹭蹬爲逐臣，鬢毛白盡巴江春。',208,'全唐诗/poet.tang.25000.json','["十年蹭蹬爲逐臣，鬢毛白盡巴江春。", "鹿鳴猨嘯雖寂寞，水蛟山魅多精神。", "山瘧困中聞有赦，死灰不望光陰借。", "半夜州符喚牧童，虛教衰病生驚怕。", "巫峽洞庭千里餘，蠻陬水國何親疎。", "由來真宰不宰我，徒勞歎者懷吹噓。", "霸橋昔與張生別，萬變桑田何處說。", "龍蛇縱在沒泥塗，長衢却爲駑駘設。", "愛君氣堅風骨峭，文章真把江淹笑。", "洛下諸生懼刺先，烏鳶不得齊鷹鷂。", "岳陽西南湖上寺，水閣松房遍文字。", "新釘張生一首詩，自餘吟著皆無味。", "策馬前途須努力，莫學龍鍾虛歎息。"]'),
('bf2d56e6-f9a8-49d1-90a7-feb92bd667a0','寄河陽從事楊潛','李涉','唐','唐诗','tang','','["\u9ec4\u6cb3"]','憶昨天台尋石梁，赤城枕下看扶桑。',380,'全唐诗/poet.tang.25000.json','["憶昨天台尋石梁，赤城枕下看扶桑。", "金烏欲上海如血，翠色一點蓬萊光。", "安期先生不可見，蓬萊目極滄海長。", "回舟偶得風水便，煙帆數夕歸瀟湘。", "瀟湘水清巖嶂曲，夜宿朝遊常不足。", "一自無名身事閑，五湖雲月偏相屬。", "進者恐不榮，退者恐不深。", "魚遊鳥逝兩雖異，彼此各有遂生心。", "身解耕耘妾能織，歲晏飢寒免相逼。", "稚子纔年七歲餘，漁樵一半分渠力。", "吾友從軍在河上，腰佩吳鉤佐飛將。", "偶與嵩山道士期，西尋汴水來相訪。", "見君顏色猶憔悴，知君未展心中事。", "落日驅車出孟津，高歌共歎傷心地。", "洛邑秦城少年別，兩都陳事空聞說。", "漢家天子不東遊，古木行宮閉煙月。", "洛濱老翁年八十，西望殘陽臨水泣。", "自言生長開元中，武皇恩化親霑及。", "當時天下無甲兵，雖聞賦斂毫毛輕。", "紅車翠蓋滿衢路，洛中歡笑爭逢迎。", "一從戎馬來幽薊，山谷虎狼無捍制。", "九重宮殿閉豺狼，萬國生人自相噬。", "蹭蹬瘡痍今不平，干戈南北常縱橫。", "中原膏血焦欲盡，四郊貪將猶憑陵。"]'),
('d98614d7-0daa-4402-bf60-f57f5b1e42cb','重登滕王閣','李涉','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','滕王閣上唱伊州，二十年前向此遊。',32,'全唐诗/poet.tang.25000.json','["滕王閣上唱伊州，二十年前向此遊。", "半是半非君莫問，好山長在水長流。"]'),
('530f8fa6-4dbf-45ee-835c-dc3ccfa5f7af','重到襄陽哭亡友韋壽朋','李涉','唐','唐诗','tang','','[]','故人墳樹立秋風，伯道無兒跡便空。',32,'全唐诗/poet.tang.25000.json','["故人墳樹立秋風，伯道無兒跡便空。", "重到笙歌分散地，隔江吹笛月明中。"]'),
('b0d7a1c5-77a0-4649-a5d1-1108cdcaec49','再至長安','李涉','唐','唐诗','tang','','[]','十年謫宦鬼方人，三遇鴻恩始到秦。',32,'全唐诗/poet.tang.25000.json','["十年謫宦鬼方人，三遇鴻恩始到秦。", "今日九衢騎馬望，却疑渾是剎那身。"]'),
('10882d59-cdfe-4a9e-be58-c9b13c4b1a63','贈道器法師','李涉','唐','唐诗','tang','','[]','冰作形容雪作眉，早知談論兩川知。',32,'全唐诗/poet.tang.25000.json','["冰作形容雪作眉，早知談論兩川知。", "如今不用空求佛，但把令狐宰相詩。"]'),
