('6d2278b0-2912-48e0-9b8e-c9ed7a95024e','貢院樓北新栽小松','吳武陵','唐','唐诗','tang','','[]','拂檻愛貞容，移根自遠峰。',72,'全唐诗/poet.tang.25000.json','["拂檻愛貞容，移根自遠峰。", "已曾經草沒，終不任苔封。", "葉少初陵雪，鱗生欲化龍。", "乘春濯雨露，得地近垣墉。", "逐吹香微動，含煙色漸濃。", "時迴日月照，爲謝小山松。"]'),
('24ac2908-f223-4498-87b5-97b9a3bd782f','題路左佛堂','吳武陵','唐','唐诗','tang','','[]','雀兒來逐颺風高，下視鷹鸇意氣豪。',32,'全唐诗/poet.tang.25000.json','["雀兒來逐颺風高，下視鷹鸇意氣豪。", "自謂能生千里翼，黃昏依舊委蓬蒿。"]'),
('d212cafa-6d47-405f-8e4d-00124c278927','盛山十二詩 隱月岫','韋處厚','唐','唐诗','tang','','[]','初映鉤如線，終銜鏡似鉤。',24,'全唐诗/poet.tang.25000.json','["初映鉤如線，終銜鏡似鉤。", "遠澄秋水色，高倚曉河流。"]'),
('2a8f42ef-af07-4b36-b905-fada91ba6808','盛山十二詩 流桮渠','韋處厚','唐','唐诗','tang','','[]','激曲縈飛箭，浮溝泛滿巵。',24,'全唐诗/poet.tang.25000.json','["激曲縈飛箭，浮溝泛滿巵。", "將來山太守，早向習家池。"]'),
('ddadb644-49a7-452c-8ce3-85ebd55de76f','盛山十二詩 竹巖','韋處厚','唐','唐诗','tang','','[]','不資冬日秀，爲作暑天寒。',24,'全唐诗/poet.tang.25000.json','["不資冬日秀，爲作暑天寒。", "先植誠非鳳，來翔定是鸞。"]'),
('78a5f66c-fe4e-475d-b9a3-ba41688cbdcf','盛山十二詩 繡衣石榻','韋處厚','唐','唐诗','tang','','[]','巉巉雪中嶠，磊磊標方峭。',24,'全唐诗/poet.tang.25000.json','["巉巉雪中嶠，磊磊標方峭。", "勿爲枕蒼山，還當礎清廟。"]'),
('bb98701e-e976-45da-8b05-acf763edbecc','盛山十二詩 宿雲亭','韋處厚','唐','唐诗','tang','','[]','雨合飛危砌，天開卷曉窗。',24,'全唐诗/poet.tang.25000.json','["雨合飛危砌，天開卷曉窗。", "齊平聯郭柳，帶繞抱城江。"]'),
('4dc66101-9b61-41a9-9e26-965eef8d818d','盛山十二詩 梅谿','韋處厚','唐','唐诗','tang','','[]','夾岸凝清素，交枝漾淺淪。',24,'全唐诗/poet.tang.25000.json','["夾岸凝清素，交枝漾淺淪。", "味調方薦實，臘近又先春。"]'),
('d64e4068-b378-431a-ab8b-6a3beffd0858','盛山十二詩 桃塢','韋處厚','唐','唐诗','tang','','[]','噴日舒紅景，通蹊茂綠陰。',24,'全唐诗/poet.tang.25000.json','["噴日舒紅景，通蹊茂綠陰。", "終期王母摘，不羨武陵深。"]'),
('b205ed8e-ffd8-44bd-8cb4-b99c6b6c8419','盛山十二詩 胡盧沼','韋處厚','唐','唐诗','tang','','[]','疏鑿徒爲巧，圓窪自可澄。',24,'全唐诗/poet.tang.25000.json','["疏鑿徒爲巧，圓窪自可澄。", "倒花紛錯秀，鑑月靜涵冰。"]'),
('bb7e594f-0839-47f2-88cf-4c44ccf12212','盛山十二詩 茶嶺','韋處厚','唐','唐诗','tang','','[]','顧渚吳商絕，蒙山蜀信稀。',24,'全唐诗/poet.tang.25000.json','["顧渚吳商絕，蒙山蜀信稀。", "千叢因此始，含霞紫英肥。"]'),
('53d63e78-9033-4496-9759-7d94501c8a2d','盛山十二詩 盤石磴','韋處厚','唐','唐诗','tang','','[]','繚繞緣雲上，璘玢甃玉聯。',24,'全唐诗/poet.tang.25000.json','["繚繞緣雲上，璘玢甃玉聯。", "高高曾幾折，極目瞰秋鳶。"]'),
('1bec6a3c-5c7a-4997-b312-9df9d2ea151e','盛山十二詩 琵琶臺','韋處厚','唐','唐诗','tang','','[]','褊地難層土，因厓遂削成。',24,'全唐诗/poet.tang.25000.json','["褊地難層土，因厓遂削成。", "淺深嵐嶂色，盡向此中呈。"]'),
('3ef45051-e18b-4689-8736-146293c05cea','盛山十二詩 上士缾泉','韋處厚','唐','唐诗','tang','','[]','綆汲豈無井，顛崖貴非浚。',24,'全唐诗/poet.tang.25000.json','["綆汲豈無井，顛崖貴非浚。", "願灑塵垢餘，一雨根莖潤。"]'),
('244167c5-829e-4074-99a8-2b3800479429','客思吟','楊敬之','唐','唐诗','tang','','[]','禾黍正離離，南園剪白芝。',48,'全唐诗/poet.tang.25000.json','["禾黍正離離，南園剪白芝。", "細腰沈趙女，高髻唱蠻姬。", "路愧前岡月，梳慚一頷絲。", "鄉人不可語，獨念畏人知。"]'),
('ffcbaa5e-6b6a-45b1-ba5b-a5095b081e8b','贈項斯','楊敬之','唐','唐诗','tang','','[]','幾度見詩詩總好，及觀標格過於詩。',32,'全唐诗/poet.tang.25000.json','["幾度見詩詩總好，及觀標格過於詩。", "平生不解藏人善，到處逢人說項斯。"]'),
('2265ea77-fa3b-4444-9bea-21cdeeaee0a6','句','楊敬之','唐','唐诗','tang','','[]','霜樹鳥棲夜，空街雀報明。',24,'全唐诗/poet.tang.25000.json','["霜樹鳥棲夜，空街雀報明。", "碧山相倚暮，歸鴈一行斜。"]'),
('64487d0c-5df1-41fa-8da2-fcffa8b760a5','初日照鳳樓','李虞仲','唐','唐诗','tang','','[]','旭日煙雲殿，朝陽燭帝居。',72,'全唐诗/poet.tang.25000.json','["旭日煙雲殿，朝陽燭帝居。", "斷霞生峻宇，通閣麗晴虛。", "流彩連朱檻，騰輝照綺疏。", "曈曨晨景裏，明滅曉光初。", "戶牖仙山近，軒楹鳳翼舒。", "還如王母過，遙度五雲車。"]'),
('d03acf16-8e65-4d88-b785-e70ba12fb63b','郡齋三月下旬作','張又新','唐','唐诗','tang','','[]','春事日已歇，池塘曠幽尋。',48,'全唐诗/poet.tang.25000.json','["春事日已歇，池塘曠幽尋。", "殘紅披獨墜，初綠間淺深。", "偃仰倦芳褥，顧步愛新陰。", "謀春未及竟，夏初遽見侵。"]'),
('f6848174-0e38-41e8-90df-8015dc3afcef','五月水邊柳','張又新','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u67f3\u6811"]','結根挺涯涘，垂影覆清淺。',72,'全唐诗/poet.tang.25000.json','["結根挺涯涘，垂影覆清淺。", "睡臉寒未開，嬾腰晴更軟。", "搖空條已重，拂水帶方展。", "似醉煙景凝，如愁月露泫。", "絲長魚悞恐，枝弱禽驚踐。", "悵別幾多情，含春任攀搴。"]'),
('37a1809a-57a7-4e8a-bb1e-b8f1c16df563','三月五日陪大夫泛長沙東湖','張又新','唐','唐诗','tang','','[]','上巳餘風景，芳辰集遠坰。',72,'全唐诗/poet.tang.25000.json','["上巳餘風景，芳辰集遠坰。", "綵舟浮泛蕩，繡轂下娉婷。", "棲樹迴蔥蒨，笙歌轉杳冥。", "湖光迷翡翠，草色醉蜻蜓。", "鳥弄桐花日，魚飜穀雨萍。", "從今留勝會，誰看畫蘭亭。"]'),
('0f4dc3e5-f9ea-4107-ac6e-a0c3cffea693','贈廣陵妓','張又新','唐','唐诗','tang','','[]','雲雨分飛二十年，當時求夢不曾眠。',32,'全唐诗/poet.tang.25000.json','["雲雨分飛二十年，當時求夢不曾眠。", "今來頭白重相見，還上襄王玳瑁筵。"]'),
('94dfe2eb-7282-4b99-a67a-93ca3fe70491','牡丹','張又新','唐','唐诗','tang','','[]','牡丹一朵值千金，將謂從來色最深。',32,'全唐诗/poet.tang.25000.json','["牡丹一朵值千金，將謂從來色最深。", "今日滿欄開似雪，一生辜負看花心。"]'),
('9c381285-f5f3-4f1e-8531-f88d4aa0203f','游白鶴山','張又新','唐','唐诗','tang','','[]','白鶴山邊秋復春，張文宅畔少風塵。',32,'全唐诗/poet.tang.25000.json','["白鶴山邊秋復春，張文宅畔少風塵。", "欲驅五馬尋真隱，誰是當初□竹人。"]'),
('8583618a-0931-4733-8945-75b761e34ff1','行田詩','張又新','唐','唐诗','tang','','[]','白石巖前湖水春，湖邊舊境有清塵。',32,'全唐诗/poet.tang.25000.json','["白石巖前湖水春，湖邊舊境有清塵。", "欲追謝守行田意，今古同憂是長人。"]'),
('60c32812-bf4c-4e8f-a71e-7fc60d8f0690','羅浮山','張又新','唐','唐诗','tang','','[]','江北重巒積翠濃，綺霞遙映碧芙蓉。',32,'全唐诗/poet.tang.25000.json','["江北重巒積翠濃，綺霞遙映碧芙蓉。", "不知末後滄溟上，滅却瀛洲第幾峰。"]'),
('44378e7f-03a5-4723-b836-a23f50318da3','青障山','張又新','唐','唐诗','tang','','[]','一派遠光澄碧月，萬株聳翠獵金飆。',32,'全唐诗/poet.tang.25000.json','["一派遠光澄碧月，萬株聳翠獵金飆。", "陶仙謾學長生術，暑往寒來更寂寥。"]'),
('e69fe3d5-875f-4917-854f-c25f1deaa855','中界山','張又新','唐','唐诗','tang','','[]','瑟瑟峰頭玉水流，晉時遺跡更堪愁。',32,'全唐诗/poet.tang.25000.json','["瑟瑟峰頭玉水流，晉時遺跡更堪愁。", "愁人到此勞長望，何處煙波是祖州。"]'),
('e8da3bba-9c1e-4ec1-92cf-469e04ff4c5b','帆遊山','張又新','唐','唐诗','tang','','[]','漲海嘗從此地流，千帆飛過碧山頭。',32,'全唐诗/poet.tang.25000.json','["漲海嘗從此地流，千帆飛過碧山頭。", "君看深谷爲陵後，翻覆人間未肯休。"]'),
('f4939f42-aaa3-4be2-81c0-be26a1c2e549','謝池','張又新','唐','唐诗','tang','','[]','郡郭東南積穀山，謝公曾是此躋攀。',32,'全唐诗/poet.tang.25000.json','["郡郭東南積穀山，謝公曾是此躋攀。", "今來惟有靈池月，猶是嬋娟一水間。"]'),
('fd989fab-9d1a-47e6-8503-034c6421d8b1','華蓋山','張又新','唐','唐诗','tang','','[]','一岫坡陀凝綠草，千重虛翠透紅霞。',32,'全唐诗/poet.tang.25000.json','["一岫坡陀凝綠草，千重虛翠透紅霞。", "愁來始上消歸思，見盡江城數百家。"]'),
('6ae0dc08-2b4e-4a4c-ad88-c37d1fe75d62','吹臺山','張又新','唐','唐诗','tang','','[]','吹臺山上綵煙凝，日落雲收疊翠屏。',32,'全唐诗/poet.tang.25000.json','["吹臺山上綵煙凝，日落雲收疊翠屏。", "應謂焦桐堪採斵，不知誰是柳吳興。"]'),
('852372d6-64ff-4341-816b-63e86e8d2e25','青㠗山','張又新','唐','唐诗','tang','','[]','靈海泓澄匝翠峰，昔賢心賞已成空。',32,'全唐诗/poet.tang.25000.json','["靈海泓澄匝翠峰，昔賢心賞已成空。", "今朝亭館無遺制，積水滄浪一望中。"]'),
('0c23b2e8-35ba-4933-ad6c-fe0b722dc449','孤嶼','張又新','唐','唐诗','tang','','[]','碧水逶迤浮翠巘，綠蘿蒙密媚晴江。',32,'全唐诗/poet.tang.25000.json','["碧水逶迤浮翠巘，綠蘿蒙密媚晴江。", "不知誰與名孤嶼，其實中川是一雙。"]'),
('b95f7661-648c-42f9-b588-d1031babdc19','春草池','張又新','唐','唐诗','tang','','[]','謝公夢草一差微，謫宦當時道不機。',32,'全唐诗/poet.tang.25000.json','["謝公夢草一差微，謫宦當時道不機。", "且謂飛霞遊賞地，池塘煙柳亦依依。"]'),
('63f8c6d2-590e-42f7-ab7f-200d0ca8dd42','春色滿皇州','封敖','唐','唐诗','tang','','[]','帝里春光正，蔥蘢喜氣浮。',72,'全唐诗/poet.tang.25000.json','["帝里春光正，蔥蘢喜氣浮。", "錦鋪仙禁側，鏡寫曲江頭。", "紅蕚開蕭閣，黃絲拂御樓。", "千門歌吹動，九陌綺羅游。", "日近風先滿，仁深澤共流。", "應非顦顇質，辛苦在神州。"]'),
('b9b5506c-bf48-422b-8f35-3c414a46faba','題西隱寺','封敖','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','三年未到九華山，終日披圖一室間。',64,'全唐诗/poet.tang.25000.json','["三年未到九華山，終日披圖一室間。", "秋寺喜因晴後賞，靈峰看待足時還。", "猨從有性留僧坐，雲靄無心伴客閑。", "勝事倘能銷歲月，已𢬵名利不相關。"]'),
('705d39df-af3a-4d59-a434-1dbca31f4da3','奉和白敏中聖道和平致茲休運歲終功就合詠盛明呈上','馬植','唐','唐诗','tang','','[]','舜德堯仁化犬戎，許提河隴欵皇風。',64,'全唐诗/poet.tang.25000.json','["舜德堯仁化犬戎，許提河隴欵皇風。", "指揮貙武皆神算，恢拓乾坤是聖功。", "四帥有征無汗馬，七關雖戍已弢弓。", "天留此事還英主，不在他年在大中。"]'),
('239b21ee-29f9-46b1-8530-64b3eb5ea970','夏日途中','李廓','唐','唐诗','tang','','[]','樹夾炎風路，行人正午稀。',48,'全唐诗/poet.tang.25000.json','["樹夾炎風路，行人正午稀。", "初蟬數聲起，戲蝶一團飛。", "日色欺清鏡，槐膏點白衣。", "無成歸故里，自覺少光輝。"]'),
('7bccac15-d21a-4f27-88f0-73320491822a','長安少年行 一','李廓','唐','唐诗','tang','','[]','金紫少年郎，繞街鞍馬光。',48,'全唐诗/poet.tang.25000.json','["金紫少年郎，繞街鞍馬光。", "身從左中尉，官屬右春坊。", "剗戴揚州帽，重薰異國香。", "垂鞭踏青草，來去杏園芳。"]'),
('c9cad4e9-45f5-4a7f-8a5c-c6fc6b3bf40f','長安少年行 二','李廓','唐','唐诗','tang','','[]','追逐輕薄伴，閑遊不著緋。',48,'全唐诗/poet.tang.25000.json','["追逐輕薄伴，閑遊不著緋。", "長攏出獵馬，數換打毬衣。", "曉日尋花去，春風帶酒歸。", "青樓無晝夜，歌舞歇時稀。"]'),
('a7de110c-eab1-4b7c-a104-c6eac4082551','長安少年行 三','李廓','唐','唐诗','tang','','[]','日高春睡足，帖馬賞年華。',48,'全唐诗/poet.tang.25000.json','["日高春睡足，帖馬賞年華。", "倒插銀魚袋，行隨金犢車。", "還攜新市酒，遠醉曲江花。", "幾度歸侵黑，金吾送到家。"]'),
('3ee29981-5d91-4ab2-8741-aec7a2b312ea','長安少年行 四','李廓','唐','唐诗','tang','','[]','好勝耽長夜，天明燭滿樓。',48,'全唐诗/poet.tang.25000.json','["好勝耽長夜，天明燭滿樓。", "留人看獨脚，賭馬換偏頭。", "樂奏曾無歇，盃巡不暫休。", "時時遙冷笑，怪客有春愁。"]'),
('ab9193b7-f8f2-4ea2-89b6-2e3901600741','長安少年行 五','李廓','唐','唐诗','tang','','[]','遨遊攜豔妓，裝束似男兒。',48,'全唐诗/poet.tang.25000.json','["遨遊攜豔妓，裝束似男兒。", "盃酒逢花住，笙歌簇馬吹。", "鶯聲催曲忽，春色送歸遲。", "不以聞街鼓，華筵待月移。"]'),
('4cec2316-98eb-4847-b9e7-afd610e692af','長安少年行 六','李廓','唐','唐诗','tang','','[]','賞春惟逐勝，大宅可曾歸。',48,'全唐诗/poet.tang.25000.json','["賞春惟逐勝，大宅可曾歸。", "不樂還逃席，多狂慣衩衣。", "歌人踏日起，語燕卷簾飛。", "婦好唯相妬，倡樓不醉稀。"]'),
('d7648538-c3fe-4e1b-9f53-a95e8d63b7a6','長安少年行 七','李廓','唐','唐诗','tang','','[]','戟門連日閉，苦飲惜殘春。',48,'全唐诗/poet.tang.25000.json','["戟門連日閉，苦飲惜殘春。", "開鎖通新客，教姬屈醉人。", "倩歌牽白馬，自舞踏紅茵。", "時輩皆相許，平生不負身。"]'),
('4684cfef-4203-40fa-b581-6983a4350dc5','長安少年行 八','李廓','唐','唐诗','tang','','[]','新年高殿上，始見有光輝。',48,'全唐诗/poet.tang.25000.json','["新年高殿上，始見有光輝。", "玉雁排方帶，金鵝立仗衣。", "酒深和椀賜，馬疾打珂飛。", "朝下人爭看，香街意氣歸。"]'),
('99876d96-72c4-4036-b59d-93d4842c9993','長安少年行 九','李廓','唐','唐诗','tang','','[]','遊市慵騎馬，隨姬入坐車。',48,'全唐诗/poet.tang.25000.json','["遊市慵騎馬，隨姬入坐車。", "樓邊聽歌吹，簾外見鶯花。", "樂眼從人鬧，歸心畏日斜。", "蒼頭來去報，飲伴到倡家。"]'),
('d9ccbf8f-a42f-40f3-91da-68bcebcf0606','長安少年行 十','李廓','唐','唐诗','tang','','[]','小婦教鸚鵡，頭邊喚醉醒。',48,'全唐诗/poet.tang.25000.json','["小婦教鸚鵡，頭邊喚醉醒。", "犬嬌眠玉簟，鷹掣撼金鈴。", "碧地攅花障，紅泥待客亭。", "雖然長按曲，不飲不曾聽。"]'),
('8303277b-eaf1-4632-8c2d-88d5d32553d6','雞鳴曲','李廓','唐','唐诗','tang','','[]','星稀月沒入五更，膠膠角角雞初鳴。',96,'全唐诗/poet.tang.25000.json','["星稀月沒入五更，膠膠角角雞初鳴。", "征人牽馬出門立，辭妾欲向安西行。", "再鳴引頸簷頭下，樓中角聲催上馬。", "纔分曙色第二鳴，旌斾紅塵已出城。", "婦人上城亂招手，夫壻不聞遙哭聲。", "長恨雞鳴別時苦，不遣雞栖近窗戶。"]'),
('91ce633d-ba79-4194-8c52-9c3cfd6ea283','鏡聽詞','李廓','唐','唐诗','tang','','[]','匣中取鏡辭竈王，羅衣掩盡明月光。',82,'全唐诗/poet.tang.25000.json','["匣中取鏡辭竈王，羅衣掩盡明月光。", "昔時長著照容色，今夜潛將聽消息。", "門前地黑人來稀，無人錯道朝夕歸。", "更深弱體冷如鐵，繡帶菱花懷裏熱。", "銅片銅片如有靈，願照得見行人千里形。"]'),
('8265398b-e695-416b-8449-4d3d1a862a10','猛士行','李廓','唐','唐诗','tang','','[]','戰鼓驚沙惡天色，猛士虬髯眼前黑。',48,'全唐诗/poet.tang.25000.json','["戰鼓驚沙惡天色，猛士虬髯眼前黑。", "單于衣錦日行兵，陣頭走馬生擒得。", "幽幷少年不敢輕，虎狼窟裏空手行。"]'),
('d4aa75b7-237a-4b9c-a558-8b98be074ccd','送振武將軍','李廓','唐','唐诗','tang','','["\u9ec4\u6cb3"]','葉葉歸邊騎，風頭萬里乾。',48,'全唐诗/poet.tang.25000.json','["葉葉歸邊騎，風頭萬里乾。", "金裝腰帶重，鐵縫耳衣寒。", "蘆酒燒蓬煖，霜鴻撚箭看。", "黃河古戍道，秋雪白漫漫。"]'),
('003c0582-b66e-4d14-a268-c34dcba97eb9','落第','李廓','唐','唐诗','tang','','[]','牓前潛制淚，衆裏自嫌身。',48,'全唐诗/poet.tang.25000.json','["牓前潛制淚，衆裏自嫌身。", "氣味如中酒，情懷似別人。", "煖風張樂席，晴日看花塵。", "盡是添愁處，深居乞過春。"]'),
('f954ad69-29d1-47de-975a-5b0118730758','贈商山東于嶺僧','李廓','唐','唐诗','tang','','[]','商嶺東西路欲分，兩間茅屋一溪雲。',32,'全唐诗/poet.tang.25000.json','["商嶺東西路欲分，兩間茅屋一溪雲。", "師言耳重知師意，人是人非不欲聞。"]'),
('0b991e53-204d-40fb-b24c-3768bf8a4ff2','上令狐舍人','李廓','唐','唐诗','tang','','[]','名利生愁地，貧居歲月移。',48,'全唐诗/poet.tang.25000.json','["名利生愁地，貧居歲月移。", "買書添架上，斷酒過花時。", "宿客嫌吟苦，乖童恨睡遲。", "近來唯儉靜，持此荅深知。"]'),
('6106ee78-eef7-4b61-93c5-21e2a0e329c2','南梁行','李紳','唐','唐诗','tang','','[]','江城鬱鬱春草長，悠悠漢水浮青光。',288,'全唐诗/poet.tang.25000.json','["江城鬱鬱春草長，悠悠漢水浮青光。", "雜英飛盡空晝景，綠楊重陰官舍靜。", "此時醉客縱橫書，公言可薦承明廬。", "青天詔下寵光至，頒籍金閨徵石渠。", "秭歸山路煙嵐隔，山木幽深晚花拆。", "澗底紅光奪火燃，搖風扇毒愁行客。", "杜鵑啼咽花亦殷，聲悲絕豔連空山。", "斜陽瞥映淺深樹，雲雨翻迷崖谷間。", "山雞錦質矜毛羽，透竹穿蘿命儔侶。", "喬木幽谿上下同，雄雌不惑飛棲處。", "望秦峰迴過商顏，浪疊雲堆萬簇山。", "行盡杳冥青嶂外，九重鐘漏紫霄間。", "元和列侍明光殿，諫草初焚市朝變。", "北闕趨承半隙塵，南梁笑客皆飛霰。", "追思感歎却昏迷，霜鬢愁吟到曉雞。", "故篋歲深開斷簡，秋堂月曙掩遺題。", "嗚嗚曉角霞輝粲，撫劒當應一長歎。", "芻狗無由學聖賢，空持感激終昏旦。"]'),
('bd879428-876f-438d-a803-e7d4012a15d3','趨翰苑遭誣搆四十六韻','李紳','唐','唐诗','tang','','["\u5e90\u5c71"]','九五當乾德，三千應瑞符。',288,'全唐诗/poet.tang.25000.json','["九五當乾德，三千應瑞符。", "纂堯昌聖曆，宗禹盛丕圖。", "畫象垂新令，消兵易舊謨。", "選賢方去智，招諫忽升愚。", "大樂調元氣，神功運化罏。", "脫鱗超沆瀣，翻翼集蓬壺。", "捧日恩光別，抽毫顧問殊。", "鳳形憐彩筆，龍頷借驪珠。", "擲地聲名寡，摩天羽翮孤。", "潔身酬雨露，利口扇讒諛。", "碧海同宸眷，鴻毛比賤軀。", "辨疑分黑白，舉直觝朋徒。", "庭獸方呈角，階蓂始効莩。", "日傾烏掩魄，星落斗摧樞。", "墜劒悲喬岳，號弓泣鼎湖。", "亂羣逢害馬，擇肉縱狂貙。", "膽爲隳肝竭，心因瀝血枯。", "滿帆摧駭浪，征棹折危途。", "燕客書方詐，堯門信未孚。", "謗興金就鑠，毀極玉生瘉。", "礪吻矜先搏，張羅騁疾驅。", "地嫌稀魍魎，海恨止番禺。", "瘴嶺衝蛇入，蒸池躡虺趨。", "望天收雪涕，看鏡攬霜鬚。"]'),
('3bb3897a-7460-40d1-9ec3-b4738e3f20b4','憶春日太液池亭候對','李紳','唐','唐诗','tang','','[]','宮鶯報曉瑞煙開，三島靈禽拂水迴。',64,'全唐诗/poet.tang.25000.json','["宮鶯報曉瑞煙開，三島靈禽拂水迴。", "橋轉彩虹當綺殿，艦浮花鷁近蓬萊。", "草承香輦王孫長，桃豔仙顏阿母栽。", "簪筆此時方侍從，却思金馬笑鄒枚。"]'),
('25f67eb0-ddd3-41e2-8aaa-7b4311465300','憶夜直金鑾殿承旨','李紳','唐','唐诗','tang','','[]','月當銀漢玉繩低，深聽簫韶碧落齊。',64,'全唐诗/poet.tang.25000.json','["月當銀漢玉繩低，深聽簫韶碧落齊。", "門壓紫垣高綺樹，閣連青瑣近丹梯。", "墨宣外渥催飛詔，草布深恩促換題。", "明日獨歸花路遠，可憐人世隔雲霓。"]'),
('f38153c7-0c90-4503-b578-f68aa067b156','憶春日曲江宴後許至芙蓉園','李紳','唐','唐诗','tang','','[]','春風上苑開桃李，詔許看花入御園。',64,'全唐诗/poet.tang.25000.json','["春風上苑開桃李，詔許看花入御園。", "香徑草中迴玉勒，鳳皇池畔泛金樽。", "綠絲垂柳遮風暗，紅藥低叢拂砌繁。", "歸繞曲江煙景晚，未央明月鎖千門。"]'),
('5e3ee002-494b-4e6d-95d1-f1b6b3973531','新昌宅書堂前有藥樹一株今已盈拱前長慶中於翰林院內西軒藥樹下移得纔長一寸僕夫封一泥丸以歸植今則長成名之天上樹','李紳','唐','唐诗','tang','','[]','白榆星底開紅甲，珠樹宮中長紫霄。',64,'全唐诗/poet.tang.25000.json','["白榆星底開紅甲，珠樹宮中長紫霄。", "丹彩結心纔辨質，碧枝抽葉乍成條。", "羽衣道士偷玄圃，金簡真人護玉苗。", "長帶九天餘雨露，近來蔥翠欲成喬。"]'),
('c242db18-67cc-4326-8be0-a1a8a6a65188','過荆門','李紳','唐','唐诗','tang','','[]','荆江水闊煙波轉，荆門路遶山蔥蒨。',224,'全唐诗/poet.tang.25000.json','["荆江水闊煙波轉，荆門路遶山蔥蒨。", "帆勢侵雲滅又明，山程背日昏還見。", "青青麥隴啼飛鴉，寂寞野徑棠梨花。", "行行驅馬萬里遠，漸入煙嵐危棧賒。", "林中有鳥飛出谷，月上千巖一聲哭。", "腸斷思歸不可聞，人言恨魄來巴蜀。", "我聽此鳥祝我魂，魂死莫學聲銜冤。", "縱爲羽族莫棲息，直上青雲呼帝閽。", "此時山月如銜鏡，嵒樹參差互輝映。", "皎潔深看入澗泉，分明細見樵人徑。", "陰森鬼廟當郵亭，雞豚日宰聞膻腥。", "愚夫禍福自迷惑，魍魎憑何通百靈。", "月低山曉問行客，已酹椒漿拜荒陌。", "惆悵忠貞徒自持，誰祭山頭望夫石。"]'),
('15a04b03-7a41-4faa-9e46-c8d6fb228bb0','涉沅瀟','李紳','唐','唐诗','tang','','[]','屈原死處瀟湘陰，滄浪淼淼雲沈沈。',226,'全唐诗/poet.tang.25000.json','["屈原死處瀟湘陰，滄浪淼淼雲沈沈。", "蛟龍長怒虎長嘯，山木翛翛波浪深。", "煙橫日落驚鴻起，山映餘霞杳千里。", "鴻叫離離入暮天，霞消漠漠深雲水。", "水靈江暗揚波濤，黿鼉動盪風騷騷。", "行人愁望待明月，星漢沈浮𩳤鬼號。", "屈原爾爲懷王沒，水府通天化靈物。", "何不驅雷擊電除奸邪，可憐空作沈泉骨。", "舉杯瀝酒招爾魂，月影滉漾開乾坤。", "波白水黑山隱見，汨羅之上遙昏昏。", "風帆候曉看五兩，戍鼓鼕鼕遠山響。", "潮滿江津猨鳥啼，荆夫楚語飛蠻槳。", "瀟湘島浦無人居，風驚水暗惟鮫魚。", "行來擊棹獨長歎，問爾精魄何所如。"]'),
('74458107-c12f-4aef-9d52-2de3205d3c12','逾嶺嶠止荒陬抵高要','李紳','唐','唐诗','tang','','["\u8861\u5c71"]','天將南北分寒燠，北被羔裘南卉服。',384,'全唐诗/poet.tang.25000.json','["天將南北分寒燠，北被羔裘南卉服。", "寒氣凝爲戎虜驕，炎蒸結作蟲虺毒。", "周王止化惟荆蠻，漢武鑿遠通孱顏。", "南標銅柱限荒徼，五嶺從茲窮險艱。", "衡山截斷炎方北，迴雁峰南瘴煙黑。", "萬壑奔傷溢作瀧，湍飛浪激如繩直。", "千崖傍聳猨嘯悲，丹蛇玄虺潛蜲蛇。", "瀧夫擬檝劈高浪，瞥忽浮沈如電隨。", "嶺頭刺竹蒙籠密，火拆紅蕉焰燒日。", "嶺上泉分南北流，行人照水愁腸骨。", "陰森石路盤縈紆，雨寒日煖常斯須。", "瘴雲暫卷火山外，蒼茫海氣窮番禺。", "鷓鴣猿鳥聲相續，椎髻曉呼同戚促。", "百處谿灘異雨晴，四時雷電迷昏旭。", "魚腸雁足望緘封，地遠三江嶺萬重。", "魚躍豈通清遠峽，雁飛難渡漳江東。", "雲蒸地熱無霜霰，桃李冬華匪時變。", "天際長垂飲澗虹，簷前不去銜泥燕。", "幸逢雷雨盪妖昏，提挈悲歡出海門。", "西日眼明看少長，北風身醒辨寒溫。", "賈生謫去因前席，痛哭書成竟何益。", "物忌忠良表是非，朝驅絳灌爲讎敵。", "明皇聖德異文皇，不使無辜困鬼方。", "漢日傅臣終委棄，如今衰叟重輝光。"]'),
('2f343153-68ff-4ee9-b922-02cadd765bd6','移九江','李紳','唐','唐诗','tang','','["\u5e90\u5c71"]','秋波入白水，帆去侵空小。',204,'全唐诗/poet.tang.25000.json','["秋波入白水，帆去侵空小。", "五兩劇奔星，檣烏疾飛鳥。", "盆城依落日，盆浦看雲眇。", "雲眇更蒼蒼，匡山低夕陽。", "楚客喜風水，秦人悲異鄉。", "異鄉秋思苦，江臯月華吐。", "漾漾隱波亭，悠悠通月浦。", "津橋歸候吏，竹巷開門戶。", "容膝有匡牀，及肩纔數堵。", "隙光非白駒，懸磬我無虞。", "體瘦寡行立，家肥安啜哺。", "天書憐譴謫，重作朱轓客。", "四座眼全青，一麾頭半白。", "今來思往事，往事益悽然。", "風月同今昔，悲歡異目前。", "四時嗟閱水，一紀換流年。", "獨有西庭鶴，孤鳴白露天。"]'),
('dbfa6652-e5ef-48ce-a1ce-03e0487ae0bb','泛五湖','李紳','唐','唐诗','tang','','[]','范子蛻冠履，扁舟逸霄漢。',194,'全唐诗/poet.tang.25000.json','["范子蛻冠履，扁舟逸霄漢。", "嗟予抱險艱，怵惕驚瀰漫。", "窮通泛濫勞，趣適殊昏旦。", "浴日盪層空，浮天淼無畔。", "依灘落葉聚，立浦驚鴻散。", "浪疊雪峰連，山孤翠崖斷。", "風帆同巨壑，雲矗成高岸。", "宇宙可東西，星辰沈粲爛。", "霞生[澒]洞遠，月吐青熒亂。", "豈復問津迷，休爲呂梁歎。", "漂沈自詎保，覆溺心長判。", "吳越郡異鄉，嬰童及爲翫。", "依稀占井邑，嘹唳同鵝鸛。", "舉棹未宵分，維舟方日旰。", "徵斯濟川力，若鼓凌風翰。", "易狎當悔游，臨深罔知難。"]'),
('1963d69d-9c2f-4385-8665-5c134cbeee92','過鍾陵','李紳','唐','唐诗','tang','','[]','龍沙江尾抱鍾陵，水郭村橋晚景澄。',64,'全唐诗/poet.tang.25000.json','["龍沙江尾抱鍾陵，水郭村橋晚景澄。", "江對楚山千里月，郭連漁浦萬家燈。", "省拋雙斾辭榮寵，遽落丹霄起愛憎。", "惆悵舊遊同草露，却思恩顧一霑膺。"]'),
('1929a827-9087-41b7-aaf1-4ebfd3f78b07','泝西江','李紳','唐','唐诗','tang','','[]','江風不定半晴陰，愁對花時盡日吟。',64,'全唐诗/poet.tang.25000.json','["江風不定半晴陰，愁對花時盡日吟。", "孤棹自遲從蹭蹬，亂帆爭疾競浮沈。", "一身累困懷千載，百口無虞貴萬金。", "空闊遠看波浪息，楚山安穩過雲岑。"]'),
('3c4a2b87-1e95-4cb0-a26c-cc4381994944','早發','李紳','唐','唐诗','tang','','[]','沙洲月落宿禽驚，潮起風微曉霧生。',64,'全唐诗/poet.tang.25000.json','["沙洲月落宿禽驚，潮起風微曉霧生。", "黃鶴浪明知上信，黑龍山暗避前程。", "火旗似辨吳門戍，水驛遙迷楚塞城。", "蕭索更看江葉下，兩鄉俱是宦遊情。"]'),
('77c91095-de25-4b2e-b747-4645ceaee538','守滁陽深秋憶登郡城望瑯琊','李紳','唐','唐诗','tang','','[]','山城小閣臨青嶂，紅樹蓮宮接薜蘿。',64,'全唐诗/poet.tang.25000.json','["山城小閣臨青嶂，紅樹蓮宮接薜蘿。", "斜日半巖開古殿，野煙浮水掩輕波。", "菊迎秋節西風急，雁引砧聲北思多。", "深夜獨吟還不寐，坐看凝露滿庭莎。"]'),
('81fa4e34-048d-4c00-9ad7-275ae0e2c963','滁陽春日懷果園閑宴','李紳','唐','唐诗','tang','','[]','西園到日栽桃李，紅白低枝拂酒杯。',64,'全唐诗/poet.tang.25000.json','["西園到日栽桃李，紅白低枝拂酒杯。", "繁豔只愁風處落，醉筵多就月中開。", "勸人莫折憐芳早，把燭頻看畏曉催。", "聞道數年深草露，幾株猶得近池臺。"]'),
('efb42b7c-c404-4b25-91b5-b1cbe6a87ceb','悲善才','李紳','唐','唐诗','tang','','[]','穆王夜幸蓬池曲，金鑾殿開高秉燭。',352,'全唐诗/poet.tang.25000.json','["穆王夜幸蓬池曲，金鑾殿開高秉燭。", "東頭弟子曹善才，琵琶請進新翻曲。", "翠蛾列坐層城女，笙笛參差齊笑語。", "天顏靜聽朱絲彈，衆樂寂然無敢舉。", "銜花金鳳當承撥，轉腕攏弦促揮抹。", "花翻鳳嘯天上來，裴回滿殿飛春雪。", "抽弦度曲新聲發，金鈴玉珮相瑳切。", "流鶯子母飛上林，仙鶴雌雄唳明月。", "此時奉詔侍金鑾，別殿承恩許召彈。", "三月曲江春草綠，九霄天樂下雲端。", "紫髯供奉前屈膝，盡彈妙曲當春日。", "寒泉注射隴水開，胡雁翻飛向天沒。", "日曛塵暗車馬散，爲惜新聲有餘歎。", "明年冠劒閉橋山，萬里孤臣投海畔。", "籠禽鎩翮尚還飛，白首生從五嶺歸。", "聞道善才成朽骨，空餘弟子奉音徽。", "南譙寂寞三春晚，有客彈弦獨淒怨。", "靜聽深奏楚月光，憶昔初聞曲江宴。", "心悲不覺淚闌干，更爲調弦反覆彈。", "秋吹動搖神女佩，月珠敲擊水晶盤。", "自憐淮海同泥滓，恨魄凝心未能死。", "惆悵追懷萬事空，雍門感慨徒爲爾。"]'),
('004fc347-aa39-4d48-a5fa-dda718f4bbe5','聞里謠效古歌','李紳','唐','唐诗','tang','','[]','鄉里兒，桑麻鬱鬱禾黍肥，冬有襤襦夏有絺。',240,'全唐诗/poet.tang.25000.json','["鄉里兒，桑麻鬱鬱禾黍肥，冬有襤襦夏有絺。", "兄鋤弟耨妻在機，夜犬不吠開蓬扉。", "鄉里兒，醉還飽，濁醪初熟勸翁媼。", "鳴鳩拂羽知年好，齊和楊花踏春草。", "勸年少，樂耕桑。", "使君爲我剪荆棘，使君爲我驅豺狼。", "林中無虎山有鹿，水底無蛟魚有魴。", "父漁子獵日歸暮，月明處處舂黃粱。", "鄉里兒，東家父老爲爾言，鼓腹那知生育恩。", "莫令太守馳朱轓，懸鼓一鳴盧鵲喧。", "惡聲主吏噪爾門，唧唧力力烹雞豚。", "鄉里兒，莫悲咤。", "上有明王頒詔下，重選賢良恤孤寡。", "春日遲遲驅五馬，留犢投錢以爲謝。", "鄉里兒，終爾詞。", "我無工巧唯無私，舉手一揮臨路岐。"]'),
('1135b21d-4885-4ba7-97a9-3ab6836ee9e9','轉壽春守太和庚戌歲二月祗命壽陽時替裴五墉終歿因視壁題自墉而上或除名在邊坐殿歿凡七子無一存焉壽人多寇盜好訴訐時謂訐時謂之凶郡獷俗特著蒙此處之顧余衰年甘躡前患俾三月而寇靜朞歲而人和虎不暴物姦吏屏竄三載復遭邪佞所惡授賓客分司東都或舉其目或寄於風亦麤繼詩人之末云','李紳','唐','唐诗','tang','','[]','未登崖谷尋丹竈，且歷軒窗看壁題。',64,'全唐诗/poet.tang.25000.json','["未登崖谷尋丹竈，且歷軒窗看壁題。", "那遇八公生羽翼，空悲七子委塵泥。", "舊壇無復翔雲鶴，廢壘曾經振鼓鼙。", "點檢遺編盡朝菌，應難求望一刀圭。"]'),
('e0b629da-76cc-4223-98b8-25fad7f63656','憶壽春廢虎坑余以春二月至郡主吏舉所職稱霍山多虎每歲採茶爲患擇肉於人至春常修陷穽數十所勒獵者採其皮睛余悉除罷之是歲虎不復爲害至余去郡三載','李紳','唐','唐诗','tang','','[]','匪將履尾求兢惕，那效探雛所患爭。',64,'全唐诗/poet.tang.25000.json','["匪將履尾求兢惕，那效探雛所患爭。", "當路絕羣嘗誡暴，爲猫驅獮亦先迎。", "每推至化宣余力，豈用潛機害爾生。", "休逐豺狼止貪戾，好爲仁獸答皇明。"]'),
('2ac7071c-cfc0-42da-acec-992c1c6b447b','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物 肥河維舟阻凍袛待勅命 一','李紳','唐','唐诗','tang','','[]','罷分符竹作閑官，舟凍肥河擬棹難。',64,'全唐诗/poet.tang.25000.json','["罷分符竹作閑官，舟凍肥河擬棹難。", "食蘗苦心甘處困，飲冰持操敢辭寒。", "夜燈空應漁家火，朝食還依雁宿灘。", "西奏血誠遙稽首，乞容歸病老江干。"]'),
('a8daf794-d044-4e48-9e93-d3f2199fb848','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物 肥河維舟阻凍袛待勅命 二','李紳','唐','唐诗','tang','','[]','淮陽效理空多病，疎受辭榮豈戀班。',64,'全唐诗/poet.tang.25000.json','["淮陽效理空多病，疎受辭榮豈戀班。", "陳力不任趨北闕，有家無處寄東山。", "疲驂豈念前程稅，倦鳥安能待暮還。", "珍重八公山下叟，不勞重淚更追攀。"]'),
('55f2083d-f3ec-4f8d-8372-dabfc656e9cf','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物','李紳','唐','唐诗','tang','','[]','垂陰敢慕甘棠葉，附幹將呈瑞木符。',64,'全唐诗/poet.tang.25000.json','["垂陰敢慕甘棠葉，附幹將呈瑞木符。", "十步蘭茶同秀彩，萬年枝葉表皇圖。", "芟夷不及知無患，雨露曾霑自不枯。", "好住孤根託桃李，莫令從此混樵蘇。"]'),
('0baf4974-11e6-4c7a-82d2-b58d174cf01e','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物','李紳','唐','唐诗','tang','','[]','南山白額同馴擾，亦變仁心去殺機。',64,'全唐诗/poet.tang.25000.json','["南山白額同馴擾，亦變仁心去殺機。", "不競牛甘令買患，免遭狐假妄憑威。", "渡河豈適他邦害，據谷終無暴物非。", "爾效騶虞護生草，豈徒柔伏在淮淝。"]'),
('2e9d86e9-ec10-4a80-8545-eb7ed9541b99','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物 發壽陽分司勅到又遇新正感懷書事','李紳','唐','唐诗','tang','','[]','休爲建隼臨淝守，轉作垂絲入洛人。',64,'全唐诗/poet.tang.25000.json','["休爲建隼臨淝守，轉作垂絲入洛人。", "罷閱舊林三載籍，又開新曆四年春。", "雲遮北雁愁行客，柳起東風慰病身。", "漸喜雪霜消解盡，得隨風水到天津。"]'),
('15f8df0c-2801-4421-87e8-90c683069dbf','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物 初出淝口入淮','李紳','唐','唐诗','tang','','[]','東風百里雪初晴，淝口冰開好濯纓。',64,'全唐诗/poet.tang.25000.json','["東風百里雪初晴，淝口冰開好濯纓。", "野老擁途知意重，病夫拋郡喜身輕。", "人心莫厭如弦直，淮水長憐似鏡清。", "回首夕嵐山翠遠，楚郊烟樹隱襄城。"]'),
('9d6fb4d7-d4b8-4697-b178-54da7fb70fbf','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物 入淮至盱眙','李紳','唐','唐诗','tang','','[]','山凝翠黛孤峰迥，淮起銀花五兩高。',64,'全唐诗/poet.tang.25000.json','["山凝翠黛孤峰迥，淮起銀花五兩高。", "天外綺霞迷海鶴，日邊紅樹豔仙桃。", "岸驚目眩同奔馬，浦溢心疑覩抃鼇。", "寄謝雲帆疾飛鳥，莫誇迴雁卷輕毛。"]'),
('59730cd8-6333-485a-a0e8-79635c51ebb6','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物 憶東湖','李紳','唐','唐诗','tang','','[]','菱歌罷唱鷁舟迴，雪鷺銀鷗左右來。',64,'全唐诗/poet.tang.25000.json','["菱歌罷唱鷁舟迴，雪鷺銀鷗左右來。", "霞散浦邊雲錦截，月昇湖面鏡波開。", "魚驚翠羽金鱗躍，蓮脫紅衣紫菂摧。", "淮口值春偏悵望，數株臨水是寒梅。"]'),
('ec39691c-53b0-4510-a998-77194c0daa61','七年初到洛陽寓居宣教里時已春暮而四老俱在洛中分司','李紳','唐','唐诗','tang','','[]','青莎滿地無三徑，白髮緣頭忝四人。',64,'全唐诗/poet.tang.25000.json','["青莎滿地無三徑，白髮緣頭忝四人。", "官職謬齊商嶺客，姓名那重漢廷臣。", "聖朝寡罪容衰齒，愚叟多慙未退身。", "惟有門人憐鈍拙，勸教沈醉洛陽春。"]'),
('42dea9c8-8efb-46dd-b38c-a0345b3081c2','初秋忽奉詔除浙東觀察使檢校右貂','李紳','唐','唐诗','tang','','[]','龍樓寄引簪裾客，鳳闕陪趨朔望朝。',64,'全唐诗/poet.tang.25000.json','["龍樓寄引簪裾客，鳳闕陪趨朔望朝。", "疎受杜門期脫屣，買臣歸邸忽乘軺。", "印封龜紐知頒爵，冠飾蟬緌更珥貂。", "飛詔寵榮歡里舍，豈徒斑白與垂髫。"]'),
('89a6e1a0-ed9e-4194-a14f-9ecf988625ac','憶至鞏縣河宿待家累追懷','李紳','唐','唐诗','tang','','[]','鞏樹翻紅秋日斜，水分伊洛照餘霞。',64,'全唐诗/poet.tang.25000.json','["鞏樹翻紅秋日斜，水分伊洛照餘霞。", "弓開後騎低初月，鶚駐前旌拂暮鴉。", "閨信坐遲青玉案，弄兒閑望白羊車。", "今來憶事涼風晚，烟浦空悲黃菊花。"]'),
('bcc1e06e-9f0e-4966-8a18-759b2c04a4af','宿揚州','李紳','唐','唐诗','tang','','[]','江橫渡闊烟波晚，潮過金陵落葉秋。',64,'全唐诗/poet.tang.25000.json','["江橫渡闊烟波晚，潮過金陵落葉秋。", "嘹唳塞鴻經楚澤，淺深紅樹見揚州。", "夜橋燈火連星漢，水郭帆檣近斗牛。", "今日市朝風俗變，不須開口問迷樓。"]'),
('75fa0a69-c167-47c0-a8bd-f985b2c4a64b','憶被牛相留醉州中時無他賓牛公夜出真珠輩數人','李紳','唐','唐诗','tang','','[]','嚴城畫角三聲閉，清宴金樽一夕同。',64,'全唐诗/poet.tang.25000.json','["嚴城畫角三聲閉，清宴金樽一夕同。", "銀燭坐隅聽子夜，寶箏筵上起春風。", "酒徵舊對慙衰質，曲換新詞感上宮。", "淮海一從雲雨散，杳然俱是夢魂中。"]'),
('36bd2f7b-c94b-4c0c-a268-281b12e3b75e','早渡揚子江','李紳','唐','唐诗','tang','','[]','日衝海浪翻銀屋，江轉秋波走雪山。',64,'全唐诗/poet.tang.25000.json','["日衝海浪翻銀屋，江轉秋波走雪山。", "青嶂迥開蹲虎戍，碧流潛伏躍龍關。", "地分吳楚星辰內，水迫滄溟宇宙間。", "焚却戍船無戰伐，使知風教被烏蠻。"]'),
('b2b78bd9-0bf1-447b-afea-4b7f5ad48e71','憶過潤州','李紳','唐','唐诗','tang','','[]','昔年從宦干戈地，黃綬青春一魯儒。',64,'全唐诗/poet.tang.25000.json','["昔年從宦干戈地，黃綬青春一魯儒。", "弓犯控弦招武旅，劒當抽匣問狂夫。", "帛書投筆封魚腹，玄髮衝冠捋虎鬚。", "談笑謝金何所媿，不爲偷買用兵符。"]'),
('ef51a4e1-0a22-48a1-96ad-80463b0c8f08','憶登棲霞寺峰','李紳','唐','唐诗','tang','','[]','香印烟火息，法堂鐘磬餘。',168,'全唐诗/poet.tang.25000.json','["香印烟火息，法堂鐘磬餘。", "紗燈耿晨焰，釋子安禪居。", "林葉脫紅影，竹烟含綺疎。", "星珠錯落耀，月宇參差虛。", "顧眺匪恣適，曠襟懷卷舒。", "江海淼清盪，丘陵何所如。", "滔滔可問津，耕者非長沮。", "茅嶺感仙客，蕭園成古墟。", "移步下碧峰，涉澗更躊躇。", "烏噪啄秋果，翠驚銜素魚。", "迴塘彩鷁來，落景標林箊。", "漾漾棹翻月，蕭蕭風襲裾。", "勞歌起舊思，戚歎竟難攄。", "却數共遊者，凋落非里閭。"]'),
('9f9c3e1c-9ba2-4973-8893-9a551dc6451f','憶萬歲樓望金山','李紳','唐','唐诗','tang','','[]','樓高雉堞千師壘，峰拔驚波萬壑攢。',64,'全唐诗/poet.tang.25000.json','["樓高雉堞千師壘，峰拔驚波萬壑攢。", "山絕地維消虎踞，水浮天險尚龍盤。", "蜃噓雲拱飛江島，鼇噴仙巖隔海瀾。", "長對碧波臨古渡，幾經風月與悲歡。"]'),
('d7955404-a6e6-4a5a-8947-f4ae3f518181','過梅里七首  家於無錫四十載今敝廬數堵猶存今列題於後','李紳','唐','唐诗','tang','','[]','上家山，家山依舊好。',186,'全唐诗/poet.tang.25000.json','["上家山，家山依舊好。", "昔去松桂長，今來容鬚老。", "上家山，臨古道。", "高低入雲樹，蕪沒連天草。", "草色綠萋萋，寒蛩徧草啼。", "噪鴉啼樹遠，行雁帖雲齊。", "嵒光翻落日，僧火開經室。", "竹洞磬聲長，松樓鐘韻疾。", "苔階泉溜鈌，石甃青莎密。", "舊徑行處迷，前交坐中失。", "歎息整華冠，持杯強自歡。", "笑歌憐稚孺，弦竹縱吹彈。", "山明溪月上，酒滿心聊放。", "丱髮此淹留，垂絲匪閑曠。", "青山不可上，昔事還惆悵。", "況復白頭人，追懷空望望。"]'),
('eff8686f-2cb8-4d15-9adb-7439085544ad','過梅里七首  家於無錫四十載今敝廬數堵猶存今列題於後 憶東郭居','李紳','唐','唐诗','tang','','[]','昔余過稚齒，從師昧知奧。',168,'全唐诗/poet.tang.25000.json','["昔余過稚齒，從師昧知奧。", "徒懷利物心，不獲藏身寶。", "曳婁一縫掖，出處勞昏早。", "醒醉迷啜哺，衣裳辨顛倒。", "忠誠貫白日，直己憑蒼昊。", "卷舌墮讒諛，驚波息行潦。", "衰禽識舊木，疲馬知歸道。", "楊柳長庭柯，蘭荃覆階草。", "旌旄光里舍，騎服歡妻嫂。", "綠鬢絕新知，蒼鬚稀舊老。", "冠緌身忝貴，齋沐心常禱。", "笙磬諒諧和，庭除還灑掃。", "栖遲還竹巷，物役浸江島。", "倏忽變星霜，悲傷滿衷抱。"]'),
('e951ac7e-488c-4282-a368-a58852fc9f2f','過梅里七首  家於無錫四十載今敝廬數堵猶存今列題於後 憶題惠山寺書堂','李紳','唐','唐诗','tang','','[]','故山一別光陰改，秋露清風歲月多。',64,'全唐诗/poet.tang.25000.json','["故山一別光陰改，秋露清風歲月多。", "松下壯心年少去，池邊衰影老人過。", "白雲生滅依巖岫，青桂榮枯託薜蘿。", "惟有此身長是客，又驅旌斾寄煙波。"]'),
('38869ec6-7ab2-4c91-b1b1-6772267fdf63','過梅里七首  家於無錫四十載今敝廬數堵猶存今列題於後 憶西湖雙鸂鶒','李紳','唐','唐诗','tang','','["\u897f\u6e56"]','雙鸂鶒，錦毛斕斑長比翼，戲繞蓮藂迴錦臆。',100,'全唐诗/poet.tang.25000.json','["雙鸂鶒，錦毛斕斑長比翼，戲繞蓮藂迴錦臆。", "照灼花叢兩相得，漁歌驚起飛南北。", "繚繞追隨不迷惑，雲間上下同棲息。", "不作驚禽遠相憶，東家少婦機中語。", "剪斷迴文泣機杼，徒嗟孔雀銜毛羽。", "一去東南別離苦，五里裴回竟何補。"]'),
('1274d774-d716-4705-8497-c3cdd510a7c0','過梅里七首  家於無錫四十載今敝廬數堵猶存今列題於後 早梅橋','李紳','唐','唐诗','tang','','[]','早梅花，滿枝發。',72,'全唐诗/poet.tang.25000.json','["早梅花，滿枝發。", "東風報春春未徹，紫萼迎風玉珠裂。", "楊柳未黃鶯結舌，委素飄香照新月。", "橋邊一樹傷離別，遊蕩行人莫攀折。", "不競江南豔陽節，任落東風伴春雪。"]'),
('66d08e7c-5949-4f75-a9bf-6fa8f16392c9','過梅里七首  家於無錫四十載今敝廬數堵猶存今列題於後 翡翠塢','李紳','唐','唐诗','tang','','[]','翡翠飛飛繞蓮塢，一啄嘉魚一鳴舞。',80,'全唐诗/poet.tang.25000.json','["翡翠飛飛繞蓮塢，一啄嘉魚一鳴舞。", "蓮莖觸散蓮葉欹，露滴珠光似還浦。", "虞人掠水輕浮弋，翡翠驚飛飛不息。", "直上層空翠影高，還向雲間雙比翼。", "彈射莫及弋不得，日暮虞人空歎息。"]'),
('a36a0840-505a-449f-b3eb-e0060e8ae76d','過梅里七首  家於無錫四十載今敝廬數堵猶存今列題於後','李紳','唐','唐诗','tang','','[]','羽毛似雪無瑕點，顧影秋池舞白雲。',64,'全唐诗/poet.tang.25000.json','["羽毛似雪無瑕點，顧影秋池舞白雲。", "閑整素儀三島近，迴飄清唳九霄聞。", "好風順舉應摩日，逸翮將成莫戀羣。", "凌勵坐看空碧外，更憐鳧鷺老江濆。"]'),
('fac21232-f8fd-4b2f-8e72-c794307ba356','過吳門二十四韻','李紳','唐','唐诗','tang','','[]','煙水吳都郭，閶門架碧流。',288,'全唐诗/poet.tang.25000.json','["煙水吳都郭，閶門架碧流。", "綠楊深淺巷，青翰往來舟。", "朱戶千家室，丹楹百處樓。", "水光搖極浦，草色辨長洲。", "憶作麻衣翠，曾爲旅棹遊。", "放歌隨楚老，清宴奉諸侯。", "花寺聽鶯入，春湖看雁留。", "里吟傳綺唱，鄉語認歈謳。", "橋轉攢虹飲，波通鬬鷁浮。", "竹扉梅圃靜，水巷橘園幽。", "縫堵荒麋苑，穿巖破虎丘。", "舊風猶越鼓，餘俗尚吳鉤。", "故館曾閑訪，遺基亦徧搜。", "吹臺山木盡，香徑佛宮秋。", "帳殿菰蒲掩，雲房露霧收。", "苧蘿妖覆滅，荆棘鬼包羞。", "風月俄黃綬，經過半白頭。", "重來冠蓋客，非復別離愁。", "候火分通陌，前旌駐外郵。", "水風搖綵斾，堤柳引鳴騶。", "問吏兒孫隔，呼名禮敬修。", "顧瞻殊宿昔，語默過悲憂。", "義感心空在，容衰日易偷。", "還持滄海詔，從此布皇猷。"]'),
('58542b87-49af-459c-b37d-aec1d72a7855','杭州天竺靈隱二寺頃歲亦布衣一遊及赴鎮會稽不敢以登臨自適竟不復到寺寺多猨猱謂之孫團彌長其類因追思爲詩二首 一','李紳','唐','唐诗','tang','','[]','翠巖幽谷高低寺，十里松風碧嶂連。',64,'全唐诗/poet.tang.25000.json','["翠巖幽谷高低寺，十里松風碧嶂連。", "開盡春花芳草澗，徧通秋水月明泉。", "石文照日分霞壁，竹影侵雲拂暮煙。", "時有猨猱擾鍾磬，老僧無復得安禪。"]'),
('603d8ea0-383d-43c5-98ea-1b83542a3d14','杭州天竺靈隱二寺頃歲亦布衣一遊及赴鎮會稽不敢以登臨自適竟不復到寺寺多猨猱謂之孫團彌長其類因追思爲詩二首 二','李紳','唐','唐诗','tang','','[]','人煙不隔江城近，水石雖清海氣深。',64,'全唐诗/poet.tang.25000.json','["人煙不隔江城近，水石雖清海氣深。", "波動只觀羅剎相，靜居難識梵王心。", "魚扃晝鎖龍宮寶，雁塔高摩欲界金。", "近日尤聞重雕飾，世人遙禮二檀林。"]'),
('d9356725-b5ad-4a5b-9e36-8e31edb39bf6','渡西陵十六韻','李紳','唐','唐诗','tang','','[]','雨送奔濤遠，風收駭浪平。',192,'全唐诗/poet.tang.25000.json','["雨送奔濤遠，風收駭浪平。", "截流張斾影，分岸走鼙聲。", "獸逐銜波湧，龜艨噴棹輕。", "海門凝霧暗，江渚濕雲橫。", "雁翼看舟子，魚鱗辨水營。", "騎交遮戍合，戈簇擁沙明。", "謬履千夫長，將詢百吏情。", "下車占黍稷，冬雨害粢盛。", "望禱依前聖，垂休翼厚生。", "半江猶慘澹，全野已澄清。", "愛景三辰朗，祥農萬庾盈。", "浦程通曲嶼，海色媚重城。", "弓日鞬櫜動，旗風虎豹爭。", "及郊揮白羽，入里卷紅旌。", "愷悌思陳力，端莊冀表誠。", "臨人與安俗，非止奉師貞。"]'),
('6e8bfad5-2e10-41c7-aeb4-d54624303c4a','新樓詩二十首 新樓','李紳','唐','唐诗','tang','','[]','戎容罷引旌旗卷，朱戶褰開雉堞高。',64,'全唐诗/poet.tang.25000.json','["戎容罷引旌旗卷，朱戶褰開雉堞高。", "山聳翠微連郡閣，地臨滄海接靈鼇。", "坐疑許宅驅雞犬，笑類樊妻化羽毛。", "惆悵桂枝零落促，莫思方朔種仙桃。"]'),
('8648c94f-3480-4c25-b696-87426376b250','新樓詩二十首 海榴亭','李紳','唐','唐诗','tang','','[]','海榴亭早開繁蘂，光照晴霞破碧煙。',64,'全唐诗/poet.tang.25000.json','["海榴亭早開繁蘂，光照晴霞破碧煙。", "高近紫霄疑菡萏，迥依江月半嬋娟。", "懷芳不作翻風豔，別萼猶含泣露妍。", "搖落舊叢雲水隔，不堪行坐數流年。"]'),
('66ca7165-e0a8-4532-93f9-b2835385daae','新樓詩二十首 望海亭','李紳','唐','唐诗','tang','','[]','烏盈兔缺天涯迥，鶴背松梢拂檻低。',64,'全唐诗/poet.tang.25000.json','["烏盈兔缺天涯迥，鶴背松梢拂檻低。", "湖鏡坐隅看匣滿，海濤生處辨雲齊。", "夕嵐明滅江帆小，煙樹蒼茫客思迷。", "蕭索感心俱是夢，九天應共草萋萋。"]'),
('19640e97-9144-4640-9a41-d5512aabb43e','新樓詩二十首','李紳','唐','唐诗','tang','','[]','杜鵑如火千房拆，丹檻低看晚景中。',64,'全唐诗/poet.tang.25000.json','["杜鵑如火千房拆，丹檻低看晚景中。", "繁豔向人啼宿露，落英飄砌怨春風。", "早梅昔待佳人折，好月誰將老子同。", "惟有此花隨越鳥，一聲啼處滿山紅。"]'),
('985b2d1f-3dee-4287-ad74-61ecaf3623f9','新樓詩二十首','李紳','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','爲憐湖水通宵望，不學樊楊却月樓。',64,'全唐诗/poet.tang.25000.json','["爲憐湖水通宵望，不學樊楊却月樓。", "惟待素規澄滿鏡，莫看纖魄挂如鉤。", "卷簾方影侵紅燭，繞竹斜暉透碧流。", "蕭瑟曉風聞木落，此時何異洞庭秋。"]'),
('f8c0f02f-21d3-4bce-acb9-eff80ce4f0c0','新樓詩二十首','李紳','唐','唐诗','tang','','[]','綠波春水湖光滿，丹檻連楹碧嶂遙。',64,'全唐诗/poet.tang.25000.json','["綠波春水湖光滿，丹檻連楹碧嶂遙。", "蘭鷁對飛漁棹急，彩虹翻影海旗搖。", "鬬疑斑虎歸三島，散作遊龍上九霄。", "鼉鼓若雷爭勝負，柳堤花岸萬人招。"]'),
('08a50e12-2888-4249-9484-88f440012324','新樓詩二十首','李紳','唐','唐诗','tang','','[]','銀地溪邊遇衲師，笑將花宇指潛知。',64,'全唐诗/poet.tang.25000.json','["銀地溪邊遇衲師，笑將花宇指潛知。", "定觀玄度生前事，不道靈山別後期。", "真相有無因色界，化城興滅在蓮基。", "好令滄海龍宮子，長護金人舊浴池。"]'),
('42518e41-9216-40b0-ab0e-4eb5f95dbaf5','新樓詩二十首 禹廟','李紳','唐','唐诗','tang','','[]','削平水土窮滄海，畚鍤東南盡會稽。',64,'全唐诗/poet.tang.25000.json','["削平水土窮滄海，畚鍤東南盡會稽。", "山擁翠屏朝玉帛，穴通金闕架雲霓。", "秘文鏤石藏青壁，寶檢封雲化紫泥。", "清廟萬年長血食，始知明德與天齊。"]'),
('c7a7f1b1-759c-4c17-a1e8-9a3f52a2c9c3','新樓詩二十首','李紳','唐','唐诗','tang','','[]','寺深松桂無塵事，地接荒郊帶夕陽。',64,'全唐诗/poet.tang.25000.json','["寺深松桂無塵事，地接荒郊帶夕陽。", "啼鳥歇時山寂寂，野花殘處月蒼蒼。", "絳紗凝焰開金像，清梵銷聲閉竹房。", "丘壠漸平連茂草，九原何處不心傷。"]'),
('b805c64b-bdc3-4b62-9ec7-5a2ae86e30e5','新樓詩二十首','李紳','唐','唐诗','tang','','[]','一峰凝黛當明鏡，十仞喬松倚翠屏。',64,'全唐诗/poet.tang.25000.json','["一峰凝黛當明鏡，十仞喬松倚翠屏。", "秋月滿時侵兔魄，素波搖處動龜形。", "舊深崖谷藏仙島，新結樓臺起佛扃。", "不學大蛟憑水怪，等閑雪雨害生靈。"]'),
('22ea197b-05d4-426a-bc07-6d912ad5b7eb','新樓詩二十首 重臺蓮','李紳','唐','唐诗','tang','','[]','綠荷舒卷涼風曉，紅萼開縈紫菂重。',64,'全唐诗/poet.tang.25000.json','["綠荷舒卷涼風曉，紅萼開縈紫菂重。", "游女漢臯爭笑臉，二妃湘浦竝愁容。", "自含秋露貞姿結，不競春妖冶態穠。", "終恐玉京仙子識，却將歸種碧池峰。"]'),
('0107cd6a-da26-4720-ade8-847bf82f0f9e','新樓詩二十首 橘園','李紳','唐','唐诗','tang','','[]','江城霧歛輕霜早，園橘千株欲變金。',64,'全唐诗/poet.tang.25000.json','["江城霧歛輕霜早，園橘千株欲變金。", "朱實摘時天路近，素英飄處海雲深。", "懼同枳棘愁遷徙，每抱馨香委照臨。", "憐爾結根能自保，不隨寒暑換貞心。"]'),
('96a26e34-d40a-4a5c-8125-ee996b829bf8','新樓詩二十首','李紳','唐','唐诗','tang','','[]','最深城郭在人煙，疑借壺中到梵天。',64,'全唐诗/poet.tang.25000.json','["最深城郭在人煙，疑借壺中到梵天。", "巖樹桂花開月殿，石樓風鐸繞金仙。", "地無塵染多靈草，室鑒真空有定泉。", "應是法宮傳覺路，使無煩惱見青蓮。"]'),
('73a9ca7a-8cd7-4b4f-a185-23fbc95861cc','新樓詩二十首 北樓櫻桃花','李紳','唐','唐诗','tang','','[]','開花占得春光早，雪綴雲裝萬萼輕。',64,'全唐诗/poet.tang.25000.json','["開花占得春光早，雪綴雲裝萬萼輕。", "凝豔拆時初照日，落英頻處乍聞鶯。", "舞空柔弱看無力，帶月蔥蘢似有情。", "多事東風入閨闥，盡飄芳思委江城。"]'),
('9ede1c15-bea9-4cd9-9090-174491168726','新樓詩二十首 城上薔薇','李紳','唐','唐诗','tang','','[]','薔薇繁豔滿城陰，爛熳開紅次第深。',64,'全唐诗/poet.tang.25000.json','["薔薇繁豔滿城陰，爛熳開紅次第深。", "新蘂度香翻宿蝶，密房飄影戲晨禽。", "竇閨織婦慙詩句，南國佳人怨錦衾。", "風月寂寥思往事，暮春空賦白頭吟。"]'),
('a6effb5c-393e-4402-ae6d-036f290bcafd','新樓詩二十首 南庭竹','李紳','唐','唐诗','tang','','[]','東南舊美凌霜操，五月凝陰入坐寒。',64,'全唐诗/poet.tang.25000.json','["東南舊美凌霜操，五月凝陰入坐寒。", "煙惹翠梢含玉露，粉開春籜聳琅玕。", "莫令戲馬童兒見，試引爲龍道士看。", "知爾結根香實在，鳳皇終擬下雲端。"]'),
('17ca506f-2af7-4238-a1cf-cf53c4615633','新樓詩二十首','李紳','唐','唐诗','tang','','[]','石橋峰上栖玄鶴，碧闕巖邊蔭羽人。',64,'全唐诗/poet.tang.25000.json','["石橋峰上栖玄鶴，碧闕巖邊蔭羽人。", "冰葉萬條垂碧實，玉珠千日保青春。", "月中泣露應同浥，澗底侵雲尚有塵。", "徒使茯苓成琥珀，不爲松老化龍鱗。"]'),
('09da42aa-01f7-4b8e-aa4f-7c243e4f1308','新樓詩二十首 海棠','李紳','唐','唐诗','tang','','[]','海邊佳樹生奇彩，知是仙山取得栽。',64,'全唐诗/poet.tang.25000.json','["海邊佳樹生奇彩，知是仙山取得栽。", "瓊蘂籍中聞閬苑，紫芝圖上見蓬萊。", "淺深芳萼通宵換，委積紅英報曉開。", "寄語春園百花道，莫爭顏色泛金杯。"]'),
('3875128a-b5d2-4d34-810b-d54f54f8fb56','新樓詩二十首 水寺','李紳','唐','唐诗','tang','','[]','煙波野寺經過處，水國蒼茫夢想中。',64,'全唐诗/poet.tang.25000.json','["煙波野寺經過處，水國蒼茫夢想中。", "雲散浦間江月迥，日曛洲渚海潮通。", "坐看魚鳥沈浮遠，靜見樓臺上下同。", "聞道化城方便喻，只應從此到龍宮。"]'),
('d56bb87e-68b3-4d69-b06c-c315bd94f4ad','新樓詩二十首 靈汜橋','李紳','唐','唐诗','tang','','[]','靈汜橋邊多感傷，分明湖派繞迴塘。',64,'全唐诗/poet.tang.25000.json','["靈汜橋邊多感傷，分明湖派繞迴塘。", "岸花前後聞幽鳥，湖月高低怨綠楊。", "能促歲陰惟白髮，巧乘風馬是春光。", "何須化鶴歸華表，却數凋零念越鄉。"]'),
('5a933cc1-29fc-4b59-a8fb-9abdfb8ffa63','若耶溪','李紳','唐','唐诗','tang','','[]','嵐光花影繞山陰，山轉花稀到碧潯。',64,'全唐诗/poet.tang.25000.json','["嵐光花影繞山陰，山轉花稀到碧潯。", "傾國美人妖豔遠，鑿山良冶鑄鑪深。", "凌波莫惜臨妝面，瑩鍔當期出匣心。", "應是蛟龍長不去，若耶秋水尚沈沈。"]'),
('37d2efb8-09fe-46c3-a1c6-3af66782500a','登禹廟迴降雪五言二十韻','李紳','唐','唐诗','tang','','[]','金奏雲壇畢，同雲拂雪來。',240,'全唐诗/poet.tang.25000.json','["金奏雲壇畢，同雲拂雪來。", "玉田千畝合，瓊室萬家開。", "湖暗冰封鏡，山明樹變梅。", "裂繒分井陌，連璧混樓臺。", "麻引詩人興，鹽牽謝女才。", "細疑歌響盡，旋作舞腰迴。", "著水鵝毛失，鋪松鶴羽摧。", "半崖雲掩映，當砌月裴回。", "遇物纖能狀，隨方巧若裁。", "玉花全綴萼，珠蚌盡呈胎。", "志士書頻照，鮫人杼正催。", "妬妝凌粉匣，欺酒上瓊杯。", "海使迷奔轍，江濤認暗雷。", "疾飄風作馭，輕集霰爲媒。", "劒客休矜利，農師正念摧。", "瑞彰知有感，靈貺表無災。", "堯歷占新慶，虞階想舊陪。", "粉凝鸞閣下，銀結鳳池隈。", "雞樹花驚笑，龍池絮欲猜。", "勞歌會稽守，遙祝永康哉。"]'),
('2bff9437-ec13-4070-b3d9-a25ffc0713cb','題法華寺五言二十韻','李紳','唐','唐诗','tang','','[]','花界無生地，慈宮有相天。',240,'全唐诗/poet.tang.25000.json','["花界無生地，慈宮有相天。", "化娥騰寶像，留影閟金仙。", "殿湧全身塔，池開半月泉。", "十峰排碧落，雙澗合清漣。", "藥草經行徧，香燈次第燃。", "戒珠高臘護，心印祖僧傳。", "瓶識先羅漢，衣存舊福田。", "幻身觀火宅，昏眼照青蓮。", "住覺超真境，依遊渡法船。", "化城珠百億，靈跡冠三千。", "蕭壁將沈影，梁薪尚綴煙。", "色塵知有數，劫燼豈無年。", "龍噴疑通海，鯨吞想漏川。", "磬疎聞啓梵，鐘息見安禪。", "指喻三車覺，開迷五陰纏。", "教通方便入，心達是非詮。", "見葉千花藏，檀林萬寶篇。", "坐嚴獅子迅，幢飾網珠懸。", "極樂知無礙，分明應有緣。", "還將意功德，留偈法王前。"]'),
('228ff657-9b19-429a-882f-0981abf7e2a2','宿越州天王寺','李紳','唐','唐诗','tang','','[]','海隅布政慙期月，江上霑巾媿萬人。',64,'全唐诗/poet.tang.25000.json','["海隅布政慙期月，江上霑巾媿萬人。", "休按簿書懲黠吏，未齊風俗昧良臣。", "壺冰自潔中無玷，鏡水非求下見鱗。", "清夜佛宮觀色相，却歸前老更前身。"]'),
('5052c292-7fcd-4d89-90f8-f585cba128be','却渡西陵別越中父老','李紳','唐','唐诗','tang','','[]','海潮晚上江風急，津吏篙師語默齊。',64,'全唐诗/poet.tang.25000.json','["海潮晚上江風急，津吏篙師語默齊。", "傾手奉觴看故老，擁流爭拜見孩提。", "慙非杜母臨襄峴，自鄙朱翁別會稽。", "漸舉雲帆煙水闊，杳然鳧雁各東西。"]'),
('1d5b8782-3afa-4a8b-8f97-acea92118d4e','却到浙西','李紳','唐','唐诗','tang','','[]','臨平水竭蒹葭死，里社蕭條旅館秋。',64,'全唐诗/poet.tang.25000.json','["臨平水竭蒹葭死，里社蕭條旅館秋。", "嘗歎晉郊無乞糴，豈忘吳俗共分憂。", "野悲揚目稱嗟食，林極翳桑顧所求。", "苛政尚存猶惕息，老人偷拜擁前舟。"]'),
('e9cb86e5-750a-41e7-a62e-86d40fb8b2f1','蘇州不住遙望武丘報恩兩寺','李紳','唐','唐诗','tang','','[]','秋山古寺東西遠，竹院松門悵望同。',64,'全唐诗/poet.tang.25000.json','["秋山古寺東西遠，竹院松門悵望同。", "幽鳥靜時侵徑月，野煙消處滿林風。", "塔分朱雁餘霞外，剎對金螭落照中。", "官備散寮身却累，往來慙謝二蓮宮。"]'),
('b21568f0-66be-42c4-a0eb-208d9b1d4c0a','迴望館娃故宮','李紳','唐','唐诗','tang','','[]','江雲斷續草綿連，雲隔秋波樹覆煙。',64,'全唐诗/poet.tang.25000.json','["江雲斷續草綿連，雲隔秋波樹覆煙。", "飄雪荻花鋪漲渚，變霜楓葉卷平田。", "雀愁化水喧斜日，鴻怨驚風叫暮天。", "因問館娃何所恨，破吳紅臉尚開蓮。"]'),
('30b4bd17-f4f2-48c0-a9ab-0e3cc0666a82','姑蘇臺雜句','李紳','唐','唐诗','tang','','[]','越王巧破夫差國，來獻黃金重雕刻。',192,'全唐诗/poet.tang.25000.json','["越王巧破夫差國，來獻黃金重雕刻。", "西施醉舞花豔傾，妬月嬌娥恣妖惑。", "姑蘇百尺曉鋪開，樓楣盡化黃金臺。", "歌清管咽歡未極，越師戈甲浮江來。", "伍胥抉目看吳滅，范蠡全身霸西越。", "寂莫千年盡古墟，蕭條兩地皆明月。", "靈巖香徑掩禪扉，秋草荒涼徧落暉。", "江浦迴看鷗鳥沒，碧峰斜見鷺鷥飛。", "如今白髮星星滿，却作閑官不閑散。", "野寺經過懼悔尤，公程迫蹙悲秋館。", "吳鄉越國舊淹留，草樹煙霞昔徧遊。", "雲木夢迴多感歡，不惟惆悵至長洲。"]'),
('33915e18-8c70-4872-9db4-ae6712edff7a','開元寺','李紳','唐','唐诗','tang','','[]','十層花宇真毫相，數仞峰巒閟月扉。',64,'全唐诗/poet.tang.25000.json','["十層花宇真毫相，數仞峰巒閟月扉。", "攢立寶山中色界，散周香海小輪圍。", "坐隅咫尺窺巖壑，窗外高低辨翠微。", "難保爾形終不轉，莫令偷拂六銖衣。"]'),
('78e1c384-29e2-46e9-aff3-0d400ba702b8','臯橋','李紳','唐','唐诗','tang','','[]','伯鸞憔悴甘飄寓，非向囂塵隱姓名。',64,'全唐诗/poet.tang.25000.json','["伯鸞憔悴甘飄寓，非向囂塵隱姓名。", "鴻鵠羽毛終有志，素絲琴瑟自諧聲。", "故橋秋月無家照，古井寒泉見底清。", "猶有餘風未磨滅，至今鄉里重和鳴。"]'),
('de285a0f-2635-4c67-b68c-d0289a39d2d5','真娘墓','李紳','唐','唐诗','tang','','[]','一株繁豔春城盡，雙樹慈門忍草生。',64,'全唐诗/poet.tang.25000.json','["一株繁豔春城盡，雙樹慈門忍草生。", "愁態自隨風燭滅，愛心難逐雨花輕。", "黛消波月空蟾影，歌息梁塵有梵聲。", "還似錢塘蘇小小，祗應迴首是卿卿。"]'),
('9c18ad53-743c-46c3-afd6-761dde1931cd','却望無錫芙蓉湖 一','李紳','唐','唐诗','tang','','[]','水寬山遠煙嵐迥，柳岸縈迴在碧流。',32,'全唐诗/poet.tang.25000.json','["水寬山遠煙嵐迥，柳岸縈迴在碧流。", "清晝不風鳧雁少，却疑初夢鏡湖秋。"]'),
('a08d0bfa-5446-4c35-9f86-6366ae42df4f','却望無錫芙蓉湖 二','李紳','唐','唐诗','tang','','[]','丹橘村邊獨火微，碧流明處雁初飛。',32,'全唐诗/poet.tang.25000.json','["丹橘村邊獨火微，碧流明處雁初飛。", "蕭條落葉垂楊岸，隔水寥寥聞擣衣。"]'),
('26c9b6ee-4ca2-4ecb-b153-4ac1415090a1','却望無錫芙蓉湖 三','李紳','唐','唐诗','tang','','[]','逐波雲影參差遠，背日嵐光隱見深。',32,'全唐诗/poet.tang.25000.json','["逐波雲影參差遠，背日嵐光隱見深。", "猶似望中連海樹，月生湖上是山陰。"]'),
('b38832ba-1187-4a67-8cf1-dcf8bc6337e2','却望無錫芙蓉湖 四','李紳','唐','唐诗','tang','','[]','舊山認得煙嵐近，湖水平鋪碧岫間。',32,'全唐诗/poet.tang.25000.json','["舊山認得煙嵐近，湖水平鋪碧岫間。", "喜見雲泉還悵望，自慙山叟不歸山。"]'),
('b924d86f-d84d-4c54-bec9-25877fc9eafa','却望無錫芙蓉湖 五','李紳','唐','唐诗','tang','','[]','翠崖幽谷分明處，倦鳥歸雲在眼前。',32,'全唐诗/poet.tang.25000.json','["翠崖幽谷分明處，倦鳥歸雲在眼前。", "惆悵白頭爲四老，遠隨塵土去伊川。"]'),
('5a34c470-da71-4a2a-97a9-b998c42bce3d','重到惠山','李紳','唐','唐诗','tang','','[]','碧峰依舊松筠老，重得經過已白頭。',64,'全唐诗/poet.tang.25000.json','["碧峰依舊松筠老，重得經過已白頭。", "俱是海天黃葉信，兩逢霜節菊花秋。", "望中白鶴憐歸翼，行處青苔恨昔遊。", "還向窗間名姓下，數行添記別離愁。"]'),
('fe5d682f-3b84-420e-8efc-822711c9188d','鑒玄影堂','李紳','唐','唐诗','tang','','[]','香燈寂莫網塵中，煩惱身須色界空。',64,'全唐诗/poet.tang.25000.json','["香燈寂莫網塵中，煩惱身須色界空。", "龍鉢已傾無法雨，虎牀猶在有悲風。", "定心池上浮泡沒，招手巖邊夢幻通。", "深夜月明松子落，儼然聽法侍生公。"]'),
('1e3d60b9-9a69-4da7-91c3-0e9664914292','別石泉','李紳','唐','唐诗','tang','','[]','素沙見底空無色，青石潛流暗有聲。',64,'全唐诗/poet.tang.25000.json','["素沙見底空無色，青石潛流暗有聲。", "微渡竹風涵淅瀝，細浮松月透輕明。", "桂凝秋露添靈液，茗折香芽泛玉英。", "應是梵宮連洞府，浴池今化醒泉清。"]'),
('e3d09c65-b21d-4b38-bb61-7a5a13a75bab','別雙溫樹','李紳','唐','唐诗','tang','','[]','翠條盈尺憐孤秀，植向西窗待月軒。',64,'全唐诗/poet.tang.25000.json','["翠條盈尺憐孤秀，植向西窗待月軒。", "輕剪綠絲秋葉暗，密扶纖幹夏陰繁。", "故山手種空懷想，溫室心知不敢言。", "看爾拂雲今得地，莫隨陵谷改深根。"]'),
('6a5f693e-7c8d-4c20-a1c3-bfec8a474e6f','重別西湖','李紳','唐','唐诗','tang','','["\u897f\u6e56"]','浦邊梅葉看凋落，波上雙禽去寂寥。',64,'全唐诗/poet.tang.25000.json','["浦邊梅葉看凋落，波上雙禽去寂寥。", "吹管曲傳花易失，織文機學羽難飄。", "雪欺春早摧芳蕚，隼勵秋深拂翠翹。", "繁豔彩毛無處所，盡成愁歎別谿橋。"]'),
('7d0ce467-1ee7-4612-979a-8c10c174357d','毘陵東山','李紳','唐','唐诗','tang','','[]','昔人別館淹留處，卜築東山學謝家。',64,'全唐诗/poet.tang.25000.json','["昔人別館淹留處，卜築東山學謝家。", "業桂半空摧枳棘，曲池平盡隔煙霞。", "重開漁浦連天月，更種春園滿地花。", "依舊秋風還寂莫，數行衰柳宿啼鴉。"]'),
('4434de0f-4328-4810-b3d7-5a812772183b','建元寺','李紳','唐','唐诗','tang','','[]','江城物候傷心地，遠寺經過禁火辰。',64,'全唐诗/poet.tang.25000.json','["江城物候傷心地，遠寺經過禁火辰。", "芳草壠邊迴首客，野花叢裏斷腸人。", "紫荆繁豔空門晝，紅藥深開古殿春。", "歎息光陰催白髮，莫悲風月獨霑巾。"]'),
('b4cb6229-d6b1-483f-a860-15b5d4fc7208','却到金陵登北固亭','李紳','唐','唐诗','tang','','[]','龍形江影隔雲深，虎勢山光入浪沈。',64,'全唐诗/poet.tang.25000.json','["龍形江影隔雲深，虎勢山光入浪沈。", "潮蹙海風驅萬里，日浮天塹洞千尋。", "衆峰作限橫空碧，一柱中維徹底金。", "還叱檝師看五兩，莫令辜負濟川心。"]'),
('2041eb8c-12af-4d50-a54a-43cc1414f9eb','望鶴林寺','李紳','唐','唐诗','tang','','[]','鶴栖峰下青蓮宇，花發江城世界春。',64,'全唐诗/poet.tang.25000.json','["鶴栖峰下青蓮宇，花發江城世界春。", "紅照日高殷奪火，紫凝霞曙瑩銷塵。", "每思載酒悲前事，欲問題詩想舊身。", "自歎秋風勞物役，白頭拘束一閑人。"]'),
('fc48d76d-a666-4b6b-9d4e-b54ce368198f','宿瓜州','李紳','唐','唐诗','tang','','[]','煙昏水郭津亭晚，迴望金陵若動搖。',64,'全唐诗/poet.tang.25000.json','["煙昏水郭津亭晚，迴望金陵若動搖。", "衝浦迴風翻宿浪，照沙低月歛殘潮。", "柳經寒露看蕭索，人改衰容自寂寥。", "官冷舊諳唯旅館，歲陰輕薄是涼飆。"]'),
('6a03213a-3dfc-41fb-a4d7-7aad9c72a9e5','入揚州郭','李紳','唐','唐诗','tang','','[]','菊芳沙渚殘花少，柳過秋風墜葉疎。',64,'全唐诗/poet.tang.25000.json','["菊芳沙渚殘花少，柳過秋風墜葉疎。", "堤繞門津喧井市，路交村陌混樵漁。", "畏衝生客呼童僕，欲指潮痕問里閭。", "非爲掩身羞白髮，自緣多病喜肩輿。"]'),
('e23faa15-b7c4-4801-9010-de99c8fe405e','宿揚州水館','李紳','唐','唐诗','tang','','[]','舟依淺岸參差合，橋映晴虹上下連。',64,'全唐诗/poet.tang.25000.json','["舟依淺岸參差合，橋映晴虹上下連。", "輕檝過時搖水月，遠燈繁處隔秋煙。", "却思海嶠還悽歎，近涉江濤更凜然。", "閑凭欄干指星漢，尚疑軒蓋在樓船。"]'),
('d8cc2268-11e7-4f3d-83d5-098d9b4fd17e','州中小飲便別牛相','李紳','唐','唐诗','tang','','[]','笙歌罷曲辭賓侶，庭竹移陰就小齋。',64,'全唐诗/poet.tang.25000.json','["笙歌罷曲辭賓侶，庭竹移陰就小齋。", "愁不解顏徒滿酌，病非傷肺爲憂懷。", "耻矜學步貽身患，豈慕醒狂躡禍階。", "從此別離長酩酊，洛陽狂狷任椎埋。"]'),
('7c504af7-9377-4540-a883-a6b2a39b22b2','却過淮陰吊韓信廟','李紳','唐','唐诗','tang','','[]','功高自棄漢元臣，遺廟陰森楚水濱。',64,'全唐诗/poet.tang.25000.json','["功高自棄漢元臣，遺廟陰森楚水濱。", "英主任賢增虎翼，假王徼福犯龍鱗。", "賤能忍恥卑狂少，貴乏懷忠近佞人。", "徒用千金酬一飯，不知明哲重防身。"]'),
('b92fefdd-ddbc-478b-8d8d-8724abe2176d','却入泗口','李紳','唐','唐诗','tang','','[]','洪河一派清淮接，堤草蘆花萬里秋。',64,'全唐诗/poet.tang.25000.json','["洪河一派清淮接，堤草蘆花萬里秋。", "煙樹寂寥分楚澤，海雲明滅滿揚州。", "望深江漢連天遠，思起鄉閭滿眼愁。", "惆悵路岐真此處，夕陽西沒水東流。"]'),
('6bea3434-7a5a-4321-bc84-d20b29627ff6','重入洛陽東門','李紳','唐','唐诗','tang','','[]','商顏重命伊川叟，時事知非入洛人。',64,'全唐诗/poet.tang.25000.json','["商顏重命伊川叟，時事知非入洛人。", "連野碧流通御苑，滿階秋草過天津。", "每慚清秩容衰齒，猶有華簪寄病身。", "驅馬獨歸尋里巷，日斜行處舊紅塵。"]'),
('b5fc2dea-7599-42e4-a849-15a6aac340b6','拜三川守','李紳','唐','唐诗','tang','','[]','恭承寵詔臨伊洛，靜守朝章化比閭。',64,'全唐诗/poet.tang.25000.json','["恭承寵詔臨伊洛，靜守朝章化比閭。", "風變市兒驚偃草，雨晴郊藪謬隨車。", "改張琴瑟移膠柱，止息笙篁辨魯魚。", "唯有從容期一德，使齊文教奉皇居。"]'),
('d30fdec9-9662-4837-8d6f-c781bf7355ae','慶雲見','李紳','唐','唐诗','tang','','[]','禮成中嶽陳金冊，祥報卿雲冠玉峰。',64,'全唐诗/poet.tang.25000.json','["禮成中嶽陳金冊，祥報卿雲冠玉峰。", "輕未透林疑待鳳，細非行雨詎從龍。", "卷風變彩霏微薄，照日籠光映隱重。", "還入九霄成沆瀣，夕嵐生處鶴歸松。"]'),
('a6c2566b-4fa4-4f97-846f-32b01e2b47ad','靈蛇見少林寺','李紳','唐','唐诗','tang','','[]','瑣文結綬靈蛇降，蠖屈螭盤顧視閑。',64,'全唐诗/poet.tang.25000.json','["瑣文結綬靈蛇降，蠖屈螭盤顧視閑。", "鱗蹙翠光抽璀璨，腹連金彩動彎環。", "已應蛻骨風雷後，豈効銜珠草莽間。", "知爾全身護崑閬，不矜揮尾在常山。"]'),
('c19415dc-5337-4280-897b-67965cc47d1b','拜宣武軍節度使','李紳','唐','唐诗','tang','','[]','油幢竝入虎旗開，錦橐從天鳳詔來。',64,'全唐诗/poet.tang.25000.json','["油幢竝入虎旗開，錦橐從天鳳詔來。", "星應魏師新鼓角，地嫌梁苑舊池臺。", "日暉紅斾分如電，人擁青門動若雷。", "伊洛鏡清迴首處，是非紛雜任塵埃。"]'),
('438cac15-96b9-4ced-9867-4045458cc672','到宣武三十韻','李紳','唐','唐诗','tang','','[]','七月趨梁苑，三年謝尹京。',288,'全唐诗/poet.tang.25000.json','["七月趨梁苑，三年謝尹京。", "舊風除物蠹，新律奉師貞。", "龍節雙油重，蛇矛百練明。", "躍魚連後斾，騰虎耀前旌。", "路轉金神竝，川開鐵馬橫。", "擁旄差白羽，分轡引紅纓。", "在浚風煙接，維嵩鞏洛清。", "貫魚奔騎疾，連雁卷行輕。", "煙壘風調角，秋原雨洗兵。", "宿雲看布甲，疎柳見分營。", "鼓徹通宵警，和門候曉晴。", "虎符三校列，魚胄萬夫迎。", "弄馬猨猱健，奔車角觝呈。", "駕肩傍隘道，張幕內連楹。", "森戟承三令，攢戈退一聲。", "及郊知雨過，觀俗辨風行。", "望宋憐思女，遊梁念客卿。", "義夫留感激，公子播英名。", "澤廣豚魚洽，恩宣豈弟生。", "善師忘任智，中略在推誠。", "式宴歌鍾合，陳筵綺繡并。", "戲鼙千卒躍，均酒百壺傾。", "樂與師徒共，歡從井邑盈。", "教通因漸染，人悅尚和平。"]'),
('7e5096a8-29bd-44a3-876c-07b00e132153','江南暮春寄家','李紳','唐','唐诗','tang','','[]','雒陽城見梅迎雪，魚口橋逢雪送梅。',64,'全唐诗/poet.tang.25000.json','["雒陽城見梅迎雪，魚口橋逢雪送梅。", "劒水寺前芳草合，鏡湖亭上野花開。", "江鴻斷續翻雲去，海燕差池拂水回。", "想得心知近寒食，潛聽喜鵲望歸來。"]'),
('22099372-939e-4154-a175-15d5365ac21c','奉酬樂天立秋夕有懷見寄','李紳','唐','唐诗','tang','','[]','深夜星漢靜，秋風初報涼。',180,'全唐诗/poet.tang.25000.json','["深夜星漢靜，秋風初報涼。", "階篁淅瀝響，露葉參差光。", "冰兔半升魄，銅壺微滴長。", "薄帷乍飄卷，襟帶輕搖颺。", "此際昏夢清，斜月滿軒房。", "屣履步前楹，劒戟森在行。", "重城宵正分，號鼓互相望。", "獨坐有所思，夫君鸞鳳章。", "天津落星河，一葦安可航。", "龍泉白玉首，魚服黃金裝。", "報國未知効，惟鵜徒在梁。", "裴回顧戎旃，顥氣生東方。", "衰葉滿欄草，斑毛盈鏡霜。", "羸牛未脫轅，老馬強騰驤。", "吟君白雪唱，慙媿巴人腸。"]'),
('83fe84e1-49aa-4462-836d-d2ac557040a6','山出雲','李紳','唐','唐诗','tang','','[]','杳靄祥雲起，飄颺翠嶺新。',72,'全唐诗/poet.tang.25000.json','["杳靄祥雲起，飄颺翠嶺新。", "縈峰開石秀，吐葉間松春。", "林靜翻空少，山明度嶺頻。", "迴崖時掩鶴，幽澗或隨人。", "姑射朝凝雪，陽臺晚伴神。", "悠悠九霄上，應坐玉京賓。"]'),
('62e08f4c-db9f-4095-b37b-97aa869d46ba','上黨奏慶雲見','李紳','唐','唐诗','tang','','[]','飛龍久馭宇，真氣尚興雲。',72,'全唐诗/poet.tang.25000.json','["飛龍久馭宇，真氣尚興雲。", "五色傳嘉瑞，千齡表聖君。", "從風忽蕭索，依漢更氛氳。", "影徹天初霽，光鮮日未曛。", "表祥近自遠，垂化聚還分。", "寧作無依者，空傳陶令文。"]'),
('287473db-3aca-49b4-a915-409b50eb5f5c','華山慶雲見','李紳','唐','唐诗','tang','','[]','聖主祠名岳，高峰發慶雲。',72,'全唐诗/poet.tang.25000.json','["聖主祠名岳，高峰發慶雲。", "金柯初繚繞，玉葉漸氛氳。", "氣色含珠日，晴光吐翠雰。", "依稀來鶴態，髣髴列仙羣。", "萬樹流光影，千潭寫錦文。", "蒼生欣有望，祥瑞在吾君。"]'),
('6463c613-eef0-4943-a22c-b14715369a3b','欲到西陵寄王行周','李紳','唐','唐诗','tang','','[]','西陵沙岸回流急，船底黏沙去岸遙。',64,'全唐诗/poet.tang.25000.json','["西陵沙岸回流急，船底黏沙去岸遙。", "驛吏遞呼催下纜，棹郎閑立道齊橈。", "猶瞻伍相青山廟，未見雙童白鶴橋。", "欲責舟人無次第，自知貪酒過春潮。"]'),
('fa117c57-cc2f-4647-a501-59a4d5b7065a','華頂','李紳','唐','唐诗','tang','','[]','欲向仙峰煉九丹，獨瞻華頂禮仙壇。',64,'全唐诗/poet.tang.25000.json','["欲向仙峰煉九丹，獨瞻華頂禮仙壇。", "石標琪樹凌空碧，水挂銀河映月寒。", "天外鶴聲隨絳節，洞中雲氣隱琅玕。", "浮生未有從師地，空誦仙經想羽翰。"]'),
('18a2193c-1bd7-4426-b17f-d02a8a4aec1b','鶯鶯歌','李紳','唐','唐诗','tang','','[]','伯勞飛遲燕飛疾，垂楊綻金花笑日。',64,'全唐诗/poet.tang.25000.json','["伯勞飛遲燕飛疾，垂楊綻金花笑日。", "綠窗嬌女字鶯鶯，金雀婭鬟年十七。", "黃姑上天阿母在，寂莫霜姿素蓮質。", "門掩重關蕭寺中，芳草花時不曾出。"]'),
('8e39c3b0-03af-47d7-a98f-32f811025380','贈毛仙翁','李紳','唐','唐诗','tang','','[]','憶昔我祖神仙主，玄元皇帝周柱史。',272,'全唐诗/poet.tang.25000.json','["憶昔我祖神仙主，玄元皇帝周柱史。", "曾師軒黃友堯湯，混迹和光佐周武。", "周之天子無仙氣，成武康昭都瞥爾。", "穆王麤識神仙事，八極輪蹄方逞志。", "鶴髮韜真世不知，日月星辰幾回死。", "金鼎作丹丹化碧，三萬六千神入宅。", "仙兄受術幾千年，已是當時駕鴻客。", "海光悠容天路長，春風玉女開宮院。", "紫筆親教書姓名，玉皇詔刻青金簡。", "桂窗一別三千春，秦妃鏡裏娥眉新。", "忽控香虯天上去，海隅劫石霄花塵。", "一從仙駕辭中土，頑日昏風老無主。", "九州爭奪無時休，八駿垂頭避豺虎。", "我亦玄元千世孫，眼穿望斷蒼煙根。", "花麟白鳳竟冥寞，飛春走月勞神昏。", "百年命促奔馬疾，愁腸盤結心摧崪。", "今朝稽首拜仙兄，願贈丹砂化秋骨。"]'),
('5fbfc98e-586b-4de7-a278-c7032b8d4a74','和晉公三首 一','李紳','唐','唐诗','tang','','[]','鳳儀常欲附，蚊力自知微。',24,'全唐诗/poet.tang.25000.json','["鳳儀常欲附，蚊力自知微。", "願假罇罍末，膺門自此依。"]'),
('2c1bd6aa-d116-4cb6-8f6b-614f655ab4ca','和晉公三首 二','李紳','唐','唐诗','tang','','[]','貂蟬公獨步，鴛鷺我同羣。',24,'全唐诗/poet.tang.25000.json','["貂蟬公獨步，鴛鷺我同羣。", "插羽先飛酒，交鋒便著文。"]'),
('11859a0a-c499-4d49-ba00-718369a74cdc','和晉公三首 三','李紳','唐','唐诗','tang','','[]','窮陰初莽蒼，離思漸氛氳。',24,'全唐诗/poet.tang.25000.json','["窮陰初莽蒼，離思漸氛氳。", "殘雪午橋岸，斜陽伊水濱。"]'),
('04970036-9dd8-4ad6-9193-4ac9731ad381','古風二首 一','李紳','唐','唐诗','tang','','[]','春種一粒粟，秋成萬顆子。',24,'全唐诗/poet.tang.25000.json','["春種一粒粟，秋成萬顆子。", "四海無閑田，農夫猶餓死。"]'),
('ab5ec1e2-084a-486d-bd84-39b320bf4d88','古風二首 二','李紳','唐','唐诗','tang','','[]','鋤禾日當午，汗滴禾下土。',24,'全唐诗/poet.tang.25000.json','["鋤禾日當午，汗滴禾下土。", "誰知盤中餐，粒粒皆辛苦。"]'),
('6936ce03-b918-4092-aa4b-89f09beaff41','柳二首 一','李紳','唐','唐诗','tang','','[]','陶令門前罥接籬，亞夫營裏拂朱旗。',32,'全唐诗/poet.tang.25000.json','["陶令門前罥接籬，亞夫營裏拂朱旗。", "人事推移無舊物，年年春至綠垂絲。"]'),
('99056766-ad1b-45f2-9f00-454f16c68bdd','柳二首 二','李紳','唐','唐诗','tang','','[]','千條垂柳拂金絲，日暖牽風葉學眉。',32,'全唐诗/poet.tang.25000.json','["千條垂柳拂金絲，日暖牽風葉學眉。", "愁見花飛狂不定，還同輕薄五陵兒。"]'),
('09115c75-6775-41e4-aab8-c7466c32a782','題白樂天文集','李紳','唐','唐诗','tang','','[]','寄玉蓮花藏，緘珠貝葉扃。',48,'全唐诗/poet.tang.25000.json','["寄玉蓮花藏，緘珠貝葉扃。", "院閑容客讀，講倦許僧聽。", "部列雕金榜，題存刻石銘。", "永添鴻寶集，莫雜小乘經。"]'),
('e01cf688-7b65-4c35-9fd0-4c57dd137873','答章孝標','李紳','唐','唐诗','tang','','["\u52b1\u5fd7", "\u54f2\u7406"]','假金方用真金鍍，若是真金不鍍金。',32,'全唐诗/poet.tang.25000.json','["假金方用真金鍍，若是真金不鍍金。", "十載長安得一第，何須空腹用高心。"]'),
('fbcb2a21-ed3f-47ab-9efa-d02004995e1e','朱槿花','李紳','唐','唐诗','tang','','[]','瘴煙長暖無霜雪，槿豔繁花滿樹紅。',32,'全唐诗/poet.tang.25000.json','["瘴煙長暖無霜雪，槿豔繁花滿樹紅。", "每歎芳菲四時厭，不知開落有春風。"]'),
('7cd11d7f-d466-4ae5-8bc6-b23c8f676f1e','至潭州聞猿','李紳','唐','唐诗','tang','','[]','昔陪天上三清客，今作端州萬里人。',32,'全唐诗/poet.tang.25000.json','["昔陪天上三清客，今作端州萬里人。", "湘浦更聞猿夜嘯，斷腸無淚可霑巾。"]'),
('1f46559d-6eba-44b3-b5d7-34615f5dbc69','江亭','李紳','唐','唐诗','tang','','[]','瘴江昏霧連天合，欲作家書更斷腸。',32,'全唐诗/poet.tang.25000.json','["瘴江昏霧連天合，欲作家書更斷腸。", "今日病身悲狀候，豈能埋骨向炎荒。"]'),
('3b307387-3bbf-40f9-bcd9-f1da697cd021','紅蕉花','李紳','唐','唐诗','tang','','[]','紅蕉花樣炎方識，瘴水溪邊色最深。',32,'全唐诗/poet.tang.25000.json','["紅蕉花樣炎方識，瘴水溪邊色最深。", "葉滿叢深殷似火，不唯燒眼更燒心。"]'),
('40a39e66-b220-49d7-9311-3f4f25b882cd','憶漢月','李紳','唐','唐诗','tang','','[]','花開花落無時節，春去春來有底憑。',32,'全唐诗/poet.tang.25000.json','["花開花落無時節，春去春來有底憑。", "燕子不藏雷不蟄，燭煙昏霧暗騰騰。"]'),
('28f3b894-be4e-49b4-9e95-fb1550e10750','端州江亭得家書二首 一','李紳','唐','唐诗','tang','','[]','雨中鵲語喧江樹，風處蛛絲颺水潯。',32,'全唐诗/poet.tang.25000.json','["雨中鵲語喧江樹，風處蛛絲颺水潯。", "開拆遠書何事喜，數行家信抵千金。"]'),
('ad36b445-fdba-4b15-b591-d254c1242ff0','端州江亭得家書二首 二','李紳','唐','唐诗','tang','','[]','長安別日春風早，嶺外今來白露秋。',32,'全唐诗/poet.tang.25000.json','["長安別日春風早，嶺外今來白露秋。", "莫道淮南悲木葉，不聞搖落更堪愁。"]'),
('6b8c629a-0626-4350-be18-3e678e49980a','聞猨','李紳','唐','唐诗','tang','','[]','見說三聲巴峽深，此時行者盡沾襟。',32,'全唐诗/poet.tang.25000.json','["見說三聲巴峽深，此時行者盡沾襟。", "端州江口連雲處，始信哀猨傷客心。"]'),
('737947c3-2db1-4e37-a0e4-a47dce0f7230','贈韋金吾','李紳','唐','唐诗','tang','','[]','自報金吾主禁兵，腰間寶劒重橫行。',32,'全唐诗/poet.tang.25000.json','["自報金吾主禁兵，腰間寶劒重橫行。", "接輿也是狂歌客，更就將軍乞一聲。"]'),
('bcb05253-765e-4e34-84e2-23b1d9e39d42','長門怨','李紳','唐','唐诗','tang','','[]','宮殿沈沈曉欲分，昭陽更漏不堪聞。',32,'全唐诗/poet.tang.25000.json','["宮殿沈沈曉欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。"]'),
('11e225c9-4a31-4afd-91b3-fb754ccac5be','龜山寺魚池 一','李紳','唐','唐诗','tang','','[]','汲水添池活白蓮，十千鬐鬣盡生天。',32,'全唐诗/poet.tang.25000.json','["汲水添池活白蓮，十千鬐鬣盡生天。", "凡庸不識慈悲意，自葬江魚入九泉。"]'),
('0a29de75-f584-4375-8b2d-683d73f4105b','龜山寺魚池 二','李紳','唐','唐诗','tang','','[]','剃髮多緣是代耕，好聞人死惡人生。',32,'全唐诗/poet.tang.25000.json','["剃髮多緣是代耕，好聞人死惡人生。", "祇園說法無高下，爾輩何勞尚世情。"]'),
('5ca211d7-18e4-41d4-a754-c72c28e846d6','賦月','李紳','唐','唐诗','tang','','[]','月，光輝，皎潔。',68,'全唐诗/poet.tang.25000.json','["月，光輝，皎潔。", "耀乾坤，靜空闊。", "圓滿中秋，玩爭詩哲。", "玉兔鏑難穿，桂枝人共折。", "萬象照乃無私，瓊臺豈遮君謁。", "抱琴對彈別鶴聲，不得知音聲不切。"]'),
('8a7e5945-d571-4c50-b620-634872d6d893','句','李紳','唐','唐诗','tang','','[]','君詠風月夕，余當童稚年。',24,'全唐诗/poet.tang.25000.json','["君詠風月夕，余當童稚年。", "閑窗讀書罷，偷詠左司篇。"]'),
('e6b1b736-ae47-42ca-8711-99aee01de648','和太原張相公山亭懷古','崔公信','唐','唐诗','tang','','[]','疊石狀崖巘，翠含城上樓。',48,'全唐诗/poet.tang.25000.json','["疊石狀崖巘，翠含城上樓。", "前移廬霍峰，遠帶沅湘流。", "瀟灑主人靜，夤緣芳徑幽。", "清輝在昏旦，豈異東山游。"]'),
('d74a82fe-4c5b-4925-9759-7f619bdb985a','過小妓英英墓','楊虞卿','唐','唐诗','tang','','[]','蕭晨騎馬出皇都，聞說埋冤在路隅。',64,'全唐诗/poet.tang.25000.json','["蕭晨騎馬出皇都，聞說埋冤在路隅。", "別我已爲泉下土，思君猶似掌中珠。", "四弦品柱聲初絕，三尺孤墳草已枯。", "蘭質蕙心何所在，焉知過者是狂夫。"]'),
('ebfb90a0-ccf4-4f10-bfe4-b8b1d253edf6','句','楊虞卿','唐','唐诗','tang','','[]','河勢崑崙遠，山形菡萏秋。',12,'全唐诗/poet.tang.25000.json','["河勢崑崙遠，山形菡萏秋。"]'),
('743b1a3c-e602-4604-a181-317bd81e60d0','和段相公登武擔寺西臺','楊汝士','唐','唐诗','tang','','[]','清淨此道宮，層臺復倚空。',48,'全唐诗/poet.tang.25000.json','["清淨此道宮，層臺復倚空。", "偶時三伏外，列席九霄中。", "平視雲端路，高臨樹杪風。", "自憐榮末座，前日別池籠。"]'),
('06ba6fc0-85d9-4e2f-9701-a69616b9c0cb','和段相公夏登張儀樓','楊汝士','唐','唐诗','tang','','[]','從公城上來，秋近絕纖埃。',48,'全唐诗/poet.tang.25000.json','["從公城上來，秋近絕纖埃。", "樓古秦規在，江分蜀望開。", "遠山標宿雪，末席本寒灰。", "陪賞今爲忝，臨歡敢訴杯。"]'),
('23a7512a-6feb-4ce5-9246-8a7000dc881f','和宗人尚書嗣復祠祭武侯畢題臨淮公舊碑','楊汝士','唐','唐诗','tang','','[]','古栢森然地，修嚴蜀相祠。',72,'全唐诗/poet.tang.25000.json','["古栢森然地，修嚴蜀相祠。", "一過榮異代，三顧盛當時。", "功德流何遠，馨香薦未衰。", "敬名探國志，飾像慰甿思。", "昔謁從征蓋，今聞擁信旗。", "固宜光寵下，有淚刻前碑。"]'),
('5f1e2a4c-b9fa-4837-b407-7b370ed7f086','宴楊僕射新昌里第','楊汝士','唐','唐诗','tang','','[]','隔坐應須賜御屏，盡將仙翰入高冥。',64,'全唐诗/poet.tang.25000.json','["隔坐應須賜御屏，盡將仙翰入高冥。", "文章舊價留鸞掖，桃李新陰在鯉庭。", "再歲生徒陳賀宴，一時良史盡傳馨。", "當時疏廣雖云盛，詎有茲筵醉綠醽。"]'),
('2ac1b81a-77e1-4a83-a417-795af4422cad','建節後偶作','楊汝士','唐','唐诗','tang','','[]','拋却弓刀上砌臺，上方臺榭與雲開。',32,'全唐诗/poet.tang.25000.json','["拋却弓刀上砌臺，上方臺榭與雲開。", "山僧見我衣裳窄，知道新從戰地來。"]'),
('156ed6c6-08da-4e5d-ab37-b067b47642b1','題畫山水','楊汝士','唐','唐诗','tang','','[]','太華峰前是故鄉，路人遙指讀書堂。',32,'全唐诗/poet.tang.25000.json','["太華峰前是故鄉，路人遙指讀書堂。", "如今老大騎官馬，羞向關西道姓楊。"]'),
('5f6f0f66-5d2e-474b-a972-ea662a6a9585','賀筵占贈營妓','楊汝士','唐','唐诗','tang','','[]','郎君得意及青春，蜀國將軍又不貧。',32,'全唐诗/poet.tang.25000.json','["郎君得意及青春，蜀國將軍又不貧。", "一曲高歌紅一疋，兩頭娘子謝夫人。"]'),
('0f9cd35e-e0d8-4311-b011-a66ed6377fe3','句','楊汝士','唐','唐诗','tang','','[]','昔日蘭亭無豔質，此時金谷有高人。',16,'全唐诗/poet.tang.25000.json','["昔日蘭亭無豔質，此時金谷有高人。"]'),
('7646514b-0003-4ef8-9fa1-d1a65d27c700','賦得芙蓉出水','陳至','唐','唐诗','tang','','[]','菡萏迎秋吐，夭搖映水濱。',72,'全唐诗/poet.tang.25000.json','["菡萏迎秋吐，夭搖映水濱。", "劍芒開寶匣，峰影寫蒲津。", "下覆差參荇，高辭苒弱蘋。", "自當巢翠甲，非止戲頳鱗。", "莫以時先後，而言色故新。", "芳香正堪翫，誰報涉江人。"]'),
('3a9eda2a-6490-4b38-90a1-9508fc8563db','薦冰','陳至','唐','唐诗','tang','','[]','凌寒開涸沍，寢廟致精誠。',72,'全唐诗/poet.tang.25000.json','["凌寒開涸沍，寢廟致精誠。", "色靜澄三酒，光寒肅兩楹。", "形鹽非近進，玉豆爲潛英。", "禮自春分展，堅從北陸成。", "藉茅心共結，出鑑水漸明。", "幸得來觀薦，靈臺一小生。"]'),
('c3597fe6-86d6-494f-b3ba-159e512b8aa3','句','陳至','唐','唐诗','tang','','[]','藻井尚寒龍跡在，紅樓初施日光通。',16,'全唐诗/poet.tang.25000.json','["藻井尚寒龍跡在，紅樓初施日光通。"]'),
('95190d25-f10e-420f-9a2a-21bf59569af7','薦冰','趙蕃','唐','唐诗','tang','','[]','仲月開凌室，齋心感聖情。',72,'全唐诗/poet.tang.25000.json','["仲月開凌室，齋心感聖情。", "寒姿分玉坐，皓彩發丹楹。", "積素因風壯，虛空向日明。", "遙涵牕戶冷，近映冕旒清。", "在掌光逾澈，當軒質自輕。", "良辰方可致，由此表精誠。"]'),
('820e1560-e3c9-4601-a27e-eaa404a6f878','老人星','趙蕃','唐','唐诗','tang','','[]','大史占南極，秋分見壽星。',72,'全唐诗/poet.tang.25000.json','["大史占南極，秋分見壽星。", "增輝延寶曆，發曜起祥經。", "灼爍依狼地，昭彰近帝庭。", "高懸方杳杳，孤白乍熒熒。", "應見光新吐，休徵德自形。", "既能符聖柞，從此表遐齡。"]'),
('facf2f2e-e60d-4c8c-ad4a-e2164333ffb1','古意','鮑溶','唐','唐诗','tang','','[]','女蘿寄青松，綠蔓花綿綿。',132,'全唐诗/poet.tang.25000.json','["女蘿寄青松，綠蔓花綿綿。", "三五定君婚，結髮早移天。", "肅肅羔鴈禮，泠泠琴瑟篇。", "恭承采蘩祀，敢効同車賢。", "皎日不留景，良辰如逝川。", "愁心忽移愛，花貌無歸妍。", "翠袖皓珠粉，碧階封綠錢。", "新人易如玉，廢瑟難爲弦。", "寄謝蕣華木，榮君香閣前。", "豈無搖落苦，貴與根蒂連。", "希君舊光景，照妾薄暮年。"]'),
('3e919f17-21ed-4f00-b331-78d9e2f39f36','蕭史圖歌','鮑溶','唐','唐诗','tang','','[]','霜綃數幅八月天，綵龍引鳳堂堂然。',96,'全唐诗/poet.tang.25000.json','["霜綃數幅八月天，綵龍引鳳堂堂然。", "小載蕭僊穆公女，隨仙上歸玉京去。", "仙路迢遙煙幾重，女衣清淨雲三素。", "胡髯毿珊雲髻光，翠蕤皎潔瓊華涼。", "露痕煙跡漬紅貌，疑別秦宮初斷腸。", "此天每在西北上，紫霄洞客曉煙望。"]'),
('8311a574-3e0a-4beb-a09d-7e96cef3b10c','會仙歌','鮑溶','唐','唐诗','tang','','[]','輕輕濛濛，龍言鳳語何從容。',181,'全唐诗/poet.tang.25000.json','["輕輕濛濛，龍言鳳語何從容。", "耳有響兮目無踪，杳杳默默。", "花張錦織，王[母]初自崑崙來。", "茅盈王方平在側，青毛仙鳥銜錦符。", "謹上阿環起居王母書，始知僊事亦多故。", "一隔絳河千歲餘，詳玉字。", "多喜氣，瑤臺明月來墮地。", "冠劒低昂蹈舞頻，禮容盡若君臣事。", "願言小仙藝，姓名許飛瓊。", "洞陰玉磬敲天聲，樂王[母]，一送玉杯長命酒。", "碧花醉，靈揚揚，笑賜二子長生方。", "二子未及伸拜謝，蒼蒼上兮皇皇下。"]'),
('c5469871-f190-4906-9f50-27448cc64872','李夫人歌','鮑溶','唐','唐诗','tang','','[]','璿閨羽帳華燭陳，方士夜降夫人神。',124,'全唐诗/poet.tang.25000.json','["璿閨羽帳華燭陳，方士夜降夫人神。", "葳蕤半露芙蓉色，窈窕將期環珮身。", "麗如三五月，可望難親近。", "嚬黛含犀竟不言，春思秋怨誰能問。", "欲求巧笑如生時，歌塵在空瑟銜絲。", "神來未及夢相見，帝比初亡心更悲。", "愛之欲其生又死，東流萬代無迴水。", "宮漏丁丁夜向晨，煙消霧散愁方士。"]'),
('6591c871-c724-42c1-8038-205060c93540','水殿采菱歌','鮑溶','唐','唐诗','tang','','[]','宮鴉叫赤光，潮聲入宮宮影涼。',62,'全唐诗/poet.tang.25000.json','["宮鴉叫赤光，潮聲入宮宮影涼。", "火華啼露卷橫塘，金堤四合宛柔揚。", "美人荷裙芙蓉妝，柔荑縈霧櫂龍航。", "采蓮一聲歌態長，青絲結眼捕鴛鴦。"]'),
('29e61c7a-6386-478d-a35f-81ea451bce21','周先生畫洞庭歌','鮑溶','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','江南客，水爲鄉，舟爲宅，能以筆鋒知地脈。',100,'全唐诗/poet.tang.25000.json','["江南客，水爲鄉，舟爲宅，能以筆鋒知地脈。", "閑分楚水入丹青，不下此堂臨洞庭。", "水文不浪煙不動，木末稜稜山碧重。", "帝子應哀窈窕雲，客人似得嬋娟夢。", "六月火光衣上生，齋心寂聽潺湲聲。", "林冰搖鏡水拂簟，盡日獨臥秋風清。"]'),
('7f92abb6-a723-45a1-baf0-dc5c4078a0ef','霓裳羽衣歌','鮑溶','唐','唐诗','tang','','[]','玉煙生窗午輕凝，晨華左耀鮮相凌。',162,'全唐诗/poet.tang.25000.json','["玉煙生窗午輕凝，晨華左耀鮮相凌。", "人言天孫機上親手迹，有時怨別無所惜。", "遂令武帝厭雲韶，金針天絲綴飄飄。", "五聲寫出心中見，拊石喧金栢梁殿。", "此衣春日賜何人，秦女腰肢輕若燕。", "香風間旋衆彩隨，聯聯珍珠貫長絲。", "眼前意是三清客，星宿離離遶身白。", "鸞鳳有聲不見身，出宮入徵隨伶人。", "神仙如月只可望，瑤華池頭幾惆悵。", "喬山一閉曲未終，鼎湖秋驚白頭浪。"]'),
('660dc0ac-3a1f-4527-b472-1671fe3bcb3f','寓興','鮑溶','唐','唐诗','tang','','[]','念來若望神，追往如話夢。',48,'全唐诗/poet.tang.25000.json','["念來若望神，追往如話夢。", "夢神不無跡，誰使煩心用。", "魯聖虛泣鱗，楚狂浪歌鳳。", "那言阮家子，更作窮途慟。"]'),
('e10f90db-3c4b-427a-9748-733582b40c60','遊山','鮑溶','唐','唐诗','tang','','[]','白道行深雲，雲高路彌細。',84,'全唐诗/poet.tang.25000.json','["白道行深雲，雲高路彌細。", "時時天上客，遺路人間世。", "煙花最深處，井臼得空刺。", "天寒鶴巢林，石長泉脈閉。", "神化萬靈集，心期一朝契。", "不見金板書，誰知阮家裔。", "終期太古人，問取松柏歲。"]'),
('be59a7d5-933d-4dae-9bca-c1880437d8a7','隋宮','鮑溶','唐','唐诗','tang','','[]','御街多行客，行客悲春風。',36,'全唐诗/poet.tang.25000.json','["御街多行客，行客悲春風。", "楚老幾代人，種田煬帝宮。", "零落池臺勢，高低禾黍中。"]'),
('84badf2a-804e-4def-9704-f8886aa4bfce','懷仙二首 一','鮑溶','唐','唐诗','tang','','[]','崑崙九層臺，臺上宮城峻。',84,'全唐诗/poet.tang.25000.json','["崑崙九層臺，臺上宮城峻。", "西母持地圖，東來獻虞舜。", "虞宮禮成後，迴駕仙風順。", "十二樓上人，笙歌沸天引。", "裴迴扶桑路，白日生離恨。", "青鳥更不來，麻姑斷書信。", "乃知東海水，清淺誰能問。"]'),
('6deba95b-4f6f-4380-8bea-ae266102f917','懷仙二首 二','鮑溶','唐','唐诗','tang','','[]','閬峰綺閣幾千丈，瑤水西流十二城。',32,'全唐诗/poet.tang.25000.json','["閬峰綺閣幾千丈，瑤水西流十二城。", "曾見周靈王太子，碧桃花下自吹笙。"]'),
('1b6346c1-d8ad-4c81-86b3-5b148d34e4dc','懷遠人','鮑溶','唐','唐诗','tang','','[]','遠道在天際，客行如浮雲。',72,'全唐诗/poet.tang.25000.json','["遠道在天際，客行如浮雲。", "浮雲不知歸，似我長望君。", "秋至漢水高，南音何時聞？", "瑤草難遠寄，西風氣氤氳。", "常恐山岳遊，不反鸞鳳羣。", "無厭坐遲人，風雨驚斯文。"]'),
('cdc7299a-dc10-4829-8514-7f6674b06ee7','懷尹真人','鮑溶','唐','唐诗','tang','','[]','萬里疊嶂翠，一心浮雲閑。',72,'全唐诗/poet.tang.25000.json','["萬里疊嶂翠，一心浮雲閑。", "羽人杏花發，倚樹紅瓊顏。", "流水杳冥外，女蘿陰蔭間。", "却思人間世，多恐不可還。", "青鳥飛難遠，春雲晴不閑。", "但恐五雲車，山上復有山。"]'),
('4df53de8-a639-454b-a2fd-e39e95a37593','秋晚銅山道中宿隱者','鮑溶','唐','唐诗','tang','','[]','我鄉山川遙，秋晚空景促。',120,'全唐诗/poet.tang.25000.json','["我鄉山川遙，秋晚空景促。", "天明共雲散，日落依鳥宿。", "主人逃名子，鶴髮臥空谷。", "野言得真風，山貌宜古服。", "喜於無聲地，暫傲羲皇俗。", "秋窗照疎螢，寒犬吠落木。", "朝隱留此處，一點天邊宿。", "今憶見此時，添悲覽止足。", "遲遲清夜晝，幽路出深竹。", "笑謝萬戶侯，余將耻干祿。"]'),
('ae2a0d38-fc11-413d-bb46-823affc9b03f','感懷','鮑溶','唐','唐诗','tang','','[]','宿心不覺遠，事去勞追憶。',48,'全唐诗/poet.tang.25000.json','["宿心不覺遠，事去勞追憶。", "曠古川上懷，東流幾時息。", "門前青山路，眼見歸不得。", "曉夢雲月光，過秋蘭蕙色。"]'),
('80d302e3-24e3-441d-90b3-723633298677','經秦皇墓','鮑溶','唐','唐诗','tang','','[]','左崗青虬盤，右坂白虎踞。',96,'全唐诗/poet.tang.25000.json','["左崗青虬盤，右坂白虎踞。", "誰識此中陵，祖龍藏身處。", "別爲一天地，下入三泉路。", "珠華翔青鳥，玉影耀白兔。", "山河一易姓，萬事隨人去。", "白晝盜開陵，玄冬火焚樹。", "哀哉送死厚，乃爲棄身具。", "死者不復知，回看漢文墓。"]'),
('114a62cf-942e-4515-aa95-8988f3a30e72','將歸舊山留別孟郊','鮑溶','唐','唐诗','tang','','[]','擇木無利刃，羨魚無巧綸。',96,'全唐诗/poet.tang.25000.json','["擇木無利刃，羨魚無巧綸。", "如何不量力，自取中路貧。", "前者不厭耕，一日不離親。", "今來千里外，我心不在身。", "悠悠慈母心，惟願才如人。", "蠶桑能幾許，衣服常著新。", "一飯吐尺絲，誰見此殷勤。", "別君歸耕去，持火燒車輪。"]'),
('2fe1fcd8-245c-4eaa-b9b2-6534588e6788','留辭杜員外式方','鮑溶','唐','唐诗','tang','','[]','東風吹旅懷，鄉夢無夜無。',96,'全唐诗/poet.tang.25000.json','["東風吹旅懷，鄉夢無夜無。", "慚見君子堂，貧思上歸途。", "海岳泛念深，涓塵復何須。", "婆娑不在本，屈曲無弦弧。", "惻惻奉離尊，承歡獨向隅。", "時當鳳來日，孰用雞鳴夫。", "迴首九仙門，皇家在玉壺。", "慙非海人別，淚下不成珠。"]'),
('a0026fed-1541-449e-a24c-088a841ea78d','長城','鮑溶','唐','唐诗','tang','','[]','蒙公虜生人，北築秦氏冤。',108,'全唐诗/poet.tang.25000.json','["蒙公虜生人，北築秦氏冤。", "禍興蕭牆內，萬里防禍根。", "城成六國亡，宮闕啟千門。", "生人半爲土，何用空中原。", "奈何家天下，骨肉尚無恩。", "投沙擁海水，安得久不翻。", "乘高慘人魂，寒日易黃昏。", "枯骨貫朽鐵，砂中如有言。", "萬古驪山下，徒悲野火燔。"]'),
('b48abf4f-005f-4e54-9016-1aec061f38f1','蔡平喜遇河陽馬判官寬話別','鮑溶','唐','唐诗','tang','','[]','從事東軍正四年，相逢且喜偃兵前。',64,'全唐诗/poet.tang.25000.json','["從事東軍正四年，相逢且喜偃兵前。", "看尋狡兔翻三窟，見射妖星落九天。", "江上柳營迴鼓角，河陽花府望神仙。", "秋風蕭颯醉中別，白馬嘶霜鴈叫煙。"]'),
('9f6ddbe7-fd35-4389-9cba-de7e2a142333','寄福州從事殷堯藩','鮑溶','唐','唐诗','tang','','[]','越嶺寒輕物象殊，海城臺閣似蓬壺。',64,'全唐诗/poet.tang.25000.json','["越嶺寒輕物象殊，海城臺閣似蓬壺。", "幾迴入市鮫綃女，終歲啼花山鷓鴣。", "雷令劒龍知去未，虎夷雲鶴亦來無。", "就中靜事冥宵話，何惜雙輪訪病夫。"]'),
('1df60304-17f6-4338-8fe2-6c6c1a8f38dc','壯士行','鮑溶','唐','唐诗','tang','','[]','西方太白高，壯士羞病死。',60,'全唐诗/poet.tang.25000.json','["西方太白高，壯士羞病死。", "心知報恩處，對酒歌易水。", "沙鴻嘷天末，橫劒別妻子。", "蘇武執節歸，班超束書起。", "山河不足重，重在遇知己。"]'),
('a36fbb37-c2b8-4ebb-a2a0-101022b81766','章華宮行','鮑溶','唐','唐诗','tang','','[]','煙渚南鴻呼曉羣，章華宮娥怨行雲。',80,'全唐诗/poet.tang.25000.json','["煙渚南鴻呼曉羣，章華宮娥怨行雲。", "十二巫峯仰天祿，金車何處邀雲宿。", "小腰婑墮三千人，宮衣水碧顏青春。", "豈無一人似神女，忍使黛蛾常不伸。", "黛蛾不伸猶自可，春朝諸處門常鏁。"]'),
('c04dcaa1-533a-4ff3-859f-e51e3e52de38','倚瑟行','鮑溶','唐','唐诗','tang','','[]','金輿傳驚灞滻水，龍旗參天行殿巍。',192,'全唐诗/poet.tang.25000.json','["金輿傳驚灞滻水，龍旗參天行殿巍。", "左文皇帝右慎姬，北面侍臣張釋之。", "因高知處邯鄲道，壽陵已見生秋草。", "萬世何人不此歸，一言出口堪生老。", "高歌倚瑟流清悲，徐樂哀生知爲誰。", "臣驚歡歎不可放，願賜一言釋名妄。", "明珠爲日紅亭亭，水銀爲河玉爲星。", "泉宮一閉秦國喪，牧童弄火驪山上。", "與世無情在速貧，棄尸于野由斯葬。", "生死茫茫不可知，視不一姓君莫悲。", "始皇有訓二世哲，君獨何人至於斯。", "灞陵一代無發毀，儉風本是張廷尉。"]'),
('517b0595-b7cd-41dc-9ee7-b8b4a9a2f076','辭輦行','鮑溶','唐','唐诗','tang','','[]','漢家代久淳風薄，帝重微行極荒樂。',146,'全唐诗/poet.tang.25000.json','["漢家代久淳風薄，帝重微行極荒樂。", "青娥三千奉一人，班女不以色事君。", "朝停玉輦詔同載，三十六宮皆眄睞。", "不驚六馬緩天儀，從容鳴環前致辭。", "君恩如海深難竭，妾命如絲輕易絕。", "願陪阿[母]同小星，敢使太陽齊萬物。", "周末幽王不可宗，妾聞上聖遺休風。", "五更三老待白日，八十一女居深宮。", "願將輦內有餘席，迴賜忠臣妾恩澤。"]'),
('4dfd87b6-3a34-4abd-bfea-b32c46479f15','巢烏行','鮑溶','唐','唐诗','tang','','[]','烏生幾子林蕭條，雄烏求食雌守巢。',112,'全唐诗/poet.tang.25000.json','["烏生幾子林蕭條，雄烏求食雌守巢。", "夜愁風雨巢傾覆，常見一烏巢下宿。", "日長雛飢雄未迴，雌鳥下巢去哀哀。", "野田春盡少遺穀，尋食不得飢飛來。", "黃雀亦引數青雀，雀飛未遠烏驚落。", "既分青雀噉爾雛，爾雛雖長心何如。", "將飛不飛猶未忍，古瑟寫哀哀不盡。"]'),
('b51abdeb-6419-4388-8f9f-ea10bea79d4e','姑蘇宮行','鮑溶','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','姑蘇宮，九層金臺半虛空。',92,'全唐诗/poet.tang.25000.json','["姑蘇宮，九層金臺半虛空。", "雕楹璇題鬬皎潔，中有妖姬似明月。", "西見洞庭秋鏡開，水華百里盤宮來。", "越王采女能水戲，仙舟如龍旌曳翠。", "羽蓋晴翻橘柚香，玉笙夜送芙蓉醉。", "歸帆平靜君無勞，還從下下上高高。"]'),
('4224d002-b9c7-458b-9ee1-3c751c9062a0','悲哉行','鮑溶','唐','唐诗','tang','','[]','促促晨復昏，死生同一源。',108,'全唐诗/poet.tang.25000.json','["促促晨復昏，死生同一源。", "貴年不懼老，賤老傷久存。", "朗朗哭前歌，絳旌引幽魂。", "來爲千金子，去臥百草根。", "黃土塞生路，悲風送回轅。", "金鞍舊良馬，四顧不入門。", "生結千歲念，榮華及百孫。", "黃金買性命，白刃酬一言。", "寧知北山下，松柏侵田園。"]'),
('1cd4d6dd-cfc6-44aa-8af3-30400208b3db','元日早朝行','鮑溶','唐','唐诗','tang','','[]','乾元發生春爲宗，盛德在天斗建東。',80,'全唐诗/poet.tang.25000.json','["乾元發生春爲宗，盛德在天斗建東。", "東方歲星大明宮，南山喜氣搖晴空。", "望雲五等舞萬玉，獻壽一聲出千峯。", "文章垂彩禮樂正，太白下直旌旗紅。", "旌旗不斷春風前，直如朱繩非爾妍。"]'),
('277be1b3-68eb-4327-a97d-eab65070bdbb','秋懷五首 一','鮑溶','唐','唐诗','tang','','[]','促促生有涯，營營意無限。',96,'全唐诗/poet.tang.25000.json','["促促生有涯，營營意無限。", "無限意未申，有涯生已晚。", "恩榮不可恃，天道歸寸管。", "老如影隨人，時若車下坂。", "行者歸期盡，居人心更遠。", "涼風日蕭條，親戚長在眼。", "多憂知無奈，聖賢莫能免。", "客鳥投本枝，生生復深淺。"]'),
('2c6e24d7-0b15-46f6-b790-f9295f1fd0a4','秋懷五首 二','鮑溶','唐','唐诗','tang','','[]','秋曉客迢迢，月清風楚楚。',96,'全唐诗/poet.tang.25000.json','["秋曉客迢迢，月清風楚楚。", "草蟲夜侵我，唧唧牀下語。", "流年白日馳，微願不我與。", "心如繅絲綸，展轉多頭緒。", "憑觴散煩襟，援瑟清夜拊。", "迴感帝子心，空堂有煙雨。", "絲減悲不減，器新聲更古。", "一弦有餘哀，何況二十五。"]'),
('f3a94c12-7462-4174-891e-4e1f01a80821','秋懷五首 三','鮑溶','唐','唐诗','tang','','[]','九月夜如年，幽房勞別夢。',72,'全唐诗/poet.tang.25000.json','["九月夜如年，幽房勞別夢。", "不知別日遠，夜夜猶相送。", "玉牀暗蟲響，錦席寒淚凍。", "明鏡失舊人，空林誤歸鳳。", "新年堪愛惜，錦字亦珍重。", "一念皎皎時，幽襟非所用。"]'),
('a7d8667b-7871-4db3-a8d4-206f4b96ccba','秋懷五首 四','鮑溶','唐','唐诗','tang','','[]','金氣白日來，疎黃滿河關。',84,'全唐诗/poet.tang.25000.json','["金氣白日來，疎黃滿河關。", "平居乏愉悅，況復身險艱。", "一憶故鄉居，一望客人還。", "兩心四海中，誰不傷朱顏。", "雙燕不巢樹，浮萍不出山。", "性命君由天，安得易其間。", "休悲砌蟲苦，此日無人閑。"]'),
('14f984ba-f8fb-4eb4-ae65-ad5b10233ec3','秋懷五首 五','鮑溶','唐','唐诗','tang','','[]','龍荒變露色，燕鴈南爲客。',84,'全唐诗/poet.tang.25000.json','["龍荒變露色，燕鴈南爲客。", "遊子聲影中，涕零念離析。", "四時如車馬，轉此今與昔。", "往歎在空中，存事委幽迹。", "翩翩日歛照，朗朗月繫夕。", "物生春不留，年壯老還迫。", "天機杳何爲，長壽與松柏。"]'),
('43220e26-c586-418c-a20b-102a4536a4a0','秋夜對月懷李正封','鮑溶','唐','唐诗','tang','','[]','援琴悵獨立，高月對秋堂。',108,'全唐诗/poet.tang.25000.json','["援琴悵獨立，高月對秋堂。", "美人遠於月，徒望空景光。", "坐憶執手時，七弦起淒涼。", "平生知音少，君子安可忘。", "客意如夢寐，路岐遍四方。", "日遠迷所之，滿天心暗傷。", "主奉二鯉魚，中含五文章。", "惜無千金荅，愁思盈中腸。", "此夕臨風歎，零露霑衣裳。"]'),
('2ef68ff3-e364-4e3c-b94c-ce03bf079f09','廬山石鏡','鮑溶','唐','唐诗','tang','','["\u5e90\u5c71"]','東巖採薇人，巖際朝見月。',132,'全唐诗/poet.tang.25000.json','["東巖採薇人，巖際朝見月。", "怪墮幽蘿間，非時更澄徹。", "綠蘿就玉兔，再與高鳥歇。", "清光照掌中，始悟石上發。", "誰傳陰陽火，鑄此天地物。", "深影藏半山，虛輪帶凝雪。", "早迴謝公賞，今遇樵夫說。", "白日乘綵霞，翩翩對容髮。", "我圖辨鬼魅，信美留煙闕。", "形神乍相逢，竟夕難取別。", "如其終身照，可化黃金骨。"]'),
('f78fd453-41dc-47cb-adaa-c2c86dde0f7b','與峨眉山道士期盡日不至','鮑溶','唐','唐诗','tang','','[]','傾景安再中，人生有何常。',132,'全唐诗/poet.tang.25000.json','["傾景安再中，人生有何常。", "胡爲少君別，風馭峨眉陽。", "結我千日期，青山故人堂。", "期盡師不至，望雲空燒香。", "顧慙有限身，易老白日光。", "懷君屢驚歎，支體安能強。", "往聞清修籙，未究服食方。", "瑤田有靈芝，眼見不得嘗。", "玉壺貯天地，歲月亦已長。", "若用壺中景，東溟又堪傷。", "寄言赤玉簫，夜夜吹清商。"]'),
('4c0bba7c-2875-48c2-becb-740c1dfb1be6','述德上太原嚴尚書綬','鮑溶','唐','唐诗','tang','','["\u9ec4\u6cb3"]','帝命河嶽神，降靈翼軒轅。',168,'全唐诗/poet.tang.25000.json','["帝命河嶽神，降靈翼軒轅。", "天王委管籥，開閉秦門北。", "頂戴日月光，口宣雨露言。", "甲馬不及汗，天驕自亡魂。", "清塚入內地，黃河窮本源。", "風雲寢氣象，鳥獸翔旗旛。", "軍人歌無胡，長劒倚崑崙。", "終古鞭血地，到今耕稼繁。", "樵客天一畔，何由拜旌軒。", "願請執御臣，爲公動朱轓。", "豈令羣荒外，尚有辜帝恩。", "願陳田舍歌，暫息四坐喧。", "條桑去附枝，薙草絕本根。", "可惜漢公主，哀哀嫁烏孫。"]'),
('ecf449e2-0bb7-44b4-ad5e-42b6dd058af8','山中懷劉修','鮑溶','唐','唐诗','tang','','[]','松老秋意孤，夜涼吟風水。',60,'全唐诗/poet.tang.25000.json','["松老秋意孤，夜涼吟風水。", "山人在遠道，相憶中夜起。", "春光如不至，幽蘭含香死。", "響象離鶴情，念來一相似。", "月斜掩扉臥，又在夢魂裏。"]'),
('b09c9524-dc3b-46b1-9bf9-7b6b39e0cd7a','塞下','鮑溶','唐','唐诗','tang','','[]','北風號薊門，殺氣日夜興。',96,'全唐诗/poet.tang.25000.json','["北風號薊門，殺氣日夜興。", "咸陽三千里，驛馬如飢鷹。", "行子久去鄉，逢山不敢登。", "寒日慘大野，虜雲若飛鵬。", "西北防秋軍，麾幢宿層層。", "匈奴天未喪，戰鼓長登登。", "漢卒馬上老，繁纓空絲繩。", "誠知天所驕，欲罷又不能。"]'),
('c6f99baf-94e0-4cd9-9eaf-acc51eba1e94','送僧南遊','鮑溶','唐','唐诗','tang','','[]','且攀隋宮柳，莫憶江南春。',24,'全唐诗/poet.tang.25000.json','["且攀隋宮柳，莫憶江南春。", "師有懷鄉志，未爲無事人。"]'),
('2a27ee11-0b4f-457e-8e48-0b76e3d97483','行路難','鮑溶','唐','唐诗','tang','','[]','玉堂向夕如無人，絲竹儼然宮商死。',96,'全唐诗/poet.tang.25000.json','["玉堂向夕如無人，絲竹儼然宮商死。", "細人何言入君耳，塵生金罇酒如水。", "君今不念歲蹉跎，鴈天明明涼露多。", "華燈清凝久照夜，綵僮窈窕虛垂蘿。", "入宮見妒君不察，暮入此地生風波。", "此時不樂早休息，女顏易老君如何。"]'),
('a71418ae-c493-429c-a3b1-a56a5a21887d','子規','鮑溶','唐','唐诗','tang','','[]','中林子規啼，云是古蜀帝。',252,'全唐诗/poet.tang.25000.json','["中林子規啼，云是古蜀帝。", "蜀帝胡爲鳥，驚急如罪戾。", "一啼豔陽節，春色亦可替。", "再啼孟夏林，密葉堪委翳。", "三啼涼秋曉，百卉無生意。", "四啼玄冥冬，雲物慘不霽。", "芸黃壯士髮，沾灑妖姬袂。", "悲深寒烏雛，哀掩病鶴翅。", "胡爲託幽命，庇質無完毳。", "戚戚含至冤，卑卑忌羣勢。", "吾聞鳳皇長，羽族皆受制。", "盍分翡翠毛，使學鸚鵡慧。", "敵怨不在弦，一哀尚能繼。", "那令不知休，泣血經世世。", "古風失中和，衰代因鄭衛。", "三歎尚淫哀，向渴嘻流涕。", "如因異聲感，樂與中腸契。", "至教一昏蕪，生人遂危脆。", "古意歎通近，如上青天際。", "荼蓼久已甘，空勞菫葵惠。", "誰聞子規苦，思與正聲計。"]'),
('ba88d0d2-683d-4e0d-904d-98dc638afa1e','秋夜聞鄭山人彈楚妃怨','鮑溶','唐','唐诗','tang','','[]','明月搖落夜，深堂清淨弦。',96,'全唐诗/poet.tang.25000.json','["明月搖落夜，深堂清淨弦。", "中間楚妃奏，十指哀嬋娟。", "寥寥夜含風，蕩蕩意如泉。", "寂寞物無象，依稀語空煙。", "旅人多西望，客鴈難南前。", "由來感神事，豈爲無情傳。", "容華能幾時，不再來者年。", "此夕河漢上，雙星含淒然。"]'),
('d0c3923f-7b3f-432b-bcda-9577735b0a4f','憶舊遊','鮑溶','唐','唐诗','tang','','[]','憶求無何鄉，了在赤谷村。',192,'全唐诗/poet.tang.25000.json','["憶求無何鄉，了在赤谷村。", "仙人居其中，將往問所存。", "日入濛汜宿，石煙抱山門。", "明月久不下，半峯照啼猨。", "堂上白鶴翁，神清心無煩。", "齋心侍席前，跪請長生恩。", "云昔崆峒老，何詞受軒轅。", "從星使變化，任日張乾坤。", "若到舊鄉里，宛如曾討論。", "風移嵓花氣，珠貫金經言。", "涼夜惜易盡，青煙謝晨喧。", "自唯腥膻體，難久留其藩。", "幾世身在夢，百年雲無根。", "悠悠竟何事，愚智相憂冤。", "歎息幾晚寤，蒙師招其魂。", "至今瑤華心，每想清水源。"]'),
('5eb524f1-b078-4e81-a69c-d5683625ad4a','白露','鮑溶','唐','唐诗','tang','','[]','清蟬暫休響，豐露還移色。',84,'全唐诗/poet.tang.25000.json','["清蟬暫休響，豐露還移色。", "金飆爽晨華，玉壺增夜刻。", "已低疎螢燄，稍減哀蟬力。", "迎社促燕心，助風勞鴈翼。", "一悲紈扇情，再想清淺憶。", "高高拜月歸，軋軋挑燈織。", "盈盈玉盤淚，何處無消息。"]'),
('a5a9e67a-1ff0-483c-bed5-852f681f22d6','經隱叟','鮑溶','唐','唐诗','tang','','[]','行蹋門外泉，坐披牀上雲。',72,'全唐诗/poet.tang.25000.json','["行蹋門外泉，坐披牀上雲。", "誰將許由事，萬古留與君。", "虛洞閉金鏁，蠹簡藏鳥文。", "蘿景深的的，蕙風閑薰薰。", "余有世上心，此來未及羣。", "殷勤諱姓名，莫遣樵客聞。"]'),
('f8b20bad-8b04-456f-aa5f-d2ada26890ea','秋暮山中懷李端公益','鮑溶','唐','唐诗','tang','','[]','舊事與日遠，秋花仍舊香。',144,'全唐诗/poet.tang.25000.json','["舊事與日遠，秋花仍舊香。", "前年繡衣客，此節過此堂。", "侍臣不自高，笑脫繡衣裳。", "眠雲有餘態，入鳥不亂行。", "我恐雲嵐色，損君鞍馬光。", "君言此何言，且共覆前觴。", "古人重一笑，買日輕金裝。", "日盡秉燭遊，千年不能忘。", "君言此何言，明日皆異鄉。", "明日非今日，山下道路長。", "一從山下來，天地再炎涼。", "此中會難得，夢君馬玄黃。"]'),
('eb262b65-a14b-4bf4-a32d-7a641244f21b','苦哉遠征人','鮑溶','唐','唐诗','tang','','[]','征人歌古曲，攜手上河梁。',144,'全唐诗/poet.tang.25000.json','["征人歌古曲，攜手上河梁。", "李陵死別處，窅杳玄冥鄉。", "憶昔從此路，連年征鬼方。", "久行迷漢曆，三死氊衣裳。", "百戰身且在，微功信難忘。", "遠承雲臺議，非勢孰敢當。", "落日弔李廣，白首過河陽。", "閑弓失月影，勞劒無龍光。", "去日始束髮，今來髮成霜。", "虛名乃閑事，生見父母鄉。", "掩抑大風歌，裴回少年場。", "誠哉古人言，鳥盡良弓藏。"]'),
('f612bd25-ffaa-4dd5-ae1d-52bba80c95f8','悼豆盧策先輩','鮑溶','唐','唐诗','tang','','[]','喪車出東門，生時馬無力。',144,'全唐诗/poet.tang.25000.json','["喪車出東門，生時馬無力。", "何處入黃泉，嵩高山西北。", "室人萬里外，久望君官職。", "今與牽衣兒，翻號死消息。", "平生江海上，我不空相識。", "遠客迷畏途，孤鴻傷一翼。", "行將雞黍祭，已是烏鳶食。", "勸酒執御郎，行人有哀色。", "先悲三尺土，經歲哭不得。", "眼前雙雙流，故袂安可拭。", "一拜隔千里，生人意何極。", "唯有陽春曲，永播清玉德。"]'),
('cc4a03c5-85e3-4e84-aea2-f4690e699c4e','首夏','鮑溶','唐','唐诗','tang','','[]','昨日青春去，晚峯尚含妍。',36,'全唐诗/poet.tang.25000.json','["昨日青春去，晚峯尚含妍。", "雖留有餘態，脈脈防憂煎。", "幽人惜時節，對此感流年。"]'),
('a82236b8-86a3-4453-8fd4-9a62c209229d','寄天台準公','鮑溶','唐','唐诗','tang','','[]','赤城橋東見月夜，佛壠寺邊行月僧。',32,'全唐诗/poet.tang.25000.json','["赤城橋東見月夜，佛壠寺邊行月僧。", "閑蹋莓苔繞琪樹，海光清淨對心燈。"]'),
('f17cf2fa-a775-4bd7-ad67-cfb1d6ed6628','送僧東遊','鮑溶','唐','唐诗','tang','','[]','風流東晉後，外學入僧家。',48,'全唐诗/poet.tang.25000.json','["風流東晉後，外學入僧家。", "獨唱郢中雪，還遊天際霞。", "雲村共香飯，水月喻秋花。", "景物添新致，前程詎可涯。"]'),
('132b5e93-03cc-44af-a8e9-415f6b37109a','送僧之宣城','鮑溶','唐','唐诗','tang','','[]','昔從謝太守，賓客宛陵城。',36,'全唐诗/poet.tang.25000.json','["昔從謝太守，賓客宛陵城。", "有日持齋戒，高僧識姓名。", "秋風送客去，安得盡忘情。"]'),
('3d0e4cd4-51ef-4292-ad62-647d8205615f','宣城北樓昔從順陽公會於此','鮑溶','唐','唐诗','tang','','[]','詩樓郡城北，窗牖敬亭山。',36,'全唐诗/poet.tang.25000.json','["詩樓郡城北，窗牖敬亭山。", "幾步塵埃隔，終朝世界閑。", "憑師看粉壁，名姓在其間。"]'),
('b0ed9984-2332-4b5e-a4f7-b221d9d42274','東高峯','鮑溶','唐','唐诗','tang','','[]','東亭最高峙，春樹繞山腰。',36,'全唐诗/poet.tang.25000.json','["東亭最高峙，春樹繞山腰。", "畫裏青鸞客，雲中碧玉簫。", "秋風若西望，爲我一長謠。"]'),
('caa01581-d8d6-495d-8ade-96176564cb10','禪定寺經院','鮑溶','唐','唐诗','tang','','[]','蓮華不朽寺，雕刻滿山根。',36,'全唐诗/poet.tang.25000.json','["蓮華不朽寺，雕刻滿山根。", "石汗知天雨，金泥落聖言。", "思量施金客，千古獨消魂。"]'),
('07ff702e-afa1-4580-a6cd-edd5c07cad60','范真傳侍御累有寄因奉酬十首 一','鮑溶','唐','唐诗','tang','','[]','昨日新花紅滿眼，今朝美酒綠留人。',32,'全唐诗/poet.tang.25000.json','["昨日新花紅滿眼，今朝美酒綠留人。", "更宜明月含芳露，憑仗蕭郎夜賞春。"]'),
('0c238a50-2d95-477c-b0b5-b8087c88eb49','范真傳侍御累有寄因奉酬十首 二','鮑溶','唐','唐诗','tang','','[]','白雪翦花朱蠟蒂，折花傳笑惜春人。',32,'全唐诗/poet.tang.25000.json','["白雪翦花朱蠟蒂，折花傳笑惜春人。", "請君白日留明日，一醉春風莫厭頻。"]'),
('5c089bda-7465-4766-92ec-cd8cf8e8187b','范真傳侍御累有寄因奉酬十首 三','鮑溶','唐','唐诗','tang','','[]','雲髻鳳文細，對君歌少年。',24,'全唐诗/poet.tang.25000.json','["雲髻鳳文細，對君歌少年。", "萬金酬一顧，可惜十千錢。"]'),
('f366d3cf-0a4c-45aa-85fe-1a706c78b1d3','范真傳侍御累有寄因奉酬十首 四','鮑溶','唐','唐诗','tang','','[]','玉管傾杯樂，春園鬬草情。',24,'全唐诗/poet.tang.25000.json','["玉管傾杯樂，春園鬬草情。", "野花無限意，處處逐人行。"]'),
('83e0373b-c0ca-429b-a44b-595d9dcd8002','范真傳侍御累有寄因奉酬十首 五','鮑溶','唐','唐诗','tang','','[]','聞道中山酒，一杯千日醒。',24,'全唐诗/poet.tang.25000.json','["聞道中山酒，一杯千日醒。", "黃鶯似傳語，勸酒太叮嚀。"]'),
('5c0c4358-ade3-427e-80b9-e5e3dc0494a6','范真傳侍御累有寄因奉酬十首 六','鮑溶','唐','唐诗','tang','','[]','紅袂歌聲起，因君始得聞。',24,'全唐诗/poet.tang.25000.json','["紅袂歌聲起，因君始得聞。", "黃昏小垂手，與我駐浮雲。"]'),
('aa2291df-41af-40a5-918b-9066d4f99899','范真傳侍御累有寄因奉酬十首 七','鮑溶','唐','唐诗','tang','','[]','相勸醉年華，莫醒春日斜。',24,'全唐诗/poet.tang.25000.json','["相勸醉年華，莫醒春日斜。", "春風宛陵道，萬里晉陽花。"]'),
('ddebd259-6943-4890-ba16-80f2031fc9b9','范真傳侍御累有寄因奉酬十首 八','鮑溶','唐','唐诗','tang','','[]','碧綠草縈堤，紅藍花滿溪。',24,'全唐诗/poet.tang.25000.json','["碧綠草縈堤，紅藍花滿溪。", "願君常踐蹋，莫使暗萋萋。"]'),
('a1a249ad-546d-4e0f-92aa-ad45b5843466','范真傳侍御累有寄因奉酬十首 九','鮑溶','唐','唐诗','tang','','[]','萋萋巫峽雲，楚客莫留恩。',24,'全唐诗/poet.tang.25000.json','["萋萋巫峽雲，楚客莫留恩。", "歲久晉陽道，誰能向太原。"]'),
('2e580af4-c011-4f1a-9682-e745551a0f0c','范真傳侍御累有寄因奉酬十首 十','鮑溶','唐','唐诗','tang','','[]','歲酒勸屠蘇，楚聲山鷓鴣。',24,'全唐诗/poet.tang.25000.json','["歲酒勸屠蘇，楚聲山鷓鴣。", "春風入君意，千日不須臾。"]'),
('d5febff1-aa0d-482a-91ce-09733762f19d','越女詞','鮑溶','唐','唐诗','tang','','[]','越女芙蓉妝，浣紗清淺水。',36,'全唐诗/poet.tang.25000.json','["越女芙蓉妝，浣紗清淺水。", "忽驚春心曉，不敢思君子。", "君子縱我思，寧來浣溪裏。"]'),
('92f5d3ce-1cd6-4322-a0fe-cbea8245f8d2','弄玉詞二首 一','鮑溶','唐','唐诗','tang','','[]','素女結念飛天行，白玉參差鳳皇聲，天仙借女雙翅猛。',36,'全唐诗/poet.tang.25000.json','["素女結念飛天行，白玉參差鳳皇聲，天仙借女雙翅猛。", "五燈繞身生，入煙去無影。"]'),
('43025c0b-38e4-475c-957b-d10cc8062722','弄玉詞二首 二','鮑溶','唐','唐诗','tang','','[]','三清弄玉秦公女，嫁得天上人。',40,'全唐诗/poet.tang.25000.json','["三清弄玉秦公女，嫁得天上人。", "瓊簫碧月喚朱雀，攜手上謁玉晨君。", "夫妻同壽，萬萬青春。"]'),
('cca3e969-8205-47ac-baf8-9bf7c29bf0f6','山行經樵翁','鮑溶','唐','唐诗','tang','','[]','我心勞我身，遠道誰與論。',168,'全唐诗/poet.tang.25000.json','["我心勞我身，遠道誰與論。", "心如木中火，憂至常自燔。", "披訪結恩地，世人輕報恩。", "女無良媒識，知入何人門。", "寒日行深山，路由谷中村。", "田翁樵採熟，男女謳吟喧。", "借問身命謀，上言媿乾坤。", "時清公賦薄，力勤地利繁。", "下念草木年，坐家見重孫。", "舉案饋賓客，糟漿盈陶尊。", "醉閑鹿裘煗，白髮舞軒軒。", "仰羨太古人，余將破行轅。", "遑遑問身事，師友難爲言。", "離歌又行去，落日低寒泉。"]'),
('79835f5d-98af-4613-a14b-f76ade22009e','途中旅思二首 一','鮑溶','唐','唐诗','tang','','[]','喔喔雞鳴曉，蕭蕭馬辭櫪。',120,'全唐诗/poet.tang.25000.json','["喔喔雞鳴曉，蕭蕭馬辭櫪。", "草草名利區，居人少於客。", "生期三萬日，童耄半虛擲。", "修短命半中，憂歡復相敵。", "朝提黃金爵，暮造青松宅。", "來往日相悲，北邙田土窄。", "峨峨西天岳，錦繡明翠壁。", "中有不死鄉，千年無人跡。", "心期周太子，下馬拜虛碧。", "鶴駕如可從，他年執煙策。"]'),
('1a295f66-8827-4ca9-963f-c61448db6244','途中旅思二首 二','鮑溶','唐','唐诗','tang','','[]','星出方問宿，睡眼始朦朧。',96,'全唐诗/poet.tang.25000.json','["星出方問宿，睡眼始朦朧。", "天光見地色，上路車幢幢。", "時物既老大，衆山何枯空。", "青冥見古栢，寥朗聞疎鴻。", "獨步天地間，無因爲君忠。", "白毛尋人憂，生此頭髮中。", "躍馬非壯歲，報恩無高功。", "斯言化爲火，日夜焚深衷。"]'),
('9015befa-d621-4ca8-a533-9412338bb0f3','舊鏡','鮑溶','唐','唐诗','tang','','[]','嬋娟本家鏡，與妾歸君子。',108,'全唐诗/poet.tang.25000.json','["嬋娟本家鏡，與妾歸君子。", "每憶並照時，相逢明月裏。", "春風忽分影，白日難依倚。", "珠粉不結花，玉璫寧輝耳。", "心期不可見，不保長如此。", "華髮一欺人，青銅化爲鬼。", "良人有歸日，肯學妖桃李。", "瑤匣若浮雲，冥冥藏玉水。", "侍兒不遣照，恐學孤鸞死。"]'),
('4d7e4c3f-2852-4e6a-b36b-18e75b7c1b59','宿悟空寺贈僧','鮑溶','唐','唐诗','tang','','[]','勞者謠燭蛾，致身何營營。',84,'全唐诗/poet.tang.25000.json','["勞者謠燭蛾，致身何營營。", "雪山本師在，心地如鏡清。", "往與本師別，人間買浮名。", "朝光畏不久，內火燒人情。", "迷路喜爲遠，宿留化人城。", "前心宛如此，了了隨靜生。", "維持薝蔔花，却與前心行。"]'),
('7bf1c336-f8c6-401f-9172-a4cfd2503001','感興','鮑溶','唐','唐诗','tang','','[]','幽人無近迹，別易會則稀。',108,'全唐诗/poet.tang.25000.json','["幽人無近迹，別易會則稀。", "黃鶴亦姓丁，寥寥何處飛？", "時見海上山，繞雲心依依。", "諒無馭風術，中路愁虛歸。", "童髮慕道心，壯年墮塵機。", "白日不饒我，如今事皆非。", "羣羊化石盡，雙鳧與我違。", "□岳黃金富，軒轅曉霞衣。", "誰令日在眼，容色煙雲微。"]'),
('9c82ce31-f228-41a1-a960-da4e36b95602','秋思','鮑溶','唐','唐诗','tang','','[]','楚客秋更悲，皇皇無聲地。',108,'全唐诗/poet.tang.25000.json','["楚客秋更悲，皇皇無聲地。", "時無無事人，我命與身異。", "良時如飛鳥，回掌成故事。", "蹉跎秋定還，凝冽堅冰至。", "人生不期老，華髮誰能避。", "感此惜壯年，壯年少爲貴。", "我生雖努力，榮途難自致。", "徒爲擊角歌，且慙雕劒字。", "吾師罕言命，感激潛傷思。"]'),
('499c76a4-433c-4dc8-a691-31cfdc21d08c','客途逢鄉人旋別','鮑溶','唐','唐诗','tang','','[]','驚鴻一斷行，天遠會無因。',108,'全唐诗/poet.tang.25000.json','["驚鴻一斷行，天遠會無因。", "無因忽相會，感歎若有神。", "我鄉路三千，百里一主人。", "一宿獨何戀，何況舊鄉鄰。", "牢落歲華晏，相憐客中貧。", "迎霜君衣煖，與我同一身。", "誰在天日下，此生能不勤。", "青萍寄流水，安得長相親。", "明發更遠道，山河重苦辛。"]'),
('73021908-2c50-4e4d-bb43-a3081d3ffd90','隋帝陵下','鮑溶','唐','唐诗','tang','','[]','白露沾衣隋主宮，雲亭月館楚淮東。',64,'全唐诗/poet.tang.25000.json','["白露沾衣隋主宮，雲亭月館楚淮東。", "盤龍樓艦浮冤水，雕錦帆幢使亂風。", "長夜應憐桀何罪，告成合笑禹無功。", "傷心近似驪山路，陵樹無根秋草中。"]'),
('1a1692c9-24e3-447f-a7e8-0e4d50eeedab','洛陽春望','鮑溶','唐','唐诗','tang','','[]','五鳳樓南望洛陽，龍門迴合抱蒼蒼。',64,'全唐诗/poet.tang.25000.json','["五鳳樓南望洛陽，龍門迴合抱蒼蒼。", "受朝前殿雲霞煗，封岳行宮草木香。", "四海爲家知德盛，二京有宅卜年長。", "東人猶憶時巡禮，願覲元和日月光。"]'),
('9bb3ff12-7af7-4f58-b077-0e19a8a9b5ea','始見二毛','鮑溶','唐','唐诗','tang','','[]','玄髮迎憂光色闌，衰華因鏡強相看。',64,'全唐诗/poet.tang.25000.json','["玄髮迎憂光色闌，衰華因鏡強相看。", "百川赴海返潮易，一葉報秋歸樹難。", "初弄藕絲牽欲斷，又驚機素翦仍殘。", "顏生豈是光陰晚，余亦何人不自寬。"]'),
('6110615d-4175-46e6-86f4-45e676904579','巫山懷古','鮑溶','唐','唐诗','tang','','[]','十二峯巒鬬翠微，石煙花霧犯容輝。',64,'全唐诗/poet.tang.25000.json','["十二峯巒鬬翠微，石煙花霧犯容輝。", "青春楚女妒雲老，白日神人入夢稀。", "銀箭暗凋歌夜燭，珠泉頻點舞時衣。", "誰傷宋玉千年後，留得青山辨是非。"]'),
('f4a34239-17b5-4533-a0b5-56220a62bb06','郊天迴','鮑溶','唐','唐诗','tang','','[]','日動蕭煙上泰壇，帝從黃道整和鑾。',64,'全唐诗/poet.tang.25000.json','["日動蕭煙上泰壇，帝從黃道整和鑾。", "風前貔武迴雕仗，雲裏神龍起畫竿。", "金鳥赦書鳴九夜，玉山壽酒舞千官。", "始知報本終朝禮，舊典時巡只自難。"]'),
('739cdb6a-c48b-457b-b4aa-ea2ad0f0040d','溫泉宮','鮑溶','唐','唐诗','tang','','[]','憶昔開元天地平，武皇十月幸華清。',64,'全唐诗/poet.tang.25000.json','["憶昔開元天地平，武皇十月幸華清。", "山蒸陰火雲三素，日落溫泉雞一鳴。", "綵羽鳥仙歌不死，翠霓童妾舞長生。", "仍聞老叟垂黃髮，猶說龍髯縹緲情。"]'),
('97630b82-0b6e-4da0-aac1-0d77efa68e50','寄歸','鮑溶','唐','唐诗','tang','','[]','塞草黃來見鴈稀，隴雲白後少人歸。',64,'全唐诗/poet.tang.25000.json','["塞草黃來見鴈稀，隴雲白後少人歸。", "新絲強入未衰鬢，別淚應沾獨宿衣。", "幾夕精誠拜初月，每秋河漢對空機。", "更看出獵相思苦，不射秋田朝雉飛。"]'),
('018782aa-7f8e-4371-95c6-5f0be2c3e38d','贈遠','鮑溶','唐','唐诗','tang','','[]','辛苦關西車騎官，幾年旌節客河蘭。',64,'全唐诗/poet.tang.25000.json','["辛苦關西車騎官，幾年旌節客河蘭。", "金泥舞虎精神暗，銀縷交龍氣色寒。", "欲和古詩成竇錦，倍悲秋扇損齊紈。", "莫勞鴈足傳書信，願向凌煙閣上看。"]'),
('41d87585-5c8a-4ade-a64b-9406d7599c2c','九日與友人登高','鮑溶','唐','唐诗','tang','','[]','雲木疎黃秋滿川，茱萸風裏一尊前。',64,'全唐诗/poet.tang.25000.json','["雲木疎黃秋滿川，茱萸風裏一尊前。", "幾迴爲客逢佳節，曾見何人再少年。", "霜報征衣冷針指，雁驚幽夢淚嬋娟。", "古來醉樂皆難得，留取窮通付上天。"]'),
('c7aec29c-9275-402e-ac74-7f9e29c3cad4','贈楊煉師','鮑溶','唐','唐诗','tang','','[]','紫煙衣上繡春雲，清隱山書小篆文。',32,'全唐诗/poet.tang.25000.json','["紫煙衣上繡春雲，清隱山書小篆文。", "明月在天將鳳管，夜深吹向玉晨君。"]'),
('f8f5537d-a83f-486a-87b3-51a730016dee','玉清壇','鮑溶','唐','唐诗','tang','','[]','上陽宮裏女，玉色楚人多。',24,'全唐诗/poet.tang.25000.json','["上陽宮裏女，玉色楚人多。", "西信無因得，東遊奈樂何。"]'),
('8eb50ed6-2410-476b-b0f8-a9fea5df2db0','荅客','鮑溶','唐','唐诗','tang','','[]','竹間深路馬驚嘶，獨入蓬門半似迷。',32,'全唐诗/poet.tang.25000.json','["竹間深路馬驚嘶，獨入蓬門半似迷。", "勞問圃人終歲事，桔槔聲裏雨春畦。"]'),
('d1c9f3a0-edb7-4a12-9ff5-b20468b1d296','隋宮','鮑溶','唐','唐诗','tang','','[]','柳塘煙起日西斜，竹浦風迴鴈弄沙。',32,'全唐诗/poet.tang.25000.json','["柳塘煙起日西斜，竹浦風迴鴈弄沙。", "煬帝春遊古城在，壞宮芳草滿人家。"]'),
('5baca491-5a2d-480c-8596-58ec72b1c132','送僧文江','鮑溶','唐','唐诗','tang','','[]','吳王劒池上，禪子石房深。',48,'全唐诗/poet.tang.25000.json','["吳王劒池上，禪子石房深。", "久慕白雲性，忽勞青玉音。", "孤高知勝鶴，清雅似聞琴。", "此韻書珍重，煩師出定吟。"]'),
('048b9758-1195-4367-b6b0-eb285e0e5d0a','古意','鮑溶','唐','唐诗','tang','','[]','重錦化爲泥，翦刀誤人事。',72,'全唐诗/poet.tang.25000.json','["重錦化爲泥，翦刀誤人事。", "夜裁遠道書，翦破相思字。", "妾心不自信，遠道終難寄。", "客心固多疑，肯信非人意。", "萬里不言遠，歸書長相次。", "可即由此書，空房□忌諱。"]'),
('f5f32718-012e-449d-b4f7-877b0e9b7d29','山中冬思二首 一','鮑溶','唐','唐诗','tang','','[]','山深先冬寒，敗葉與林齊。',96,'全唐诗/poet.tang.25000.json','["山深先冬寒，敗葉與林齊。", "門巷非世路，何人念窮棲。", "哀風破山起，夕雪誤鳴雞。", "巢鳥侵旦出，飢猨無聲啼。", "晨興動煙火，開雲伐冰溪。", "老木寒更瘦，陰雲晴亦低。", "我貧自求力，顏色常低迷。", "時思靈臺下，遊子正悽悽。"]'),
('fd3ccca7-b611-4b71-9ab8-6f8ce1ec6889','山中冬思二首 二','鮑溶','唐','唐诗','tang','','[]','雪壯冰亦堅，凍澗如平地。',72,'全唐诗/poet.tang.25000.json','["雪壯冰亦堅，凍澗如平地。", "幽人毛褐煖，笑就糟牀醉。", "喚人空谷應，開火寒猨至。", "拾薪煮秋栗，看鼎書古字。", "忽憶南澗游，衣巾多雲氣。", "露腳尋逸僧，諮量意中事。"]'),
('0da128ae-3425-4b49-9dd3-1c1cd99e9030','讀史','鮑溶','唐','唐诗','tang','','[]','鬼書報秦亡，天地亦云閉。',110,'全唐诗/poet.tang.25000.json','["鬼書報秦亡，天地亦云閉。", "赤龍吟大野，老[母]哭白帝。", "蒼蒼無白日，項氏徒先濟。", "六合已姓劉，鴻門事難制。", "坑降嬴政在，衣錦人望替。", "宿昔見漢兵，龍蛇滿旌棨。", "始矜山可拔，終歎騅不逝。", "區區亞父心，未究天人際。", "蕭張馬無汗，盛業垂千世。"]'),
('d99450f4-44d1-4741-b219-ad93d4c39a9f','冬夜荅客','鮑溶','唐','唐诗','tang','','[]','冬日誠可愛，不如夜漏多。',96,'全唐诗/poet.tang.26000.json','["冬日誠可愛，不如夜漏多。", "幸君霜露裏，車馬犯寒過。", "學耕不逢年，稂莠敗黍禾。", "豈唯親賓散，鳥鼠移巢窠。", "獨見青松心，凌霜庇柔蘿。", "壯日賤若此，留恩意如何。", "因憶古丈夫，一言重山河。", "臨風彈楚劒，爲子奏燕歌。"]'),
('64d15b1f-3020-42cd-88bb-ff93302ca1e3','宿吳興道中苕村','鮑溶','唐','唐诗','tang','','[]','浮客倦長道，秋深夜如年。',120,'全唐诗/poet.tang.26000.json','["浮客倦長道，秋深夜如年。", "久行惜日月，常起雞鳴前。", "夕計今日程，息車在苕川。", "霜中水南寺，金磬泠泠然。", "疇昔此林下，歸心巢頂禪。", "身依寤昏寐，智月生虛圓。", "羈旅違我程，去留難雙全。", "觀身話往事，如夢遊青天。", "明發止賓從，寄聲琴上弦。", "聊書越人意，此曲名思仙。"]'),
('ffb0c135-98b7-4108-98d6-b2b8c7ead862','代楚老酬主人','鮑溶','唐','唐诗','tang','','[]','流水爲我鄉，扁舟爲我宅。',96,'全唐诗/poet.tang.26000.json','["流水爲我鄉，扁舟爲我宅。", "二毛去天遠，幾日人間客。", "曈曈銜山景，渺渺翔雲迹。", "從時無定心，病處不煖席。", "煩君問岐路，爲我生悽慽。", "百年衣食身，未死皆有役。", "曾傷無遺嗣，縱有復何益。", "終古北邙山，樵人賣松栢。"]'),
('94984e1f-fc1c-4929-a9d3-9076382a0f0e','沛中懷古','鮑溶','唐','唐诗','tang','','[]','煙蕪歌風臺，此是赤帝鄉。',96,'全唐诗/poet.tang.26000.json','["煙蕪歌風臺，此是赤帝鄉。", "赤帝今已矣，大風邈淒涼。", "惟昔仗孤劒，十年朝八荒。", "人言生處樂，萬乘巡東方。", "高臺何巍巍，行殿起中央。", "興言萬代事，四坐沾衣裳。", "我爲異代臣，酌水祀先王。", "撫事復懷昔，臨風獨彷徨。"]'),
('ce421446-8c4c-4e75-9c0d-b89b565057c8','夏日華山別韓博士愈','鮑溶','唐','唐诗','tang','','["\u9ec4\u6cb3"]','別地泰華陰，孤亭潼關口。',192,'全唐诗/poet.tang.26000.json','["別地泰華陰，孤亭潼關口。", "夏日可畏時，望山易遲久。", "暫因車馬倦，一逐雲先後。", "碧霞氣爭寒，黃鳥相語誘。", "三峰多異態，逈舉仙人手。", "天晴捧日輪，月夕弄星斗。", "幽疑白帝近，明見黃河走。", "遠心不期來，真境非吾有。", "鳥鳴草木下，日息天地右。", "躑躅因風松，青冥謝仙叟。", "不知無聲淚，中感一顏厚。", "青霄上何階，別劒空朗扣。", "故鄉此關外，身與名相守。", "跡比斷根蓬，憂如長飲酒。", "生離抱多恨，方寸安可受。", "咫尺岐路分，蒼煙蔽回首。"]'),
('96e17da6-0e57-41c3-835a-eda786ed4948','春日言懷','鮑溶','唐','唐诗','tang','','[]','湛湛琴前酒，期自賞青春。',84,'全唐诗/poet.tang.26000.json','["湛湛琴前酒，期自賞青春。", "胡爲緘笑語，深念不思身。", "寂寂花舞多，嚶嚶鳥言頻。", "心悲兄弟遠，願見相似人。", "江界田土卑，競來東作勤。", "歲寒虛盡力，家外無強親。", "杳窅青雲望，無途同苦辛。"]'),
('bdd09b97-63cc-41db-9fc7-71187e05f3c5','題吳徵君巖居','鮑溶','唐','唐诗','tang','','[]','堯澤潤天下，許由心不知。',84,'全唐诗/poet.tang.26000.json','["堯澤潤天下，許由心不知。", "真風存綿緜，常與達者期。", "有道吾不仕，有生吾不欺。", "澹然靈府中，獨見太古時。", "地脈發醴泉，巖根生靈芝。", "天文若通會，星影應離離。", "亭亭傅氏巖，何獨萬古思。"]'),
('b1603aba-6ded-4262-b4de-cb78a2d34bc1','雲溪竹園翁','鮑溶','唐','唐诗','tang','','[]','硠硠雲溪裏，翠竹和雲生。',120,'全唐诗/poet.tang.26000.json','["硠硠雲溪裏，翠竹和雲生。", "古泉積澗深，竦竦如刻成。", "楚客臥雲老，世間無姓名。", "因茲千畝業，以代雙牛耕。", "亂林不可留，寸莖不可輕。", "風煖鬬出地，仰齊故年莖。", "幽室結白茅，密葉羅衆清。", "照水寒澹蕩，對山綠崢嶸。", "蒼松含古貌，秋桂儼白英。", "相看受天風，深夜戛擊聲。"]'),
('b166a3e0-2841-4222-b1dd-a539469ae9e8','竊覽都官李郎中和李舍人益酬張舍人弘靜夏夜寓直思聞雅琴見寄','鮑溶','唐','唐诗','tang','','[]','朝草天子奏，夜語思憂琴。',72,'全唐诗/poet.tang.26000.json','["朝草天子奏，夜語思憂琴。", "因聲含香氣，其韻流水音。", "仙樂朱鳳意，靈芝紫鸞心。", "翻然遠求友，豈獨雙歸林。", "松吹暑中冷，星花池上深。", "倘俾有聲樂，請以絲和金。"]'),
('217ae2f8-826f-4e98-b040-b32f8b4beb89','長安言懷','鮑溶','唐','唐诗','tang','','[]','殷殷生念厚，戚戚勞者多。',120,'全唐诗/poet.tang.26000.json','["殷殷生念厚，戚戚勞者多。", "二時晝夜等，百歲詎幾何。", "日下文翰苑，側身識經過。", "千慮恐一失，翔陽已蹉跎。", "臨觴翦衆憂，靜寄絲桐歌。", "思歸繞十指，五聲不相和。", "暮天還巢翼，明日隕葉柯。", "高謝巖谷人，鹿衣帶女蘿。", "生不去親愛，浮名若風波。", "誰令不及此，親愛隔山河。"]'),
('8015b5a1-8d4b-4ec0-bbe2-87e908811dcb','秋思三首 一','鮑溶','唐','唐诗','tang','','[]','胡風吹鴈翼，遠別無人鄉。',84,'全唐诗/poet.tang.26000.json','["胡風吹鴈翼，遠別無人鄉。", "君近鴈來處，幾迴斷君腸。", "昔奉千日書，撫心怨星霜。", "無書又千日，世路重茫茫。", "燕國有佳麗，蛾眉富春光。", "自然君歸晚，花落君空堂。", "君其若不然，歲晚雙鴛鴦。"]'),
('06378852-e29a-4f92-8658-072008c95de4','秋思三首 二','鮑溶','唐','唐诗','tang','','[]','顧兔蝕殘月，幽光不如星。',84,'全唐诗/poet.tang.26000.json','["顧兔蝕殘月，幽光不如星。", "女兒晚事夫，顏色同秋螢。", "秋日邊馬思，武夫不遑寧。", "燕歌易水怨，劒舞蛟龍腥。", "風折連枝樹，水翻無蔕萍。", "立身多門戶，何必燕山銘。", "生世不如鳥，雙雙比翼翎。"]'),
('700b3179-7f9f-4ebd-8d54-d110e2ed95c7','秋思三首 三','鮑溶','唐','唐诗','tang','','[]','季秋天地閑，萬物生意足。',84,'全唐诗/poet.tang.26000.json','["季秋天地閑，萬物生意足。", "我憂長於生，安得及草木。", "試從古人願，致酒歌秉燭。", "燕趙皆世人，詎能長似玉。", "俯憐老期近，仰視日車速。", "蕭颯御風君，魂夢願相逐。", "百年夜銷半，端爲垂纓束。"]'),
('070090be-0d2a-4832-83a7-5f1be7dad755','歸鴈','鮑溶','唐','唐诗','tang','','[]','南國春早煖，渚蒲正月生。',132,'全唐诗/poet.tang.26000.json','["南國春早煖，渚蒲正月生。", "東風吹鴈心，上下和樂聲。", "繞水半空去，拂雲偕相迎。", "如防失羣怨，預有侵夜驚。", "渺邈天外影，支離塞中鶯。", "自顧摧頹羽，偏感南北情。", "乍甘煙霧勞，不顧龍沙榮。", "雖樂未歸意，終不能自鳴。", "喜去春月滿，歸來秋風清。", "啼餘碧窗夢，望斷陰山行。", "不及瑤𥯅燕，寄身金宮楹。"]'),
('3cc8b077-25e6-43f8-a503-894a8802a87c','悲湘靈','鮑溶','唐','唐诗','tang','','[]','山上涼雲收，日斜川風止。',132,'全唐诗/poet.tang.26000.json','["山上涼雲收，日斜川風止。", "娥皇五十弦，秋深漢江水。", "初因無象外，牽感百憂裏。", "霜露結瑤華，煙波勞玉指。", "將隨落葉去，又繞疎蘋起。", "哀響雲合來，清餘桐半死。", "女顏萬歲後，豈復嬋娟子。", "不道神無悲，那能久如此。", "魂魄無不之，九山徒相似。", "沒沒竟不從，唯傷遠人耳。", "斑斑淚篁下，恐有學瑟鬼。"]'),
('60756730-3848-49de-a9fb-a55b7785e89f','聞蟬','鮑溶','唐','唐诗','tang','','[]','高蟬旦夕唳，景物浮涼氣。',84,'全唐诗/poet.tang.26000.json','["高蟬旦夕唳，景物浮涼氣。", "木葉漸驚年，錦字因絡緯。", "稍斷當窗夢，更悽臨水意。", "清香筍蒂風，曉露蓮花淚。", "餘引未全歇，凝悲尋迥至。", "星井欲望河，月扇看藏笥。", "誰念因聲感，放歌寫人事。"]'),
('25e1e4f6-728f-44ac-a428-2b4c528a0709','懷幽期','鮑溶','唐','唐诗','tang','','[]','清砧擊霜天外發，楚僧期到石上月。',64,'全唐诗/poet.tang.26000.json','["清砧擊霜天外發，楚僧期到石上月。", "寒峯深虛獨遶盡，夜水淺急不可越。", "窅機冥智難思量，無盡性月如空王。", "眼界行處不著我，天花下來惟有香。"]'),
('de48135c-2fb4-4922-9961-24d5d74c73f5','思琴高','鮑溶','唐','唐诗','tang','','[]','琴仙人，得仙去。',56,'全唐诗/poet.tang.26000.json','["琴仙人，得仙去。", "萬古釣龍空有處，我持曲鉤思白魚。", "仙溪綠盡含空虛，天鈞蹤跡無遺餘。", "燒香寄影在巖樹，東禮海日雞鳴初。"]'),
('a16583ef-9846-4dea-b231-8d6d5f0ce719','得儲道士書','鮑溶','唐','唐诗','tang','','[]','嬋娟春盡暮心秋，鄰里同年半白頭。',32,'全唐诗/poet.tang.26000.json','["嬋娟春盡暮心秋，鄰里同年半白頭。", "爲問蓬萊近消息，海波平靜好東遊。"]'),
('5a45b3fa-7b2e-49ca-9688-e6453d369971','寒夜吟','鮑溶','唐','唐诗','tang','','[]','九衢金吾夜行行，上宮玉漏遙分明。',96,'全唐诗/poet.tang.26000.json','["九衢金吾夜行行，上宮玉漏遙分明。", "霜飆乘陰掃地起，旅鴻迷雪遶枕聲。", "遠人歸夢既不成，留家惜夜歡心發。", "羅幕畫堂深皎潔，蘭煙對酒客幾人。", "獸火揚光二三月，細腰楚姬絲竹間。", "白紵長袖歌閑閑，豈識苦寒損朱顏。"]'),
('8b468e53-fb77-4fb6-a080-af4e434c56c2','採蓮曲二首 一','鮑溶','唐','唐诗','tang','','[]','弄舟朅來南塘水，荷葉映身摘蓮子。',48,'全唐诗/poet.tang.26000.json','["弄舟朅來南塘水，荷葉映身摘蓮子。", "暑衣清淨鴛鴦喜，作浪舞花驚不起。", "殷勤護惜纖纖指，水菱初熟多新刺。"]'),
('1cfa1be4-5878-491a-9184-2e763b81e0dd','採蓮曲二首 二','鮑溶','唐','唐诗','tang','','[]','採蓮朅來水無風，蓮潭如鑑松如龍。',32,'全唐诗/poet.tang.26000.json','["採蓮朅來水無風，蓮潭如鑑松如龍。", "夏衫短袖交斜紅，豔歌笑鬬新芙蓉。"]'),
('3fb0c4cf-8ed3-4550-a1d1-3c97933cbecc','玉山謠奉送王隱者','鮑溶','唐','唐诗','tang','','[]','鳳皇城南玉山高，石腳聳立爭雄豪。',144,'全唐诗/poet.tang.26000.json','["鳳皇城南玉山高，石腳聳立爭雄豪。", "攢峯胎玉氣色潤，百泉透雲流不盡。", "萬古分明對眼開，五煙窈窕呈祥近。", "有客師事金身仙，用金買得山中田。", "閑開玉水灌芝草，靜醉天酒松間眠。", "心期南溟萬里外，出山幾遇光陰改。", "水玉丁東不可聞，冰華皎潔應如待。", "秋風引吾歌去來，玉山綵翠遙相催。", "殷勤千樹玉山頂，碧洞寥寥寒錦苔。"]'),
('e2a44cb0-517b-4df3-8b37-93918d564fa9','岐路','鮑溶','唐','唐诗','tang','','[]','北風送微寒，徒侶勤遠征。',120,'全唐诗/poet.tang.26000.json','["北風送微寒，徒侶勤遠征。", "憂人席不煖，殘月馬上明。", "飄飄岐路間，長見日初生。", "重嶂曉色淺，疎猨寒啼清。", "人間多岐路，常恐終身行。", "回見四方人，車輪無留聲。", "空谷亦堪隱，下田非嬾耕。", "古人有遺訓，飽食非親榮。", "我生禮義鄉，少小見太平。", "聖賢猶羈旅，況復非其名。"]'),
('52096ef9-671a-4ef5-833e-d8a1bee9d476','隴頭水','鮑溶','唐','唐诗','tang','','[]','隴頭水，千古不堪聞。',34,'全唐诗/poet.tang.26000.json','["隴頭水，千古不堪聞。", "生歸蘇屬國，死別李將軍。", "細響風凋草，清哀雁落雲。"]'),
('a2450017-58c1-4504-bc6b-6d471c06890e','沙上月','鮑溶','唐','唐诗','tang','','[]','黃昏潮落南沙明，月光涵沙秋雪清。',32,'全唐诗/poet.tang.26000.json','["黃昏潮落南沙明，月光涵沙秋雪清。", "水文不上煙不蕩，平平玉田冷空曠。"]'),
('05b286e2-832c-4d1f-a8cb-2574106041cd','贈李黯將軍','鮑溶','唐','唐诗','tang','','[]','細柳連營石壍牢，平安狼火赤星高。',66,'全唐诗/poet.tang.26000.json','["細柳連營石壍牢，平安狼火赤星高。", "巖雲入角雕龍爽，寒日搖旗畫獸豪。", "搜伏雄兒欺魍魎，射聲遊騎怯分毫。", "聖人唯有河[湟]恨，寰海無虞在一勞。"]'),
('2c66b7a4-bfa9-47a1-a650-0a79ba8effab','人日陪宣州范中丞傳正與范侍御宴','鮑溶','唐','唐诗','tang','','[]','人日春風綻早梅，謝家兄弟看花來。',64,'全唐诗/poet.tang.26000.json','["人日春風綻早梅，謝家兄弟看花來。", "吳姬對客歌千曲，秦女留人酒百杯。", "絲柳向空輕婉轉，玉山看日漸裴回。", "流光易去歡難得，莫厭頻頻上此臺。"]'),
('9470f560-4dd8-49f4-bd8d-43f70485a5bb','古鑑','鮑溶','唐','唐诗','tang','','[]','古鑑含靈氣象和，蛟龍盤鼻護金波。',64,'全唐诗/poet.tang.26000.json','["古鑑含靈氣象和，蛟龍盤鼻護金波。", "隱山道士未曾識，負局先生不敢磨。", "曾向春窗分綽約，誤迴秋水照蹉跎。", "世間縱有應難比，十斛明珠酬未多。"]'),
('b5eef8f7-e63c-4ba9-9f0b-896f85dbb2fa','送王煉師','鮑溶','唐','唐诗','tang','','[]','聖母祠堂藥樹香，邑君承命薦椒漿。',64,'全唐诗/poet.tang.26000.json','["聖母祠堂藥樹香，邑君承命薦椒漿。", "風雲大感精神地，雷雨頻過父母鄉。", "盡日一川侵草綠，迴車二麥遶山黃。", "野人久會神仙事，敢奏歌鍾慶萬箱。"]'),
('de5778f4-dfe8-40b6-bfc3-1f2fe19b3e9e','寄張十七校書李仁行秀才','鮑溶','唐','唐诗','tang','','[]','去年八月此佳辰，池上閑閑四五人。',64,'全唐诗/poet.tang.26000.json','["去年八月此佳辰，池上閑閑四五人。", "久行月影愁迷夢，誤入華光笑認春。", "一與清風上芸閣，再期秋雨過龍津。", "今年此日何由見，蓬戶蕭條對病身。"]'),
('f7390b5b-8957-4923-992d-e6bdff4bba80','送王損之秀才赴舉','鮑溶','唐','唐诗','tang','','[]','青門珮蘭客，淮水誓風流。',48,'全唐诗/poet.tang.26000.json','["青門珮蘭客，淮水誓風流。", "名在鄉書貢，心期月殿遊。", "平沙大河急，細雨二陵秋。", "感此添離恨，年光不少留。"]'),
('c1f7d8aa-6128-4e64-bbcb-1ef58da7cdff','舊鏡','鮑溶','唐','唐诗','tang','','[]','團團銅鏡似潭水，心愛玉顏私自親。',32,'全唐诗/poet.tang.26000.json','["團團銅鏡似潭水，心愛玉顏私自親。", "一經離別少年改，難與清光相見新。"]'),
('de3e4887-952d-462d-a05a-7541926ed3d8','憶郊天','鮑溶','唐','唐诗','tang','','[]','憶向郊壇望武皇，九軍旗帳下南方。',64,'全唐诗/poet.tang.26000.json','["憶向郊壇望武皇，九軍旗帳下南方。", "六龍日馭天行健，神母呈圖地道光。", "濃煖氣中生曆草，是非煙裏愛瑤漿。", "至今滿耳簫韶曲，徒羨瑤池舞鳳皇。"]'),
('7d579d63-13e0-471b-a4ad-ff8d47b84bee','期盡','鮑溶','唐','唐诗','tang','','[]','魚鏁生衣門不開，玉筐金月共塵埃。',32,'全唐诗/poet.tang.26000.json','["魚鏁生衣門不開，玉筐金月共塵埃。", "青山石婦千年望，雷雨曾知來不來。"]'),
('5d6e7f76-0cb7-4bb0-8ed7-a0adff51bdd4','晚山蟬','鮑溶','唐','唐诗','tang','','[]','山蟬秋晚妨人語，客子驚心馬亦嘶。',48,'全唐诗/poet.tang.26000.json','["山蟬秋晚妨人語，客子驚心馬亦嘶。", "能閱幾時新碧樹，不知何日寂金閨。", "若逢海月明千里，莫忘何郎寄一題。"]'),
('f73c7c09-7767-4fb4-8491-308c9bce92ce','秋暮送裴垍員外刺婺州','鮑溶','唐','唐诗','tang','','[]','婺女星邊氣不秋，金華山水似瀛州。',32,'全唐诗/poet.tang.26000.json','["婺女星邊氣不秋，金華山水似瀛州。", "含香太守心清淨，去與神仙日日遊。"]'),
('87760030-da65-4d3c-be27-012ac8e0ef12','寄薛膺昆季','鮑溶','唐','唐诗','tang','','[]','楚山清洛兩無期，夢裏春風玉樹枝。',32,'全唐诗/poet.tang.26000.json','["楚山清洛兩無期，夢裏春風玉樹枝。", "何況芙蓉樓上客，海門江月亦相思。"]'),
('cdb16d45-d6ad-403b-897c-a2aa165d84fa','楊真人籙中像','鮑溶','唐','唐诗','tang','','[]','畫中留得清虛質，人世難逢白鶴身。',32,'全唐诗/poet.tang.26000.json','["畫中留得清虛質，人世難逢白鶴身。", "應見茅盈哀老弟，爲持金籙救生人。"]'),
('6568b2a6-3b1d-4343-b22e-3a63f6f752c8','寄盧給事汀吳員外丹','鮑溶','唐','唐诗','tang','','[]','姓丁黃鶴遼東去，客倩仙翁海上人。',32,'全唐诗/poet.tang.26000.json','["姓丁黃鶴遼東去，客倩仙翁海上人。", "聞道姓名多改變，只今偕是聖朝臣。"]'),
('11a58ce2-72db-4f34-b361-57e18d82c378','懷王直秀才','鮑溶','唐','唐诗','tang','','[]','鄉無竹圃爲三徑，貧寄鄰家已二年。',32,'全唐诗/poet.tang.26000.json','["鄉無竹圃爲三徑，貧寄鄰家已二年。", "惟有素風身未墜，世間開口不言錢。"]'),
('4c339a14-415c-4bfa-ba26-7e849a670567','贈真公影堂','鮑溶','唐','唐诗','tang','','[]','舊房西壁畫支公，昨暮今晨色不同。',32,'全唐诗/poet.tang.26000.json','["舊房西壁畫支公，昨暮今晨色不同。", "遠客閑心無處所，獨添香火望虛空。"]'),
('38ea3a1e-c591-42a7-a3ee-dddfcb6505c8','贈僧戒休','鮑溶','唐','唐诗','tang','','[]','風行露宿不知貧，明月爲心又是身。',32,'全唐诗/poet.tang.26000.json','["風行露宿不知貧，明月爲心又是身。", "欲問月中無我法，無人無我問何人。"]'),
('06d60bb8-709d-42e9-a29f-edfa99e91a2d','秋夜懷紫閣峯僧','鮑溶','唐','唐诗','tang','','[]','滿山雨色應難見，隔澗經聲又不聞。',32,'全唐诗/poet.tang.26000.json','["滿山雨色應難見，隔澗經聲又不聞。", "紫閣夜深多入定，石臺誰爲掃秋雲。"]'),
('a672d182-be2c-4a05-810f-b42590988adf','酬江公見寄','鮑溶','唐','唐诗','tang','','[]','曾荅鴈門偈，爲憐同社人。',24,'全唐诗/poet.tang.26000.json','["曾荅鴈門偈，爲憐同社人。", "多慙惠休句，偕得此陽春。"]'),
('fdf5f232-7537-4e7d-bfa5-aee4f7671b18','送羅侍御歸西臺','鮑溶','唐','唐诗','tang','','[]','歸臺新柱史，辭府舊英髦。',48,'全唐诗/poet.tang.26000.json','["歸臺新柱史，辭府舊英髦。", "勸酒蓮幕貴，望塵驄馬高。", "詩情分繡段，劒彩拂霜毫。", "此舉關風化，誰云別恨勞。"]'),
('01fc2844-e7ca-483e-9287-5f491fe2263f','宿水亭','鮑溶','唐','唐诗','tang','','[]','雕楹綵檻壓通波，魚鱗碧幕銜曲玉。',32,'全唐诗/poet.tang.26000.json','["雕楹綵檻壓通波，魚鱗碧幕銜曲玉。", "夜深星月伴芙蓉，如在廣寒宮裏宿。"]'),
('e4d10f3d-adfa-4e32-b318-8c94e63f877c','寄峨嵋山楊煉師','鮑溶','唐','唐诗','tang','','["\u5ce8\u7709\u5c71"]','道士夜誦蘂珠經，白鶴下遶香煙聽。',32,'全唐诗/poet.tang.26000.json','["道士夜誦蘂珠經，白鶴下遶香煙聽。", "夜移經盡人上鶴，仙風吹入秋冥冥。"]'),
('aa282553-4e94-4f98-9239-acffb8eb0a51','寄海陵韓長官','鮑溶','唐','唐诗','tang','','[]','吏散重門印不開，玉琴招鶴舞裴回。',32,'全唐诗/poet.tang.26000.json','["吏散重門印不開，玉琴招鶴舞裴回。", "野人爲此多東望，雲雨仍從海上來。"]'),
('8c11d93a-ffc0-4a5b-8998-a57cbb122cc1','淮南臥病感路羣侍御訪別','鮑溶','唐','唐诗','tang','','[]','西臺御史重難言，落木疎籬遶病魂。',32,'全唐诗/poet.tang.26000.json','["西臺御史重難言，落木疎籬遶病魂。", "一望青雲感驄馬，欵行黃草出柴門。"]'),
('1ce50fc2-2b72-4f27-9caa-6c4ef13b9856','題禪定寺集公竹院','鮑溶','唐','唐诗','tang','','[]','公門得休靜，禪寺少逢迎。',36,'全唐诗/poet.tang.26000.json','["公門得休靜，禪寺少逢迎。", "任客看花醉，隨僧入竹行。", "歸時常犯夜，雲裏有經聲。"]'),
('3a56ae0a-0370-4797-9ec3-e5d61af5780d','風箏','鮑溶','唐','唐诗','tang','','[]','何響與天通，瑤箏挂望中。',72,'全唐诗/poet.tang.26000.json','["何響與天通，瑤箏挂望中。", "彩弦非觸指，錦瑟忽聞風。", "鴈柱虛連勢，鸞歌且墜空。", "夜和霜擊磬，晴引鳳歸桐。", "幽咽誰生怨，清泠自匪躬。", "秦姬收寶匣，搔首不成功。"]'),
('b03d28d8-db35-4ba8-b14e-aeeb4ee040a2','經舊遊','鮑溶','唐','唐诗','tang','','[]','遊魚懷故池，倦鳥懷故窠。',108,'全唐诗/poet.tang.26000.json','["遊魚懷故池，倦鳥懷故窠。", "故山繫歸念，行坐青巍峨。", "羸馬經舊途，此鄉喜重過。", "居人無故老，倍感別日多。", "但見野中墳，纍纍如青螺。", "涼風日搖落，桑下松婆娑。", "歎息追古人，臨風傷逝波。", "古人無不死，歎息欲如何。", "朅來遂遠心，默默存天和。"]'),
('a5c3a522-891d-47f2-934a-1396a3a99bdc','過薛舍人舊隱','鮑溶','唐','唐诗','tang','','[]','寢門來哭夜，此月小祥初。',48,'全唐诗/poet.tang.26000.json','["寢門來哭夜，此月小祥初。", "風意猶憶瑟，螢光乍近書。", "牆蒿藏宿鳥，池月上鉤魚。", "徒引相思淚，涓涓東逝餘。"]'),
('ddff19c3-95ce-4590-a612-ddf958a308f6','山居','鮑溶','唐','唐诗','tang','','[]','窈窕垂澗蘿，蒙茸黃葛花。',24,'全唐诗/poet.tang.26000.json','["窈窕垂澗蘿，蒙茸黃葛花。", "鴛鴦憐碧水，照影舞金沙。"]'),
('3db0baa7-cb74-422c-b606-17dadb3a97f4','暮秋與裴居晦宴因見採菊花之作','鮑溶','唐','唐诗','tang','','[]','菊花低色過重陽，似憶王孫白玉觴。',32,'全唐诗/poet.tang.26000.json','["菊花低色過重陽，似憶王孫白玉觴。", "今日王孫好收採，高天已下兩迴霜。"]'),
('e0959e8e-9389-41a7-96a3-70158ff4cc6e','望麻姑山','鮑溶','唐','唐诗','tang','','[]','幽人往往懷麻姑，浮世悠悠仙景殊。',32,'全唐诗/poet.tang.26000.json','["幽人往往懷麻姑，浮世悠悠仙景殊。", "自從青鳥不堪使，更得蓬萊消息無。"]'),
('ba3ddf00-bc47-419d-852a-9197051301d1','湖上望月','鮑溶','唐','唐诗','tang','','[]','湖上清涼月更好，天邊旅人猶未歸。',32,'全唐诗/poet.tang.26000.json','["湖上清涼月更好，天邊旅人猶未歸。", "幾見金波滿還破，草蟲聲畔露沾衣。"]'),
('f5de197e-533a-4ed5-b7f4-0db235c342d0','襄陽懷古','鮑溶','唐','唐诗','tang','','[]','襄陽太守沈碑意，身後身前幾年事。',32,'全唐诗/poet.tang.26000.json','["襄陽太守沈碑意，身後身前幾年事。", "湘江千歲未爲陵，水底魚龍應識字。"]'),
('35e9e17c-6b88-4b50-b361-df97be55d8f1','秋夜對月寄僧特','鮑溶','唐','唐诗','tang','','[]','憶見特公賞秋處，涼溪看月清光寒。',32,'全唐诗/poet.tang.26000.json','["憶見特公賞秋處，涼溪看月清光寒。", "今夕深溪又相映，特公何處共團圓。"]'),
('e3c3bb20-1355-4c17-92d2-dc055ef661ec','望江中金山寺','鮑溶','唐','唐诗','tang','','[]','一朵蓬萊在世間，梵王宮闕翠雲間。',32,'全唐诗/poet.tang.26000.json','["一朵蓬萊在世間，梵王宮闕翠雲間。", "近南溪水更清淺，聞道遊人未忍還。"]'),
('069d738d-6c35-4099-95ac-4b8972162df3','宿青牛谷梁煉師仙居','鮑溶','唐','唐诗','tang','','[]','隨雲步入青牛谷，青牛道士留我宿。',32,'全唐诗/poet.tang.26000.json','["隨雲步入青牛谷，青牛道士留我宿。", "可憐夜久月中行，惟有壇邊一枝竹。"]'),
('e0027eff-5bad-47eb-92da-3fd15f486e9f','得僧書','鮑溶','唐','唐诗','tang','','[]','身歸紫霄嶺，書下白雲來。',36,'全唐诗/poet.tang.26000.json','["身歸紫霄嶺，書下白雲來。", "翦筍發寒字，燒花芳夜雷。", "想隨香馭至，不假定鐘催。"]'),
('420bc1a0-deb2-4441-9db7-bb0f3630b3b3','見袁德師侍御說江南有仙檀花因以戲贈','鮑溶','唐','唐诗','tang','','[]','聞說天壇花耐涼，笑風含露對秋光。',32,'全唐诗/poet.tang.26000.json','["聞說天壇花耐涼，笑風含露對秋光。", "欲求御史更分別，何似衣花歲歲香。"]'),
('0ef4016a-16d9-469b-b64d-f0894b84ad17','和王璠侍御酬友人贈白角冠','鮑溶','唐','唐诗','tang','','[]','芙蓉寒豔鏤冰姿，天朗燈深拔豸時。',32,'全唐诗/poet.tang.26000.json','["芙蓉寒豔鏤冰姿，天朗燈深拔豸時。", "好見吹笙伊洛上，紫煙丹鳳亦相隨。"]'),
('3e9db4c7-df87-4d13-8f53-8a0b47942ac3','送僧擇棲遊天台二首 一','鮑溶','唐','唐诗','tang','','[]','身非居士常多病，心愛空王稍覺閑。',32,'全唐诗/poet.tang.26000.json','["身非居士常多病，心愛空王稍覺閑。", "師問寄禪何處所，浙東青翠沃洲山。"]'),
('b7f67239-7f09-4ea1-bc1f-8cf0ea8fa05e','送僧擇棲遊天台二首 二','鮑溶','唐','唐诗','tang','','[]','金嶺雪晴僧獨歸，水文霞彩衲禪衣。',32,'全唐诗/poet.tang.26000.json','["金嶺雪晴僧獨歸，水文霞彩衲禪衣。", "可憐石室燒香夜，江月對心無是非。"]'),
('2bd0ade3-99a2-4442-8d41-79098d86f8c3','上巳日寄樊瓘樊宗憲兼呈上浙東孟中丞簡','鮑溶','唐','唐诗','tang','','[]','世間禊事風流處，鏡裏雲山若畫屏。',32,'全唐诗/poet.tang.26000.json','["世間禊事風流處，鏡裏雲山若畫屏。", "今日會稽王內史，好將賓客醉蘭亭。"]'),
('bfa237e0-c9d2-459e-9633-290fdff9cacb','暮春戲贈樊宗憲','鮑溶','唐','唐诗','tang','','[]','羌笛胡琴春調長，美人何處樂年芳。',48,'全唐诗/poet.tang.26000.json','["羌笛胡琴春調長，美人何處樂年芳。", "野船弄酒鴛鴦醉，官路攀花騕褭狂。", "應和朝雲垂手語，肯嫌夜色斷刀光。"]'),
('30e5ef0b-ed7f-4250-88f2-84f6b7103952','酬王侍御','鮑溶','唐','唐诗','tang','','[]','慙非青玉製，故以贈仙郎。',48,'全唐诗/poet.tang.26000.json','["慙非青玉製，故以贈仙郎。", "希翼留書閤，提攜在筆牀。", "詎能輝繡服，安得似芸香。", "所報何珍重，清明勝夜光。"]'),
('72da81b5-8de5-4b5f-bc46-820925a90d64','寄宋申錫評事時從李少師移軍回歸','鮑溶','唐','唐诗','tang','','[]','君逐元侯靜虜歸，虎旗龍節駐春暉。',64,'全唐诗/poet.tang.26000.json','["君逐元侯靜虜歸，虎旗龍節駐春暉。", "欲求岱岳燔柴禮，已錫魯人縫掖衣。", "長劒一時天外倚，五雲多遶日邊飛。", "心期共賀太平世，去去故鄉親食薇。"]'),
('2cab1cb0-0c9e-414a-b890-849a045932a7','夏日懷杜悰駙馬','鮑溶','唐','唐诗','tang','','[]','五月清涼蕭史家，瑤池分水種菱花。',64,'全唐诗/poet.tang.26000.json','["五月清涼蕭史家，瑤池分水種菱花。", "迴文地簟龍鱗浪，交鏁天窗蟬翼紗。", "閑遣青琴飛小雪，自看碧玉破甘瓜。", "仍聞聖主知書癖，鳳閣燒香對五車。"]'),
('f2469da2-1e59-4b57-a94e-0e38823783a4','鶯雛','鮑溶','唐','唐诗','tang','','[]','雙鶯銜野蝶，枝上教雛飛。',36,'全唐诗/poet.tang.26000.json','["雙鶯銜野蝶，枝上教雛飛。", "避日花陰語，愁風竹裏啼。", "須防美人賞，爲爾好毛衣。"]'),
('c5ee3248-bc97-4ab9-a1fe-96d1145a10e6','上陽宮月','鮑溶','唐','唐诗','tang','','[]','水北宮城夜柝嚴，宮西新月影纖纖。',64,'全唐诗/poet.tang.26000.json','["水北宮城夜柝嚴，宮西新月影纖纖。", "受環花幌小開鏡，移燭瑤房皆捲簾。", "學織機邊娥影靜，拜新衣上露華沾。", "合裁班扇思行幸，願託涼風篋笥嫌。"]'),
('15411047-e7fb-44f1-bf52-a0d04f1b31be','淮南臥病聞李相夷簡移軍山陽以靖東寇感激之下因抒長句','鮑溶','唐','唐诗','tang','','[]','太白星前龍虎符，元臣出將順天誅。',64,'全唐诗/poet.tang.26000.json','["太白星前龍虎符，元臣出將順天誅。", "教聞清淨蕭丞相，計立安危范大夫。", "玉帳黃昏大刁斗，月營寒曉小單于。", "魯連未必蹈滄海，應見麒麟新畫圖。"]'),
('ad65dbf7-ab89-4de7-afa4-dce073a5ce8f','讀淮南李相行營至楚州詩','鮑溶','唐','唐诗','tang','','[]','閫外建牙威不賓，古來戡難憶忠臣。',64,'全唐诗/poet.tang.26000.json','["閫外建牙威不賓，古來戡難憶忠臣。", "已分舟楫歸元老，更使熊羆屬丈人。", "玄象合教滄海晏，青龍喜應太山春。", "來年二月登封禮，去望台星扈日輪。"]'),
('3a7b3d37-b52e-4a13-b5d7-05f4237ce79e','讀李相心中樂','鮑溶','唐','唐诗','tang','','[]','負海狂鯨縱巨鱗，四朝天子阻時巡。',64,'全唐诗/poet.tang.26000.json','["負海狂鯨縱巨鱗，四朝天子阻時巡。", "誰將侯玉乖南面，幾使戎軍殷左輪。", "久作妖星虛費日，終□天洞亦何人。", "果聞丞相心中樂，上贊陶唐一萬春。"]'),
('55d67245-4ceb-49d0-be30-a0c64000d208','聞國家將行封禪聊抒臣情','鮑溶','唐','唐诗','tang','','[]','雲雨由來隨六龍，玉泥瑤檢不乾封。',64,'全唐诗/poet.tang.26000.json','["雲雨由來隨六龍，玉泥瑤檢不乾封。", "山知槱柞新煙火，臣望簫韶舊鼓鐘。", "清蹕間過素王廟，翠華高映大夫松。", "旅中病客諳堯曲，身賤何由奏九重。"]'),
('fb0b0d0f-6635-4947-9d9d-32414660c861','和淮南李相公夷簡喜平淄青迴軍之作','鮑溶','唐','唐诗','tang','','[]','橫笛臨吹發曉軍，元戎幢節拂寒雲。',64,'全唐诗/poet.tang.26000.json','["橫笛臨吹發曉軍，元戎幢節拂寒雲。", "搜山羽騎乘風引，下瀨樓船背水分。", "天際獸旗搖火燄，日前魚甲動金文。", "馬毛不汗東方靖，行見蕭何第一勳。"]'),
('59abfb44-de57-473b-9d2e-f61c85a79984','秋暮八月十五夜與王璠侍御賞月因愴遠離聊以奉寄','鮑溶','唐','唐诗','tang','','[]','前月月明夜，美人同遠光。',36,'全唐诗/poet.tang.26000.json','["前月月明夜，美人同遠光。", "清塵一以間，今夕坐相忘。", "風落芙蓉露，凝餘繡服香。"]'),
('4a45f38a-4f30-4e8a-b6a2-ec8ef813a10f','送蕭世秀才','鮑溶','唐','唐诗','tang','','[]','心交別我西京去，愁滿春魂不易醒。',32,'全唐诗/poet.tang.26000.json','["心交別我西京去，愁滿春魂不易醒。", "從此無人訪窮病，馬蹄車轍草青青。"]'),
('89729cf7-40bf-41e5-a452-cf2c2b09dbd6','懷惠明禪師','鮑溶','唐','唐诗','tang','','[]','秋天欲霜夜無風，我意不在天地中。',64,'全唐诗/poet.tang.26000.json','["秋天欲霜夜無風，我意不在天地中。", "雪山世界此涼夜，寶月獨照琉璃宮。", "解空長老蓮花手，曾以佛書親指授。", "雪嶺無人又問來，十年夏臘平安否。"]'),
('ec543382-f300-4b5a-9332-9262cf0e7d63','吳中夜別','鮑溶','唐','唐诗','tang','','[]','楚客秋思著黃葉，吳姬夜歌停碧雲。',32,'全唐诗/poet.tang.26000.json','["楚客秋思著黃葉，吳姬夜歌停碧雲。", "聲盡燈前各流淚，水天涼冷鴈離羣。"]'),
('faf6b1b1-a0a8-4242-8d2c-03f1115e911b','隋家井','鮑溶','唐','唐诗','tang','','[]','玉鉤欄下寒泉水，金轆轤邊影照人。',32,'全唐诗/poet.tang.26000.json','["玉鉤欄下寒泉水，金轆轤邊影照人。", "此水今爲九泉路，數枝花照數堆塵。"]'),
('8cea8716-cedd-4e7b-b782-bf69ccdc81e3','寄王璠侍御求蜀箋','鮑溶','唐','唐诗','tang','','[]','蜀川牋紙綵雲初，聞說王家最有餘。',32,'全唐诗/poet.tang.26000.json','["蜀川牋紙綵雲初，聞說王家最有餘。", "野客思將池上學，石楠紅葉不堪書。"]'),
('4de00136-585e-4ae2-acd9-913ff6f83610','湘妃列女操','鮑溶','唐','唐诗','tang','','[]','有虞夫人哭虞后，淑女何事又傷離，竹上淚跡生不盡。',152,'全唐诗/poet.tang.26000.json','["有虞夫人哭虞后，淑女何事又傷離，竹上淚跡生不盡。", "寄哀雲和五十絲，雲和終奏鈞天曲。", "乍聽寶琴遙嗣續，三湘測測流急綠。", "秋夜露寒蜀帝飛，楓林月斜楚臣宿。", "更疑川宮日黃昏，闇攜女手殷勤言。", "環珮玲瓏有無間，終疑既遠雙悄悄。", "蒼梧舊雲豈難召，老猨心寒不可嘯。", "目眄眄兮意蹉跎，魂騰騰兮驚秋波。", "曲一盡兮憶再奏，衆弦不聲且如何。"]'),
('e282923c-87ed-4db0-82a7-75675531fec0','羽林行','鮑溶','唐','唐诗','tang','','[]','朝出羽林宮，入參雲臺議。',108,'全唐诗/poet.tang.26000.json','["朝出羽林宮，入參雲臺議。", "獨請萬里行，不奏和親事。", "君王重年少，深納開邊利。", "寶馬雕玉鞍，一朝從萬騎。", "煌煌都門外，祖帳光七貴。", "歌鍾樂行軍，雲物慘別地。", "簫笳整部曲，幢蓋動郊次。", "臨風親戚懷，滿袖兒女淚。", "行行復何贈，長劒報恩字。"]'),
('b04243e6-fedd-4dbe-8d52-01794bfcbf97','鳴鴈行','鮑溶','唐','唐诗','tang','','[]','七月朔方鴈心苦，聯影翻空落南土。',112,'全唐诗/poet.tang.26000.json','["七月朔方鴈心苦，聯影翻空落南土。", "八月江南陰復晴，浮雲繞天難夜行。", "羽翼勞痛心虛驚，一聲相呼百處鳴。", "楚童夜宿煙波側，沙上布羅連草色。", "月闇風悲欲下天，不知何處容棲息？", "楚童胡爲傷我神，爾不曾作遠行人。", "江南羽族本不少，寧得網羅此客鳥。"]'),
('7caf1299-3cb3-4c66-8bea-9bdefc869030','織婦詞','鮑溶','唐','唐诗','tang','','[]','百日織綵絲，一朝停杼機。',72,'全唐诗/poet.tang.26000.json','["百日織綵絲，一朝停杼機。", "機中有雙鳳，化作天邊衣。", "使人馬如風，誠不阻音徽。", "影響隨羽翼，雙雙繞君飛。", "行人豈願行，不怨不知歸。", "所怨天盡處，何人見光輝。"]'),
('f95bdf64-5896-4551-b323-33039eeef5df','塞上行','鮑溶','唐','唐诗','tang','','["\u9ec4\u6cb3"]','西風應時筋角堅，承露牧馬水草冷。',32,'全唐诗/poet.tang.26000.json','["西風應時筋角堅，承露牧馬水草冷。", "可憐黃河九曲盡，氈館牢落胡無影。"]'),
('8e529d70-a02f-4879-9b17-94a3b0b827da','採珠行','鮑溶','唐','唐诗','tang','','[]','東方暮空海面平，驪龍弄珠燒月明。',208,'全唐诗/poet.tang.26000.json','["東方暮空海面平，驪龍弄珠燒月明。", "海人驚窺水底火，百寶錯落隨龍行。", "浮心一夜生姦見，月質龍軀看幾遍。", "擘波下去忘此身，迢迢謂海無靈神。", "海宮正當龍睡重，昨夜孤光今得弄。", "河伯空憂水府貧，天吳不敢相驚動。", "一團冰容掌上清，四面人入光中行。", "騰華乍搖白日影，銅鏡萬古羞爲靈。", "海邊老翁怨狂子，抱珠哭向無底水。", "一富何須龍頷前，千金幾葬魚腹裏。", "鱗蟲變化爲陰陽，填海破山無景光。", "拊心髣髴失珠意，此土爲爾離農桑。", "飲風衣日亦飽煖，老翁擲却荆雞卵。"]'),
('ba0ea996-a761-4dcc-9d40-a3fea9e9b2c9','采葛行','鮑溶','唐','唐诗','tang','','[]','春溪幾回葛花黃，黃麝引子山山香。',176,'全唐诗/poet.tang.26000.json','["春溪幾回葛花黃，黃麝引子山山香。", "蠻女不惜手足損，鉤刀一一牽柔長。", "葛絲茸茸春雪體，深澗擇泉清處洗。", "殷勤十指蠶吐絲，當窗嫋嫋聲高機。", "織成一尺無一兩，供進天子五月衣。", "水精夏殿開涼戶，冰山繞座猶難御。", "衣親玉體又何如，杳然獨對秋風曙。", "鏡湖女兒嫁鮫人，鮫綃逼肖也不分。", "吳中角簟泛清水，搖曳勝被三素雲。", "自茲貢薦無人惜，那敢更爭龍手跡。", "蠻女將來海市頭，賣與嶺南貧估客。"]'),
('0f17410d-4423-4455-8c91-1cc8a33a3c35','南塘二首 一','鮑溶','唐','唐诗','tang','','[]','南塘旅舍秋淺清，夜深綠蘋風不生。',32,'全唐诗/poet.tang.26000.json','["南塘旅舍秋淺清，夜深綠蘋風不生。", "蓮花受露重如睡，斜月起動鴛鴦聲。"]'),
('a349dddb-7734-4ba3-a1c9-4bc836bb2ca3','南塘二首 二','鮑溶','唐','唐诗','tang','','[]','塘東白日駐紅霧，早魚翻光落碧潯。',32,'全唐诗/poet.tang.26000.json','["塘東白日駐紅霧，早魚翻光落碧潯。", "畫舟蘭棹欲破浪，恐畏驚動蓮花心。"]'),
('a4f07029-4e68-4be0-a478-77eba63c82c1','東鄰女','鮑溶','唐','唐诗','tang','','[]','雙飛鷓鴣春影斜，美人盤金衣上花。',32,'全唐诗/poet.tang.26000.json','["雙飛鷓鴣春影斜，美人盤金衣上花。", "身爲父母幾時客，一生知向何人家。"]'),
('d2a3554c-2d7e-4fc6-b736-90e3af47c4a6','寄李都護','鮑溶','唐','唐诗','tang','','[]','去年河上送行人，萬里弓旌一武臣。',32,'全唐诗/poet.tang.26000.json','["去年河上送行人，萬里弓旌一武臣。", "聞道玉關烽火滅，犬戎知有外家親。"]'),
('6f6be383-e054-4811-a564-a310bffa3923','長安旅舍懷舊山','鮑溶','唐','唐诗','tang','','[]','昨夜清涼夢本山，眠雲喚鶴有慙顏。',32,'全唐诗/poet.tang.26000.json','["昨夜清涼夢本山，眠雲喚鶴有慙顏。", "青蓮道士長堪羨，身外無名至老閑。"]'),
('f3b5ab29-a93d-416e-a28b-05b862e86c49','漢宮詞二首 一','鮑溶','唐','唐诗','tang','','[]','栢梁宸居清窈窕，東方先生夜待詔。',32,'全唐诗/poet.tang.26000.json','["栢梁宸居清窈窕，東方先生夜待詔。", "夜久月當承露盤，內人吹笙舞鳳鸞。"]'),
('ed236e32-c4ce-466b-8003-00c6dc1381be','漢宮詞二首 二','鮑溶','唐','唐诗','tang','','[]','月映東窗似玉輪，未央前殿絕聲塵。',32,'全唐诗/poet.tang.26000.json','["月映東窗似玉輪，未央前殿絕聲塵。", "宮槐花落西風起，鸚鵡驚寒夜喚人。"]'),
('86441272-ac1c-41be-9a97-eb4716e67041','薦冰','鮑溶','唐','唐诗','tang','','[]','西陵宜先啓，春寒寢廟清。',72,'全唐诗/poet.tang.26000.json','["西陵宜先啓，春寒寢廟清。", "曆官分氣候，天子薦精誠。", "已辨瑤池色，如和玉珮鳴。", "禮餘神轉肅，曙後月殘明。", "雅合霜容潔，非同雪體輕。", "空憐一掬水，珍重此時情。"]'),
('bdae75ba-bdbf-43eb-a613-6567a002ebbc','送薛補闕入朝','鮑溶','唐','唐诗','tang','','[]','平原門下十餘人，獨受恩多未殺身。',64,'全唐诗/poet.tang.26000.json','["平原門下十餘人，獨受恩多未殺身。", "每歎陸家兄弟少，更憐楊氏子孫貧。", "柴門已斷施行馬，魯酒那能醉近臣。", "賴有軍中遺令在，猶將談笑對風塵。"]'),
('fe82fb41-b086-416f-b761-b5415757f083','句','鮑溶','唐','唐诗','tang','','[]','萬里岐路多，一身天地窄。',12,'全唐诗/poet.tang.26000.json','["萬里岐路多，一身天地窄。"]'),
('216f56cd-d4b2-4dee-8cf4-543dd3d897d0','薦冰','盧鈞','唐','唐诗','tang','','[]','薦冰朝日後，闢廟曉光清。',72,'全唐诗/poet.tang.26000.json','["薦冰朝日後，闢廟曉光清。", "不改晶熒質，能彰語露情。", "且無霜共潔，豈與水均明。", "在捧搖寒色，當呈表素誠。", "凝姿陳俎豆，浮彩映牕楹。", "皎皎盤盂側，稜稜嚴氣生。"]'),
('71a6e1aa-30ef-4d4f-a1bb-489b8f06c522','薦冰','范傳質','唐','唐诗','tang','','[]','乘春方啓閉，羞獻有常程。',72,'全唐诗/poet.tang.26000.json','["乘春方啓閉，羞獻有常程。", "潔朗寒光徹，輝華素彩明。", "色凝霜雪淨，影照冕旒清。", "肅肅將崇禮，兢兢示捧盈。", "方圓陳玉座，小大表精誠。", "朝覿當西陸，桃弧每共行。"]'),
('2d41ad1a-63a4-4546-887e-afb658f1a4d9','賦得芙蓉出水','賈謩','唐','唐诗','tang','','[]','的皪舒芳豔，紅姿映綠蘋。',72,'全唐诗/poet.tang.26000.json','["的皪舒芳豔，紅姿映綠蘋。", "搖風開細浪，出沼媚清晨。", "翻影初迎日，流香暗襲人。", "獨披千葉淺，不競百花春。", "魚戲參差動，龜游次第新。", "涉江如可採，從此免迷津。"]'),
('00517cde-eab7-4033-9959-0d91f76637a2','恩賜魏文貞公諸孫舊第以𨗳直臣','陳彥博','唐','唐诗','tang','','[]','阿衡隨逝水，池館主他人。',72,'全唐诗/poet.tang.26000.json','["阿衡隨逝水，池館主他人。", "天意能酬德，雲孫喜庇身。", "生前由直道，歿後振芳塵。", "雨露新恩日，芝蘭舊里春。", "勳庸留十代，光彩映諸鄰。", "共賀升平日，從茲得諫臣。"]'),
('7e782eb7-1220-4330-b41e-023d360f8169','使南海道長沙題道林岳麓寺','唐扶','唐','唐诗','tang','','[]','道林岳麓仲與昆，卓犖請從先後論。',208,'全唐诗/poet.tang.26000.json','["道林岳麓仲與昆，卓犖請從先後論。", "松根踏雲二千步，始見大屋開三門。", "泉清或戲蛟龍窟，殿豁數盡高帆掀。", "即今異鳥聲不斷，聞道看花春更繁。", "從容一衲分若有，蕭瑟兩鬢吾能髠。", "逢迎侯伯轉覺貴，膜拜佛像心加尊。", "稍揖皇英頮濃淚，試與屈賈招清魂。", "荒唐大樹悉楠桂，細碎枯草多蘭蓀。", "沙彌去學五印字，靜女來懸千尺幡。", "主人念我塵眼昏，半夜號令期至暾。", "遲回難得上白舫，羈泄不敢言綠尊。", "兩祠物色採拾盡，壁間杜甫真少恩。", "晚來光彩更騰射，筆鋒正健如可吞。"]'),
('d08b538e-8fca-4237-a266-4609a36d7620','和兵部鄭侍郎省中四松詩','唐扶','唐','唐诗','tang','','[]','幽抱應無語，貞松遂自栽。',120,'全唐诗/poet.tang.26000.json','["幽抱應無語，貞松遂自栽。", "寄懷丞相業，因擢大夫材。", "日射蒼鱗動，塵迎翠箒迴。", "嫩茸含細粉，初葉泛新桮。", "偶聖爲舟去，逢時與鶴來。", "寒聲連曉竹，靜氣結陰苔。", "赫奕鳴騶至，熒煌洞戶開。", "良辰一臨眺，憩樹幾裴回。", "恨發風期阻，詩從綺思裁。", "還聞舊凋契，凡在此中培。"]'),
('37201913-42e3-4b2d-a331-3ad5cb5b0bb7','和兵部鄭侍郎省中四松詩','陶雍','唐','唐诗','tang','','[]','右相歷兵署，四松皆手栽。',120,'全唐诗/poet.tang.26000.json','["右相歷兵署，四松皆手栽。", "斸時驚鶴去，移處帶雲來。", "根倍雙桐植，花分八桂開。", "生成造化力，長作棟梁材。", "豈羨蘭依省，猶嫌柏占臺。", "出樓終百尺，入夢已三台。", "幽韻和宮漏，餘香度酒杯。", "拂冠枝上雪，染履影中苔。", "高位相承地，新詩寡和才。", "何由比蘿蔓，攀附在條枚。"]'),
('a85b80f8-2f9b-423a-993d-587f00ee24ab','譚子池','郭周藩','唐','唐诗','tang','','[]','澄水一百步，世名譚子池。',288,'全唐诗/poet.tang.26000.json','["澄水一百步，世名譚子池。", "余詰陵陽叟，此池當因誰。", "父老謂余說，本郡譚叔皮。", "開元末年中，生子字阿宜。", "墜地便能語，九歲多鬚眉。", "不飲亦不食，未嘗言渴飢。", "十五銳行走，快馬不能追。", "二十入山林，一去無還期。", "父母憶念深，鄉閭爲立祠。", "大曆元年春，此兒忽來歸。", "頭冠簪鳳皇，身著霞裳衣。", "普遍拯疲俗，丁寧告親知。", "余爲神仙官，下界不可祈。", "恐爲妖魅假，不如早平夷。", "此有黃金藏，鎮在茲廟基。", "發掘散生聚，可以救貧羸。", "金出繼靈泉，湛若清琉璃。", "泓澄表符瑞，水旱無竭時。", "言訖辭沖虛，杳靄上玄微。", "凡情留不得，攀望衆號悲。", "尋稟神仙誡，徹廟斸開窺。", "果獲無窮寶，均融霑困危。", "巨源出嶺頂，噴湧世間稀。", "異境流千古，終年福四維。"]'),
('91d121b6-8e10-4dce-b0dd-c373b74654dc','金谷園花發懷古','侯冽','唐','唐诗','tang','','[]','金谷千年後，春花發滿園。',72,'全唐诗/poet.tang.26000.json','["金谷千年後，春花發滿園。", "紅芳徒笑日，穠豔尚迎軒。", "雨濕輕光軟，風搖碎影翻。", "猶疑施錦帳，堪歎罷朱紈。", "愁態鶯吟澀，啼容露綴繁。", "慇懃問前事，桃李竟無言。"]'),
('e6c69b03-f779-4961-a4ef-4a82baf3da9f','花發上林','侯冽','唐','唐诗','tang','','[]','花發三陽盛，香飄五柞深。',72,'全唐诗/poet.tang.26000.json','["花發三陽盛，香飄五柞深。", "素暉雲積苑，紅彩繡張林。", "落水隨魚戲，搖風映鳥吟。", "瓊樓出高豔，玉輦駐濃陰。", "亂蝶枝開影，繁蜂蘂上音。", "鮮芳盈禁籞，布澤荷天心。"]'),
('9cebecba-1673-44c6-a83b-e525e331bad5','金谷園花發懷古','王質','唐','唐诗','tang','','[]','寂寥金谷澗，花發舊時園。',72,'全唐诗/poet.tang.26000.json','["寂寥金谷澗，花發舊時園。", "人事空懷古，煙霞此獨存。", "管弦非上客，歌舞少王孫。", "繁蘂風驚散，輕紅鳥乍翻。", "山川終不改，桃李自無言。", "今日經塵路，淒涼詎可論。"]'),
('19387623-b6c7-4a43-90c0-6c2208eab545','和太原張相公山亭懷古','高銖','唐','唐诗','tang','','[]','鬬石類巖巘，飛流瀉潺湲。',48,'全唐诗/poet.tang.26000.json','["鬬石類巖巘，飛流瀉潺湲。", "遠壑簷宇際，孤巒雉堞間。", "何必到海岳，境幽機自閑。", "茲焉得高趣，高步謝東山。"]'),
('c4f3f5c8-ea7b-4b37-b96d-e1fb5a1ebe00','八月五日中部官舍讀唐曆天寶已來追愴故事','舒元輿','唐','唐诗','tang','','[]','將尋國朝事，靜讀柳芳曆。',278,'全唐诗/poet.tang.26000.json','["將尋國朝事，靜讀柳芳曆。", "八月日之五，開卷忽感激。", "正當天寶末，撫事坐追惜。", "仰思聖明帝，貽禍在肘腋。", "楊李盜吏權，貪殘日狼籍。", "燕戎伺其便，百萬奮長戟。", "兩河連煙塵，二京成瓦礫。", "生人死欲盡，揳業猶不息。", "肅宗傳寶圖，寇難連年擊。", "天地方開泰，鑄鼎成繼述。", "萬國哭龍衮，悲思動蠻[貊]。", "自此千秋節，不復動金石。", "悲風揚霜天，繐帷冷塵席。", "零落太平老，東西亂離客。", "往往爲余言，嗚咽淚雙滴。", "況當近塞地，哀吹起邊笛。", "撫几觀陳文，使我心不懌。", "花萼笑繁華，溫泉樹容碧。", "霓裳煙雲盡，梨園風雨隔。", "露囊與金鏡，東逝驚波溺。", "昔聞歡娛事，今日成慘慼。", "神仙不可求，劒璽苔文積。", "萬古長恨端，蕭蕭泰陵陌。"]'),
('61a43cef-fa94-4700-bfd7-f2d8c1144294','坊州按獄','舒元輿','唐','唐诗','tang','','[]','中部接戎塞，頑山四周遭。',288,'全唐诗/poet.tang.26000.json','["中部接戎塞，頑山四周遭。", "風冷木長瘦，石磽人亦勞。", "牧守苟懷仁，癢之時爲搔。", "其愛如赤子，始得無啼號。", "奈何貪狼心，潤屋沈脂膏。", "攫搏如猛虎，吞噬若狂獒。", "山禿逾高採，水窮益深撈。", "龜魚即絕跡，鹿兔無遺毛。", "氓苦稅外緡，吏憂笑中刀。", "大君明四目，燭之洞秋毫。", "眷茲一州命，慮齊墜波濤。", "臨軒詔小臣，汝往窮貪饕。", "分明舉公法，爲我緩窮騷。", "小臣誠小心，奉命如煎熬。", "飲冰不待夕，驅馬凌晨臯。", "及此督簿書，遊詞出狴牢。", "門牆見狼狽，案牘聞腥臊。", "探情與之言，變態如姦猱。", "真非既巧飾，僞意乃深韜。", "去惡猶農夫，稂莠須耘耨。", "恢恢布疎網，罪者何由逃。", "自顧孱鈍姿，利器非能操。", "六旬始歸奏，霜落秋原蒿。", "寄謝守土臣，努力清郡曹。"]'),
('d6a05f18-277c-410c-b4bf-11d9e9e5589e','橋山懷古','舒元輿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','軒轅厭代千萬秋，淥波浩蕩東南流。',211,'全唐诗/poet.tang.26000.json','["軒轅厭代千萬秋，淥波浩蕩東南流。", "今來古往無不死，獨有天地長悠悠。", "我乘驛騎到中部，古聞此地爲渠搜。", "橋山突兀在其左，荒榛交鏁寒風愁。", "神仙天下亦如此，況我慼促同蜉蝣。", "誰言衣冠葬其下，不見弓劒何人收。", "哀喧呌笑牧童戲，陰天月落狐狸遊。", "却思皇墳立人極，車輪馬跡無不周。", "洞庭張樂降玄鶴，涿鹿大戰摧蚩尤。", "知勇神天不自大，風后力牧輸長籌。", "襄城迷路問童子，帝鄉歸去無人留。", "崆峒求道失遺跡，荆山鑄鼎餘荒丘。", "君不見黃龍飛去山下路，斷髯成草風颼颼。"]'),
('2f005e39-eb18-4fc5-863c-019384013154','坊州按獄蘇氏莊記室二賢自鄜州走馬相訪留連數日發後獨坐寂寞因成詩寄之','舒元輿','唐','唐诗','tang','','[]','十年一相見，世俗信多岐。',288,'全唐诗/poet.tang.26000.json','["十年一相見，世俗信多岐。", "雲雨易分散，山川長間之。", "我銜鳳闕恩，按獄橋山陲。", "君在龍驤府，掌奏羽檄詞。", "相去百餘里，魂夢自相馳。", "形容在胸臆，書札通相思。", "煩君愛我深，輕車忽載脂。", "塞門秋色老，霜氣方凝姿。", "此地少平川，岡阜相參差。", "誰知路非遠，行者多云疲。", "君能犯勁風，信宿凌欹危。", "情親不自倦，下馬開雙眉。", "相對坐沉吟，屈指驚歲時。", "萬事且莫問，一杯欣共持。", "陽烏忽西傾，明蟾挂高枝。", "卷簾引瑤玉，滅燭臨霜墀。", "中庭有疎蘆，淅淅聞風吹。", "長河卷雲色，凝碧無瑕疵。", "一言開我懷，曠然澹希夷。", "悠悠夜方永，冷思偏相宜。", "眉睫無他人，與君閑解題。", "陶然叩寂寞，更請吟清詩。", "得意且忘言，何況竹與絲。", "頃刻過三夕，起坐輕四肢。"]'),
('0c2f4134-1086-417e-823e-9d7520565734','履春冰','舒元輿','唐','唐诗','tang','','[]','投跡清冰上，凝光動早春。',72,'全唐诗/poet.tang.26000.json','["投跡清冰上，凝光動早春。", "兢兢愁陷履，步步怯移身。", "鳥照微生水，狐聽或過人。", "細遷形外影，輕躡鏡中輪。", "咫尺憂偏遠，危疑懼已頻。", "願堅容足分，莫使獨驚神。"]'),
('c10c09d5-198e-49c6-bd4c-c8a4e9fb3b74','贈李翺','舒元輿','唐','唐诗','tang','','[]','湘江舞罷忽成悲，便脫蠻靴出絳帷。',32,'全唐诗/poet.tang.26000.json','["湘江舞罷忽成悲，便脫蠻靴出絳帷。", "誰是蔡邕琴酒客，魏公懷舊嫁文姬。"]'),
('ff7fafbf-e19a-4a7c-980f-272855e8697c','登長安慈恩寺塔','盧宗回','唐','唐诗','tang','','[]','東方曉日上翔鸞，西轉蒼龍拂露盤。',64,'全唐诗/poet.tang.26000.json','["東方曉日上翔鸞，西轉蒼龍拂露盤。", "渭水寒光搖藻井，玉峰晴色上朱闌。", "九重宮闕參差見，百二山河表裏觀。", "蹔輟去蓬悲不定，一凭金界望長安。"]'),
('ddf99789-f0e2-4426-a983-c0c4e4a54c02','古鏡歌','周匡物','唐','唐诗','tang','','[]','軒轅鑄鏡誰將去，曾被良工瀉金取。',64,'全唐诗/poet.tang.26000.json','["軒轅鑄鏡誰將去，曾被良工瀉金取。", "明月心中桂不生，輕冰面上菱初吐。", "蛟龍久無雷雨聲，鸞鳳空踏莓苔舞。", "欲向高臺對曉開，不知誰是孤光主。"]'),
('2864a846-fb51-470c-9ab9-1ee5aeb7ed12','及第謠','周匡物','唐','唐诗','tang','','[]','水國寒消春日長，燕鶯催促花枝忙。',80,'全唐诗/poet.tang.26000.json','["水國寒消春日長，燕鶯催促花枝忙。", "風吹金榜落凡世，三十三人名字香。", "遙望龍墀新得意，九天勅下多狂醉。", "驊騮一百三十蹄，踏破蓬萊五雲地。", "物經千載出塵埃，從此便爲天下瑞。"]'),
('7ad0f6d3-0168-44c5-9287-5998f18a03bc','及第後謝座主','周匡物','唐','唐诗','tang','','[]','一縱東越入西秦，十度聞鶯不見春。',64,'全唐诗/poet.tang.26000.json','["一縱東越入西秦，十度聞鶯不見春。", "試向崑山投瓦礫，便容靈沼濯埃塵。", "悲歡暗負風雲力，感激潛生草木身。", "中夜自將形影語，古來吞炭是何人。"]'),
('1e7ccc08-1ca4-42a4-a0c3-b14401aa5ecf','自題讀書堂','周匡物','唐','唐诗','tang','','[]','窗外捲簾侵碧落，檻前敲竹嚮青冥。',32,'全唐诗/poet.tang.26000.json','["窗外捲簾侵碧落，檻前敲竹嚮青冥。", "黃昏不欲留人宿，雲起風生龍虎醒。"]'),
('254c4cd0-d581-445f-9bb0-ecb42bcd7937','應舉題錢塘公館','周匡物','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','萬里茫茫天塹遙，秦皇底事不安橋。',32,'全唐诗/poet.tang.26000.json','["萬里茫茫天塹遙，秦皇底事不安橋。", "錢塘江口無錢過，又阻西陵兩信潮。"]'),
('94ac20fc-63c7-4e81-9136-10b40842a946','題旅櫬','廖有方','唐','唐诗','tang','','[]','嗟君沒世委空囊，幾度勞心翰墨場。',16,'全唐诗/poet.tang.26000.json','["嗟君沒世委空囊，幾度勞心翰墨場。"]'),
('7e3b505d-7444-47fc-8b0d-3c73e0d616c6','立春日呈宮傅侍郎','皇甫曙','唐','唐诗','tang','','[]','朝旦微風吹曉霞，散爲和氣滿家家。',64,'全唐诗/poet.tang.26000.json','["朝旦微風吹曉霞，散爲和氣滿家家。", "不知容貌潛消落，且喜春光動物華。", "出問池冰猶塞岸，歸尋園柳未生芽。", "摩娑酒甕重封閉，待入新年共賞花。"]'),
('7fc9aa7b-17b6-4b54-b463-b19bab873234','賦得玉聲如樂','潘存實','唐','唐诗','tang','','[]','表質自堅貞，因人一扣鳴。',72,'全唐诗/poet.tang.26000.json','["表質自堅貞，因人一扣鳴。", "靜將金並響，妙與樂同聲。", "杳杳疑風送，泠泠似曲成。", "韻含湘瑟切，音帶舜弦清。", "不獨藏虹氣，猶能暢物情。", "后夔如爲聽，從此振琮琤。"]'),
('30d84edc-a6c2-4fc3-b2b8-3349c971c7e8','送林刺史簡言之漳州','陳去疾','唐','唐诗','tang','','[]','江樹欲含曛，清歌一送君。',48,'全唐诗/poet.tang.26000.json','["江樹欲含曛，清歌一送君。", "征驂辭荔浦，別袂暗松雲。", "路狹橫柯度，山深墜葉聞。", "明朝宿何處，未忍醉中分。"]'),
('d07fed2b-5187-4dab-8875-f62bdbdb6fef','憶山中','陳去疾','唐','唐诗','tang','','[]','長吟重悒然，爲憶山中年。',96,'全唐诗/poet.tang.26000.json','["長吟重悒然，爲憶山中年。", "清瑟泛遙夜，亂花隨暮煙。", "珠林餘露氣，乳竇滴香泉。", "跡遠塵埃外，花開綺藻前。", "巖羅雲貌逸，竹抱水容妍。", "蕙磴飛英遶，萍潭片影懸。", "林藏諸曲勝，臺擅一峰偏。", "會可標真寄，焚香對石筵。"]'),
('b4ec4948-b06c-4306-9e23-5a0c4bf2c494','元夕京城和歐陽衮','陳去疾','唐','唐诗','tang','','[]','蘭焰芳芬徹曉開，珠光新靄映人來。',48,'全唐诗/poet.tang.26000.json','["蘭焰芳芬徹曉開，珠光新靄映人來。", "歌迎甲夜催銀管，影動繁星綴玉臺。", "別有朱門春澹蕩，不妨芝火翠崔嵬。"]'),
('608a774e-46b3-4398-b8ef-3bdda66b739f','送韓將軍之鴈門','陳去疾','唐','唐诗','tang','','[]','荒塞峰煙百道馳，鴈門風色暗旌旗。',64,'全唐诗/poet.tang.26000.json','["荒塞峰煙百道馳，鴈門風色暗旌旗。", "破圍鐵騎長驅疾，飲血將軍轉戰危。", "畫角吹開邊月靜，縵纓不信虜塵窺。", "歸來長揖功成後，黃石當年故有期。"]'),
('f1dfe31c-e559-4b84-b675-683cea1bbebb','賦得騏驥長鳴','陳去疾','唐','唐诗','tang','','[]','騏驥忻知己，嘶鳴忽異常。',72,'全唐诗/poet.tang.26000.json','["騏驥忻知己，嘶鳴忽異常。", "積悲攄怨抑，一舉徹穹蒼。", "迹類三年鳥，心馳五達莊。", "何言從蹇躓，今日逐騰驤。", "牛皁休維縶，天衢恣陸梁。", "向非逢伯樂，誰足見其長。"]'),
('dac5b2e1-ecc7-49a3-b317-30edb0cf2404','偶題','陳去疾','唐','唐诗','tang','','[]','魂夢天南垂，宿昔萬里道。',24,'全唐诗/poet.tang.26000.json','["魂夢天南垂，宿昔萬里道。", "池臺花氣深，到處生春草。"]'),
('ca055d23-e444-4523-ac89-7f9384dfd94c','春宮曲','陳去疾','唐','唐诗','tang','','[]','流鶯春曉喚櫻桃，花外傳呼殿影高。',32,'全唐诗/poet.tang.26000.json','["流鶯春曉喚櫻桃，花外傳呼殿影高。", "抱裏琵琶最承寵，君王勅賜玉檀槽。"]'),
('61910feb-385f-40e9-8a51-1b356ecf21a8','采蓮曲','陳去疾','唐','唐诗','tang','','[]','粉光花色葉中開，荷氣衣香水上來。',32,'全唐诗/poet.tang.26000.json','["粉光花色葉中開，荷氣衣香水上來。", "棹響清潭見斜領，雙鴛何事亦相猜。"]'),
('f55da3dd-e810-4e90-b065-acb1459bf7c5','踏歌行 一','陳去疾','唐','唐诗','tang','','[]','鴛鴦樓下萬花新，翡翠宮前百戲陳。',32,'全唐诗/poet.tang.26000.json','["鴛鴦樓下萬花新，翡翠宮前百戲陳。", "夭矯翔龍銜火樹，飛來瑞鳳散芳春。"]'),
('fa068d91-f11f-4117-a87d-9643c1fec8b9','踏歌行 二','陳去疾','唐','唐诗','tang','','[]','仙蹕初傳紫禁香，瑞雲開處夜花芳。',32,'全唐诗/poet.tang.26000.json','["仙蹕初傳紫禁香，瑞雲開處夜花芳。", "繁弦促管升平調，綺綴丹蓮借月光。"]'),
('57f4b9db-bd91-4ee3-96d1-25f0e4971191','塞下曲','陳去疾','唐','唐诗','tang','','[]','春至金河雪似花，蕭條玉塞但胡沙。',32,'全唐诗/poet.tang.26000.json','["春至金河雪似花，蕭條玉塞但胡沙。", "曉來重上關城望，惟見驚塵不見家。"]'),
('5f8277a2-8d19-4104-bc98-531e293bb85f','送人謫幽州','陳去疾','唐','唐诗','tang','','[]','臨路深懷放廢慚，夢中猶自憶江南。',32,'全唐诗/poet.tang.26000.json','["臨路深懷放廢慚，夢中猶自憶江南。", "莫言塞北春風少，還勝炎荒入瘴嵐。"]'),
('ecb3dfbf-8e29-4a6e-a589-57c158100882','西上辭母墳','陳去疾','唐','唐诗','tang','','[]','高蓋山頭日影微，黃昏獨立宿禽稀。',32,'全唐诗/poet.tang.26000.json','["高蓋山頭日影微，黃昏獨立宿禽稀。", "林間滴酒空垂淚，不見丁寧囑早歸。"]'),
('2df9886f-9eeb-4974-9813-418b92f62fb2','履春冰','張蕭遠','唐','唐诗','tang','','[]','一步一愁新，輕輕恐陷人。',72,'全唐诗/poet.tang.26000.json','["一步一愁新，輕輕恐陷人。", "薄光全透日，殘影半銷春。", "蟬想行時翼，魚驚蹋處鱗。", "底虛難駐足，岸闊怯迴身。", "豈暇踟躕久，寧辭顧盼頻。", "願將兢慎意，從此赴通津。"]'),
('9687a143-c526-4bdc-b779-f95ea0de8e69','觀燈','張蕭遠','唐','唐诗','tang','','[]','十萬人家火燭光，門門開處見紅妝。',64,'全唐诗/poet.tang.26000.json','["十萬人家火燭光，門門開處見紅妝。", "歌鐘喧夜更漏暗，羅綺滿街塵土香。", "星宿別從天畔出，蓮花不向水中芳。", "寶釵驟馬多遺落，依舊明朝在路傍。"]'),
('c59b3e4d-be19-4eb5-9973-5715571286d1','送宮人入道','張蕭遠','唐','唐诗','tang','','[]','捨寵求仙畏色衰，辭天素面立堦墀。',64,'全唐诗/poet.tang.26000.json','["捨寵求仙畏色衰，辭天素面立堦墀。", "金丹擬駐千年貌，玉指休勻八字眉。", "師主與收珠翠後，君王看戴角冠時。", "從來宮女皆相妬，聞向瑤臺盡淚垂。"]'),
('fa3677fc-4aae-4269-9ad3-ba301f27aa6e','句','張蕭遠','唐','唐诗','tang','','[]','秦雲寂寂僧還定，盡日無人鹿遶牀。',40,'全唐诗/poet.tang.26000.json','["秦雲寂寂僧還定，盡日無人鹿遶牀。", "日暮風吹官渡柳，白鵶飛出石頭牆。", "雙雙白燕入詞堂。"]'),
('bd6ae1a7-051d-44d4-8d5d-bf790209a438','見志','李播','唐','唐诗','tang','','[]','去歲買琴不與價，今年沽酒未還錢。',32,'全唐诗/poet.tang.26000.json','["去歲買琴不與價，今年沽酒未還錢。", "門前債主雁行立，屋裏醉人魚貫眠。"]'),
('10a7da93-3623-4caa-88b6-17cf3fa84ebc','魚上冰','王季則','唐','唐诗','tang','','[]','北陸收寒盡，東風解凍初。',72,'全唐诗/poet.tang.26000.json','["北陸收寒盡，東風解凍初。", "冰消通淺溜，氣變躍潛魚。", "應節似知化，揚鬐任所如。", "浮沈非樂藻，沿泝異傳書。", "結網時空久，臨川意有餘。", "爲龍將可望，今日媿才虛。"]'),
('21d47b98-62c5-4133-895a-1f0d1949ab61','魚上冰','紀元臯','唐','唐诗','tang','','[]','春生寒氣滅，稍動伏泉魚。',72,'全唐诗/poet.tang.26000.json','["春生寒氣滅，稍動伏泉魚。", "乍喜東風至，來觀曲浦初。", "近冰朱鬣見，望日錦鱗舒。", "漸覺流澌退，還忻掉尾餘。", "噞喁情自樂，沿泝意寧疎。", "儻得隨鯤化，終能戾太虛。"]'),
('3ad6b76d-ba12-4cdd-b597-2382e8a4ee39','魚上冰','吳晃','唐','唐诗','tang','','[]','春水潛鱗發，寒潭舊藻疎。',72,'全唐诗/poet.tang.26000.json','["春水潛鱗發，寒潭舊藻疎。", "揚鬐順氣後，振鬣上冰初。", "戲廣憐空潔，浮清媚景虛。", "戒貪還避餌，思達每懷書。", "濕映流澌薄，狂遊觸浪餘。", "終希泮渙澤，爲化北溟魚。"]'),
('c093e466-f501-4b24-824f-2584ef749425','贈柳氏妓','鄭還古','唐','唐诗','tang','','[]','冶豔出神仙，歌聲勝管弦。',48,'全唐诗/poet.tang.26000.json','["冶豔出神仙，歌聲勝管弦。", "詞輕白紵曲，歌遏碧雲天。", "未擬生裴秀，如何乞鄭玄。", "不堪金谷水，橫過墜樓前。"]'),
('1c121c33-b9a1-4153-a27a-8eff830755c6','吉州道中','鄭還古','唐','唐诗','tang','','[]','吉州新置掾，馳驛到條山。',48,'全唐诗/poet.tang.26000.json','["吉州新置掾，馳驛到條山。", "薏苡殊非謗，羊腸未是艱。", "自慚多白髮，爭敢競朱顏。", "若有前生債，今朝不懊還。"]'),
('17d63222-c052-4217-833d-8497032bc744','望思臺','鄭還古','唐','唐诗','tang','','[]','讒語能令骨肉離，姦情難測事堪悲。',32,'全唐诗/poet.tang.26000.json','["讒語能令骨肉離，姦情難測事堪悲。", "何因掘得江充骨，搗作微塵祭望思。"]'),
('e2e064c6-fb3e-45d1-9438-fa4543145dfa','日南長至','獨孤鉉','唐','唐诗','tang','','[]','玉曆頒新律，凝陰發一陽。',72,'全唐诗/poet.tang.26000.json','["玉曆頒新律，凝陰發一陽。", "輪輝猶惜短，圭影此偏長。", "晷度經南斗，流晶盡北堂。", "乍疑周戶耀，可愛逗林光。", "積雪銷微照，初萌動早芒。", "更升臺上望，雲物已昭彰。"]'),
('7a4980a7-d4ba-4c16-ba4c-b628ac2d279b','延平天慶觀','王初','唐','唐诗','tang','','[]','劒化江邊綠構新，層臺不染玉梯塵。',64,'全唐诗/poet.tang.26000.json','["劒化江邊綠構新，層臺不染玉梯塵。", "千章隱篆標龍簡，一曲空歌降鳳鈞。", "嵐氣濕衣雲葉晚，天香飄戶月枝春。", "盟經早晚聞仙語，學種三芝伴羽人。"]'),
('57444b76-3bd5-4667-8998-b0888da88a61','送葉秀才','王初','唐','唐诗','tang','','[]','快騎璁瓏刻玉羈，河梁返照上征衣。',64,'全唐诗/poet.tang.26000.json','["快騎璁瓏刻玉羈，河梁返照上征衣。", "層冰春近蟠龍起，九澤雲閑獨鶴飛。", "行想北山清夢斷，重遊西洛故人稀。", "漢庭狗監深知己，有日前驅負弩歸。"]'),
('98c671f7-9fc9-4028-9862-9da98d712d23','送王秀才謁池州吳都督','王初','唐','唐诗','tang','','[]','池陽去去躍雕鞍，十里長亭百草乾。',64,'全唐诗/poet.tang.26000.json','["池陽去去躍雕鞍，十里長亭百草乾。", "衣袂障風金鏤細，劒光橫雪玉龍寒。", "晴郊別岸鄉魂斷，曉樹啼烏客夢殘。", "南館星郎東道主，搖鞭休問路行難。"]'),
('3e1de59f-fb3f-4bb4-8ab0-09fa64b5e833','青帝','王初','唐','唐诗','tang','','[]','青帝邀春隔歲還，月娥孀獨夜漫漫。',64,'全唐诗/poet.tang.26000.json','["青帝邀春隔歲還，月娥孀獨夜漫漫。", "韓憑舞羽身猶在，素女商弦調未殘。", "終古蘭巖棲偶鶴，從來玉谷有離鸞。", "幾時幽恨飄然斷，共待天池一水乾。"]'),
('3b2c1310-be63-4c49-b3e1-efb7022cdea1','銀河','王初','唐','唐诗','tang','','[]','閶闔疎雲漏絳津，橋頭秋夜鵲飛頻。',64,'全唐诗/poet.tang.26000.json','["閶闔疎雲漏絳津，橋頭秋夜鵲飛頻。", "猶殘仙媛湔帬水，幾見星妃度襪塵。", "歷歷素榆飄玉葉，涓涓清月濕冰輪。", "年來若有乘槎客，爲弔波靈是楚臣。"]'),
('6b974919-a5d6-4c72-a85f-7085f5894019','書秋','王初','唐','唐诗','tang','','[]','千里南雲度塞鴻，秋容無跡淡平空。',64,'全唐诗/poet.tang.26000.json','["千里南雲度塞鴻，秋容無跡淡平空。", "人間玉嶺清宵月，天上銀河白晝風。", "潘賦登山魂易斷，楚歌遺佩怨何窮。", "往來未若奇張翰，欲鱠霜鯨碧海東。"]'),
('8ba57838-95d0-4e43-bbdf-9289d061a237','自和書秋','王初','唐','唐诗','tang','','[]','隴首斜飛避弋鴻，頹雲蕭索見層空。',64,'全唐诗/poet.tang.26000.json','["隴首斜飛避弋鴻，頹雲蕭索見層空。", "漢宮夜結雙莖露，閶闔涼生六幕風。", "湘女怨弦愁不禁，鄂君香被夢難窮。", "江邊兩槳連歌渡，驚散遊魚蓮葉東。"]'),
('fd5075cf-690e-4cff-9949-ff5dde8643aa','立春後作','王初','唐','唐诗','tang','','[]','東君珂佩響珊珊，青馭多時下九關。',32,'全唐诗/poet.tang.26000.json','["東君珂佩響珊珊，青馭多時下九關。", "方信玉霄千萬里，春風猶未到人間。"]'),
('c5154a66-2e69-41ff-bc12-718763201e90','梅花二首 一','王初','唐','唐诗','tang','','[]','應爲陽春信未傳，固將青豔屬殘年。',32,'全唐诗/poet.tang.26000.json','["應爲陽春信未傳，固將青豔屬殘年。", "東君欲待尋佳約，剩寄衣香與粉綿。"]'),
('253ad6ba-185c-4915-9b9a-95e2d1a4515a','梅花二首 二','王初','唐','唐诗','tang','','[]','迎春雪豔飄零極，度夕蟾華掩映多。',32,'全唐诗/poet.tang.26000.json','["迎春雪豔飄零極，度夕蟾華掩映多。", "欲托清香傳遠信，一枝無計奈愁何。"]'),
('f198211f-331a-4f1f-87f2-ca57cc5264cd','春日詠梅花二首 一','王初','唐','唐诗','tang','','[]','靚妝纔罷粉痕新，遞曉風回散玉塵。',32,'全唐诗/poet.tang.26000.json','["靚妝纔罷粉痕新，遞曉風回散玉塵。", "若遣有情應悵望，已兼殘雪又兼春。"]'),
('d71a5667-a683-40ec-bb82-94373c508595','春日詠梅花二首 二','王初','唐','唐诗','tang','','[]','青帝來時值遠芳，殘花殘雪尚交光。',32,'全唐诗/poet.tang.26000.json','["青帝來時值遠芳，殘花殘雪尚交光。", "隔年擬待春消息，得見春風已斷腸。"]'),
('b3ef39ee-54bd-4c29-8cb5-0bc1a4a74693','即夕','王初','唐','唐诗','tang','','[]','榆葉飄零碧漢流，玉蟾珠露兩清秋。',32,'全唐诗/poet.tang.26000.json','["榆葉飄零碧漢流，玉蟾珠露兩清秋。", "僊家若有單棲恨，莫向銀臺半夜遊。"]'),
('ef714f7a-8241-415a-bd19-5136b5c2ffbf','送陳校勘入宿','王初','唐','唐诗','tang','','[]','日落風回卷碧霓，芳蓬一夜拆龍泥。',32,'全唐诗/poet.tang.26000.json','["日落風回卷碧霓，芳蓬一夜拆龍泥。", "銀臺級級連清漢，桂子香濃月杵低。"]'),
('34efb8ee-6813-404f-b8ba-add243a46f61','即夕','王初','唐','唐诗','tang','','[]','風幌涼生白袷衣，星榆纔亂絳河低。',32,'全唐诗/poet.tang.26000.json','["風幌涼生白袷衣，星榆纔亂絳河低。", "月明休近相思樹，恐有韓憑一處棲。"]'),
('8330209e-72b9-44b5-8518-a11eeaf322c4','早春詠雪','王初','唐','唐诗','tang','','[]','句芒宮樹已先開，珠蘂瓊花鬬剪裁。',32,'全唐诗/poet.tang.26000.json','["句芒宮樹已先開，珠蘂瓊花鬬剪裁。", "散作上林今夜雪，送教春色一時來。"]'),
('37d2a1ab-f256-4445-96b0-21638984ef5d','望雪','王初','唐','唐诗','tang','','[]','銀花珠樹曉來看，宿醉初醒一倍寒。',32,'全唐诗/poet.tang.26000.json','["銀花珠樹曉來看，宿醉初醒一倍寒。", "已似王恭披鶴氅，憑欄仍是玉欄干。"]'),
('83d38511-e21c-4835-8cb3-8e8284d89794','雪霽','王初','唐','唐诗','tang','','[]','星榆葉葉晝離披，雲粉千重凝不飛。',32,'全唐诗/poet.tang.26000.json','["星榆葉葉晝離披，雲粉千重凝不飛。", "崑玉樓臺珠樹密，夜來誰向月中歸。"]'),
('09eaea92-39bf-4a3c-976c-4de09f3b4885','舟次汴堤','王初','唐','唐诗','tang','','[]','曲岸蘭叢雁飛起，野客維舟碧煙裏。',32,'全唐诗/poet.tang.26000.json','["曲岸蘭叢雁飛起，野客維舟碧煙裏。", "竿頭五兩轉天風，白日楊花滿流水。"]'),
('95773780-e922-4deb-b323-38b8224acbca','玉聲如樂','劉軻','唐','唐诗','tang','','[]','玉叩能旋止，人言與樂并。',72,'全唐诗/poet.tang.26000.json','["玉叩能旋止，人言與樂并。", "繁音忽已闋，雅韻詘然清。", "佩想停仙步，泉疑咽夜聲。", "曲終無異聽，響極有餘情。", "特達知難擬，玲瓏豈易名。", "崑山如可得，一片佇爲榮。"]'),
('b4ecc28c-64d3-44c2-8b91-535d4347a449','喜陳懿老示新製','朱晝','唐','唐诗','tang','','[]','一別一千日，一日十二憶。',84,'全唐诗/poet.tang.26000.json','["一別一千日，一日十二憶。", "苦心無閑時，今夕見玉色。", "玉色復何異，弘明含羣德。", "有文如星宿，飛入我胷臆。", "憂愁方破壞，歡喜重補塞。", "使我心貌全，且非黃金力。", "將攀下風手，願假仙鸞翼。"]'),
('15c9f704-045f-42dc-b2e2-a7239e33ca88','贈友人古鏡','朱晝','唐','唐诗','tang','','[]','我有古時鏡，初自壞陵得。',48,'全唐诗/poet.tang.26000.json','["我有古時鏡，初自壞陵得。", "蛟龍猶泥蟠，魑魅幸月蝕。", "摩久見菱蘂，青於藍水色。", "贈君將照色，無使心受惑。"]'),
('e2e9e760-8d24-440c-a26f-a2eb0dc65d20','賦得花藤藥合寄頴陰故人','朱晝','唐','唐诗','tang','','[]','藤生南海濱，引蔓青且長。',72,'全唐诗/poet.tang.26000.json','["藤生南海濱，引蔓青且長。", "剪削爲花枝，何人無文章。", "非才亦有心，割骨聞餘芳。", "繁葉落何處，孤貞在中央。", "願盛黃金膏，寄與青眼郎。", "路遠莫知意，水深天蒼蒼。"]'),
('19b86cd9-d293-4da5-baef-f1810ed648ae','春色滿皇州','滕邁','唐','唐诗','tang','','[]','藹藹復悠悠，春歸十二樓。',72,'全唐诗/poet.tang.26000.json','["藹藹復悠悠，春歸十二樓。", "最明雲裏闕，先滿日邊州。", "色媚青門外，光搖紫陌頭。", "上林榮舊樹，太液鏡新流。", "曖帶祥煙起，清添瑞景浮。", "陽和如啓蟄，從此事芳遊。"]'),
('fffdf240-fa11-4a36-beef-62862800ce61','楊柳枝詞','滕邁','唐','唐诗','tang','','[]','三條陌上拂金羈，萬里橋邊映酒旗。',32,'全唐诗/poet.tang.26000.json','["三條陌上拂金羈，萬里橋邊映酒旗。", "此日令人腸欲斷，不堪將入笛中吹。"]'),
('03a384cb-9b95-437d-8217-a2531e7c5bf9','句','滕邁','唐','唐诗','tang','','[]','陶令門前罥接䍦，亞夫營裏拂朱旗。',16,'全唐诗/poet.tang.26000.json','["陶令門前罥接䍦，亞夫營裏拂朱旗。"]'),
('ebedd92e-2f68-4dfe-92ac-03a4c62c0ca0','留別吉州太守宗人邁','滕倪','唐','唐诗','tang','','[]','秋初江上別旌旗，故國無家淚欲垂。',64,'全唐诗/poet.tang.26000.json','["秋初江上別旌旗，故國無家淚欲垂。", "千里未知投足處，前程便是聽猨時。", "誤攻文字身空老，却返漁樵計已遲。", "羽翼彫零飛不得，丹霄無路接差池。"]'),
('dca0ac5d-647e-4a5e-bd02-680516875798','句','滕倪','唐','唐诗','tang','','[]','映水有深意，見人無懼心。',28,'全唐诗/poet.tang.26000.json','["映水有深意，見人無懼心。", "白髮不能容相國，也同閑客滿頭生。"]'),
('9f62f201-87ad-4d1a-ab1d-a20974e65f18','吳宮','殷堯藩','唐','唐诗','tang','','[]','吳王愛歌舞，夜夜醉嬋娟。',48,'全唐诗/poet.tang.26000.json','["吳王愛歌舞，夜夜醉嬋娟。", "見日吹紅燭，和塵掃翠鈿。", "徒令句踐霸，不信子胥賢。", "莫問長洲草，荒涼無限年。"]'),
('a93d49dd-43a0-4426-9f3a-9915864386e9','久雨','殷堯藩','唐','唐诗','tang','','[]','雲影蔽遙空，無端淡復濃。',48,'全唐诗/poet.tang.26000.json','["雲影蔽遙空，無端淡復濃。", "兩旬綿密雨，二月似深冬。", "詩酒從教數，簾幃一任重。", "孰知春有地，微露小桃紅。"]'),
('e3addb04-8aaf-4348-b1f1-8e872077800d','郊行逢社日','殷堯藩','唐','唐诗','tang','','[]','酒熟送迎便，村村慶有年。',48,'全唐诗/poet.tang.26000.json','["酒熟送迎便，村村慶有年。", "妻孥親稼穡，老稚効漁畋。", "紅樹青林外，黃蘆白鳥邊。", "稔看風景美，寧不羨歸田。"]'),
('4c59b75c-f151-4ab7-8c36-076983223349','過友人幽居','殷堯藩','唐','唐诗','tang','','[]','身坐衆香國，蒲團詩思新。',48,'全唐诗/poet.tang.26000.json','["身坐衆香國，蒲團詩思新。", "一貧曾累我，此興未輸人。", "陋巷誰爲俗，寒窗不染塵。", "石齋盟四友，年下頓生春。"]'),
('c31bcc0c-7dad-4572-b0b5-090256079374','過雍陶博士邸中飲','殷堯藩','唐','唐诗','tang','','[]','落葉下蕭蕭，幽居遠市朝。',48,'全唐诗/poet.tang.26000.json','["落葉下蕭蕭，幽居遠市朝。", "偶成投轄飲，不待致書招。", "塞鴈衝寒過，山雲傍檻飄。", "此身何所似，天地一漁樵。"]'),
('a281f900-74c5-452f-869c-75364decc82f','遊王羽士山房','殷堯藩','唐','唐诗','tang','','[]','落日半樓明，琳宮事事清。',48,'全唐诗/poet.tang.26000.json','["落日半樓明，琳宮事事清。", "山橫萬古色，鶴帶九臯聲。", "易作神仙侶，難忘父子情。", "道人應識我，未肯說長生。"]'),
('5e396fc1-435a-4a68-a2d7-a1f0b0aa3359','署中答武功姚合','殷堯藩','唐','唐诗','tang','','[]','原中多陰雨，惟留一室明。',48,'全唐诗/poet.tang.26000.json','["原中多陰雨，惟留一室明。", "自宜居靜者，誰得問先生。", "深井泉香出，危沙藥更榮。", "全家笑無辱，曾不見戈兵。"]'),
('2568b21b-c081-4f1d-b93c-c715a0225114','贈龍陽尉馬戴','殷堯藩','唐','唐诗','tang','','[]','早學全身術，惟令耕近田。',48,'全唐诗/poet.tang.26000.json','["早學全身術，惟令耕近田。", "自輸官稅後，常臥晚雲邊。", "細草沿堦長，高蘿出石懸。", "向來名姓茂，空被外情牽。"]'),
('84b7b087-7e6d-423e-9e2c-34c9d71825a4','上巳日贈都上人 一','殷堯藩','唐','唐诗','tang','','[]','三月初三日，千家與萬家。',48,'全唐诗/poet.tang.26000.json','["三月初三日，千家與萬家。", "蝶飛秦地草，鶯入漢宮花。", "鞍馬皆爭麗，笙歌盡鬬奢。", "吾師無所願，惟願老煙霞。"]');
